CREATE OR REPLACE FUNCTION "public"."aggregate_campaign_metrics"("p_campaign_id" integer) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_email_metrics JSONB;
  v_social_metrics JSONB;
  v_total_metrics JSONB;
BEGIN
  -- Get email metrics from email_deliveries
  SELECT jsonb_build_object(
    'sent', COUNT(*),
    'delivered', COUNT(*) FILTER (WHERE delivery_status = 'delivered'),
    'opened', COUNT(*) FILTER (WHERE opened = true),
    'clicked', COUNT(*) FILTER (WHERE clicked = true),
    'bounced', COUNT(*) FILTER (WHERE delivery_status = 'bounce'),
    'complained', COUNT(*) FILTER (WHERE delivery_status = 'complaint')
  ) INTO v_email_metrics
  FROM email_deliveries ed
  JOIN email_jobs ej ON ej.id = ed.email_job_id
  JOIN subcampaigns s ON s.id = ej.subcampaign_id
  WHERE s.campaign_id = p_campaign_id;

  -- Get social media metrics from blaze_posts
  SELECT jsonb_build_object(
    'posts', COUNT(*),
    'published', COUNT(*) FILTER (WHERE status = 'published'),
    'scheduled', COUNT(*) FILTER (WHERE status = 'scheduled'),
    'total_engagement', COALESCE(SUM((engagement_metrics->>'likes')::INTEGER), 0) + 
                        COALESCE(SUM((engagement_metrics->>'shares')::INTEGER), 0) +
                        COALESCE(SUM((engagement_metrics->>'comments')::INTEGER), 0),
    'impressions', COALESCE(SUM((engagement_metrics->>'impressions')::INTEGER), 0)
  ) INTO v_social_metrics
  FROM blaze_posts bp
  JOIN subcampaigns s ON s.id = bp.subcampaign_id
  WHERE s.campaign_id = p_campaign_id;

  -- Combine metrics
  v_total_metrics := jsonb_build_object(
    'email', COALESCE(v_email_metrics, '{}'::jsonb),
    'social', COALESCE(v_social_metrics, '{}'::jsonb),
    'updated_at', now()
  );

  RETURN v_total_metrics;
END;
$$;


ALTER FUNCTION "public"."aggregate_campaign_metrics"("p_campaign_id" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."apply_dataset_filter"("_module_name" "text", "_action_name" "text", "_user_id" "uuid" DEFAULT "auth"."uid"()) RETURNS "text"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  dataset_code text;
  filter_condition text := '1=1'; -- Default: no filter
BEGIN
  -- Get the dataset code for this user's permissions
  SELECT d.code INTO dataset_code
  FROM public.role_permissions rp
  JOIN public.module_action_datasets mad ON mad.id = rp.module_action_dataset_id
  JOIN public.modules m ON m.id = mad.module_id
  JOIN public.actions a ON a.id = mad.action_id
  JOIN public.datasets d ON d.id = mad.dataset_id
  WHERE m.name = _module_name
  AND a.code = _action_name
  AND rp.is_allowed = true
  AND (
    -- Check primary role
    EXISTS (
      SELECT 1 FROM public.users u
      WHERE u.auth_user_id = _user_id AND u.role_id = rp.role_id AND u.status = 'active'
    ) OR
    -- Check additional roles
    EXISTS (
      SELECT 1 FROM public.user_roles ur
      JOIN public.users u ON u.id = ur.user_id
      WHERE u.auth_user_id = _user_id AND ur.role_id = rp.role_id 
      AND ur.is_active = true AND u.status = 'active'
    )
  )
  ORDER BY d.code DESC -- Prefer more restrictive datasets
  LIMIT 1;

  -- Apply filter based on dataset
  CASE dataset_code
    WHEN 'ALL_RECORDS' THEN
      filter_condition := '1=1';
    WHEN 'MY_RECORDS' THEN
      filter_condition := format('created_by = %L OR assigned_to = %L', _user_id, _user_id);
    WHEN 'MY_TEAMS_RECORDS' THEN
      filter_condition := format(
        'created_by = %L OR assigned_to = %L OR EXISTS (
          SELECT 1 FROM team_members tm 
          JOIN teams t ON t.id = tm.team_id
          WHERE tm.user_id = (SELECT id FROM users WHERE auth_user_id = %L)
          AND tm.is_active = true
          AND (created_by IN (
            SELECT u.auth_user_id FROM users u 
            JOIN team_members tm2 ON tm2.user_id = u.id
            WHERE tm2.team_id = tm.team_id AND tm2.is_active = true
          ))
        )', 
        _user_id, _user_id, _user_id
      );
    WHEN 'UNASSIGNED_RECORDS' THEN
      filter_condition := 'assigned_to IS NULL';
    ELSE
      filter_condition := '1=1';
  END CASE;

  RETURN filter_condition;
END;
$$;


ALTER FUNCTION "public"."apply_dataset_filter"("_module_name" "text", "_action_name" "text", "_user_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."auto_assign_sales_manager_on_mp_task"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_sales_manager_type_id INTEGER := 3;
  v_existing_handler INTEGER;
BEGIN
  -- Only process for MP tasks (taskid = 8)
  IF NEW.taskid = 8 AND NEW.companyid IS NOT NULL AND NEW.product_id IS NOT NULL AND NEW.taskowner IS NOT NULL THEN
    
    -- Check if Sales Manager already exists for this company-product
    SELECT id INTO v_existing_handler
    FROM company_handlers
    WHERE companyid = NEW.companyid
      AND product_id = NEW.product_id
      AND handler_type_id = v_sales_manager_type_id
    LIMIT 1;
    
    -- If no handler exists, create one with the MP task assignee
    IF v_existing_handler IS NULL THEN
      INSERT INTO company_handlers (
        companyid,
        product_id,
        handler_type_id,
        handler_id,
        entered_by,
        updated_by,
        entered_on,
        updated_on
      ) VALUES (
        NEW.companyid,
        NEW.product_id,
        v_sales_manager_type_id,
        NEW.taskowner,
        NEW.taskowner,
        NEW.taskowner,
        NOW(),
        NOW()
      );
      
      RAISE NOTICE 'Auto-assigned Sales Manager (%) for company % product %', 
        NEW.taskowner, NEW.companyid, NEW.product_id;
    END IF;
  END IF;
  
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."auto_assign_sales_manager_on_mp_task"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."auto_deactivate_datasets_on_campaign_archive"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF NEW.status = 'Archived' AND OLD.status != 'Archived' THEN
    UPDATE campaign_datasets
    SET is_active = false
    WHERE id IN (
      SELECT cd.id
      FROM campaign_datasets cd
      JOIN subcampaigns sc ON sc.campaign_dataset_id = cd.id
      WHERE sc.campaign_id = NEW.id
    );
  END IF;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."auto_deactivate_datasets_on_campaign_archive"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."auto_generate_document_reference"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_dept_id INTEGER;
  v_doc_type_code TEXT;
  v_reference TEXT;
BEGIN
  -- First, ensure department_id is set from the owner's department if not provided
  IF NEW.department_id IS NULL AND NEW.owner_id IS NOT NULL THEN
    SELECT u.department_id INTO NEW.department_id
    FROM public.users u
    WHERE u.auth_user_id = NEW.owner_id;
  END IF;

  -- Only generate reference if not provided
  IF NEW.reference_number IS NULL OR NEW.reference_number = '' THEN
    -- Get department_id (should now be set from above)
    v_dept_id := NEW.department_id;
    
    -- Get document type code
    SELECT dt.code INTO v_doc_type_code
    FROM public.document_types dt
    WHERE dt.id = NEW.document_type_id;
    
    -- Generate reference number
    IF v_doc_type_code IS NOT NULL THEN
      v_reference := public.generate_document_reference(v_dept_id, v_doc_type_code);
      NEW.reference_number := v_reference;
    END IF;
  END IF;
  
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."auto_generate_document_reference"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."auto_grant_super_admin_permissions"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  -- When a new module_action_dataset is created and is active, 
  -- automatically grant permission to Super Admin (role_id = 4)
  IF NEW.is_active = true THEN
    INSERT INTO role_permissions (role_id, module_action_dataset_id, dataset_id)
    VALUES (4, NEW.id, NULL)
    ON CONFLICT DO NOTHING;
  END IF;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."auto_grant_super_admin_permissions"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."auto_link_company_by_domain"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
    lead_domain text;
    matched_company_id integer;
    match_count integer;
    match_type text;
BEGIN
    IF NEW.email IS NOT NULL AND NEW.email != '' THEN
        lead_domain := lower(split_part(NEW.email, '@', 2));
        
        IF lead_domain IS NOT NULL AND lead_domain != '' THEN
            -- First try: Email domain matching
            -- Count how many companies match this domain
            SELECT COUNT(*) INTO match_count
            FROM companies c
            WHERE (
                (c.email1 IS NOT NULL AND lower(split_part(c.email1, '@', 2)) = lead_domain) OR
                (c.email2 IS NOT NULL AND lower(split_part(c.email2, '@', 2)) = lead_domain) OR
                (c.email3 IS NOT NULL AND lower(split_part(c.email3, '@', 2)) = lead_domain)
            )
            AND c.status = 'Active';
            
            -- Only auto-link if EXACTLY ONE company matches
            IF match_count = 1 THEN
                SELECT c.id INTO matched_company_id
                FROM companies c
                WHERE (
                    (c.email1 IS NOT NULL AND lower(split_part(c.email1, '@', 2)) = lead_domain) OR
                    (c.email2 IS NOT NULL AND lower(split_part(c.email2, '@', 2)) = lead_domain) OR
                    (c.email3 IS NOT NULL AND lower(split_part(c.email3, '@', 2)) = lead_domain)
                )
                AND c.status = 'Active';
                match_type := 'email_domain';
            END IF;
            
            -- If no unique email match, try website domain
            IF matched_company_id IS NULL THEN
                SELECT COUNT(*) INTO match_count
                FROM companies c
                WHERE c.status = 'Active'
                  AND (
                    extract_url_domain(c.website1) = lead_domain OR
                    extract_url_domain(c.website2) = lead_domain OR
                    extract_url_domain(c.website3) = lead_domain
                  );
                
                IF match_count = 1 THEN
                    SELECT c.id INTO matched_company_id
                    FROM companies c
                    WHERE c.status = 'Active'
                      AND (
                        extract_url_domain(c.website1) = lead_domain OR
                        extract_url_domain(c.website2) = lead_domain OR
                        extract_url_domain(c.website3) = lead_domain
                      );
                    match_type := 'website_domain';
                END IF;
            END IF;
            
            -- Link only if unique match found
            IF matched_company_id IS NOT NULL AND (NEW.linked_company_id IS NULL OR NEW.linked_company_id != matched_company_id) THEN
                NEW.linked_company_id := matched_company_id;
                NEW.linkedby := auth.uid();
                NEW.linkedon := now();
                NEW.status := 'Verified';
                
                IF NEW.notes IS NULL THEN
                    NEW.notes := 'Auto-linked via ' || match_type;
                ELSE
                    NEW.notes := NEW.notes || ' (Auto-linked via ' || match_type || ')';
                END IF;
            END IF;
        END IF;
    END IF;
    
    RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."auto_link_company_by_domain"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."build_criteria_where_clause"("criteria" "jsonb") RETURNS "text"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  conditions text[] := ARRAY[]::text[];
  v_key text;
  v_value jsonb;
  v_type text;
  v_arr_values text[];
  v_int_arr_values int[];
BEGIN
  IF criteria IS NULL OR criteria = '{}'::jsonb THEN
    RETURN 'TRUE';
  END IF;

  FOR v_key, v_value IN SELECT * FROM jsonb_each(criteria)
  LOOP
    v_type := jsonb_typeof(v_value);
    
    CASE v_key
      WHEN 'contactStatus' THEN
        IF v_type = 'array' AND jsonb_array_length(v_value) > 0 THEN
          v_arr_values := ARRAY(SELECT jsonb_array_elements_text(v_value));
          conditions := conditions || format('COALESCE(c.status, %L) = ANY(%L::text[])', 'Active', v_arr_values);
        ELSIF v_type = 'string' AND v_value #>> '{}' <> '' THEN
          conditions := conditions || format('COALESCE(c.status, %L) = %L', 'Active', v_value #>> '{}');
        END IF;
      
      WHEN 'contactType' THEN
        IF v_type = 'array' AND jsonb_array_length(v_value) > 0 THEN
          v_arr_values := ARRAY(SELECT jsonb_array_elements_text(v_value));
          conditions := conditions || format('c.contact_type = ANY(%L::text[])', v_arr_values);
        ELSIF v_type = 'string' AND v_value #>> '{}' <> '' THEN
          conditions := conditions || format('c.contact_type = %L', v_value #>> '{}');
        END IF;
      
      WHEN 'contactDesignation' THEN
        IF v_type = 'array' AND jsonb_array_length(v_value) > 0 THEN
          v_arr_values := ARRAY(SELECT jsonb_array_elements_text(v_value));
          conditions := conditions || format('c.designation = ANY(%L::text[])', v_arr_values);
        ELSIF v_type = 'string' AND v_value #>> '{}' <> '' THEN
          conditions := conditions || format('c.designation = %L', v_value #>> '{}');
        END IF;
      
      WHEN 'companyName' THEN
        IF v_type = 'string' AND v_value #>> '{}' <> '' THEN
          conditions := conditions || format('comp.name ILIKE %L', '%' || (v_value #>> '{}') || '%');
        END IF;
      
      WHEN 'companyCountry' THEN
        IF v_type = 'array' AND jsonb_array_length(v_value) > 0 THEN
          v_int_arr_values := ARRAY(SELECT (jsonb_array_elements_text(v_value))::int);
          conditions := conditions || format('comp.country_id = ANY(ARRAY[%s]::int[])', array_to_string(v_int_arr_values, ','));
        ELSIF v_type = 'string' AND v_value #>> '{}' <> '' THEN
          conditions := conditions || format('comp.country_id = %s', (v_value #>> '{}')::int);
        ELSIF v_type = 'number' THEN
          conditions := conditions || format('comp.country_id = %s', (v_value #>> '{}')::int);
        END IF;
      
      WHEN 'companyState' THEN
        IF v_type = 'array' AND jsonb_array_length(v_value) > 0 THEN
          v_int_arr_values := ARRAY(SELECT (jsonb_array_elements_text(v_value))::int);
          conditions := conditions || format('comp.state_id = ANY(ARRAY[%s]::int[])', array_to_string(v_int_arr_values, ','));
        ELSIF v_type = 'string' AND v_value #>> '{}' <> '' THEN
          conditions := conditions || format('comp.state_id = %s', (v_value #>> '{}')::int);
        ELSIF v_type = 'number' THEN
          conditions := conditions || format('comp.state_id = %s', (v_value #>> '{}')::int);
        END IF;
      
      WHEN 'companyCity' THEN
        IF v_type = 'array' AND jsonb_array_length(v_value) > 0 THEN
          v_int_arr_values := ARRAY(SELECT (jsonb_array_elements_text(v_value))::int);
          conditions := conditions || format('comp.city_id = ANY(ARRAY[%s]::int[])', array_to_string(v_int_arr_values, ','));
        ELSIF v_type = 'string' AND v_value #>> '{}' <> '' THEN
          conditions := conditions || format('comp.city_id = %s', (v_value #>> '{}')::int);
        ELSIF v_type = 'number' THEN
          conditions := conditions || format('comp.city_id = %s', (v_value #>> '{}')::int);
        END IF;
      
      WHEN 'companyType' THEN
        IF v_type = 'array' AND jsonb_array_length(v_value) > 0 THEN
          v_int_arr_values := ARRAY(SELECT (jsonb_array_elements_text(v_value))::int);
          conditions := conditions || format('comp.companytype_id = ANY(ARRAY[%s]::int[])', array_to_string(v_int_arr_values, ','));
        ELSIF v_type = 'string' AND v_value #>> '{}' <> '' THEN
          conditions := conditions || format('comp.companytype_id = %s', (v_value #>> '{}')::int);
        ELSIF v_type = 'number' THEN
          conditions := conditions || format('comp.companytype_id = %s', (v_value #>> '{}')::int);
        END IF;
      
      WHEN 'companyStatus' THEN
        IF v_type = 'array' AND jsonb_array_length(v_value) > 0 THEN
          v_arr_values := ARRAY(SELECT jsonb_array_elements_text(v_value));
          conditions := conditions || format('comp.status = ANY(%L::text[])', v_arr_values);
        ELSIF v_type = 'string' AND v_value #>> '{}' <> '' THEN
          conditions := conditions || format('comp.status = %L', v_value #>> '{}');
        END IF;
      
      WHEN 'sfsProduct' THEN
        IF v_type = 'array' AND jsonb_array_length(v_value) > 0 THEN
          v_int_arr_values := ARRAY(SELECT (jsonb_array_elements_text(v_value))::int);
          conditions := conditions || format('csfs.productid = ANY(ARRAY[%s]::int[])', array_to_string(v_int_arr_values, ','));
        ELSIF v_type = 'number' THEN
          conditions := conditions || format('csfs.productid = %s', (v_value #>> '{}')::int);
        END IF;
      
      WHEN 'sfsId', 'sfsValue' THEN
        IF v_type = 'array' AND jsonb_array_length(v_value) > 0 THEN
          v_int_arr_values := ARRAY(SELECT (jsonb_array_elements_text(v_value))::int);
          conditions := conditions || format('csfs.sfsid = ANY(ARRAY[%s]::int[])', array_to_string(v_int_arr_values, ','));
        ELSIF v_type = 'number' THEN
          conditions := conditions || format('csfs.sfsid = %s', (v_value #>> '{}')::int);
        END IF;

      WHEN 'ibisUserPackage' THEN
        IF v_type = 'array' AND jsonb_array_length(v_value) > 0 THEN
          v_int_arr_values := ARRAY(SELECT (jsonb_array_elements_text(v_value))::int);
          conditions := conditions || format('iu.package = ANY(ARRAY[%s]::int[])', array_to_string(v_int_arr_values, ','));
        ELSIF v_type = 'number' THEN
          conditions := conditions || format('iu.package = %s', (v_value #>> '{}')::int);
        ELSIF v_type = 'string' AND v_value #>> '{}' <> '' THEN
          conditions := conditions || format('iu.package = %s', (v_value #>> '{}')::int);
        END IF;

      WHEN 'package' THEN
        IF v_type = 'array' AND jsonb_array_length(v_value) > 0 THEN
          v_int_arr_values := ARRAY(SELECT (jsonb_array_elements_text(v_value))::int);
          conditions := conditions || format('iu.package = ANY(ARRAY[%s]::int[])', array_to_string(v_int_arr_values, ','));
        ELSIF v_type = 'number' THEN
          conditions := conditions || format('iu.package = %s', (v_value #>> '{}')::int);
        END IF;

      WHEN 'ibisUserStatus' THEN
        IF v_type = 'array' AND jsonb_array_length(v_value) > 0 THEN
          v_arr_values := ARRAY(SELECT jsonb_array_elements_text(v_value));
          conditions := conditions || format('iu.status = ANY(%L::text[])', v_arr_values);
        ELSIF v_type = 'string' AND v_value #>> '{}' <> '' THEN
          conditions := conditions || format('iu.status = %L', v_value #>> '{}');
        END IF;

      WHEN 'ibisOnboardPlatform' THEN
        IF v_type = 'array' AND jsonb_array_length(v_value) > 0 THEN
          v_arr_values := ARRAY(SELECT jsonb_array_elements_text(v_value));
          conditions := conditions || format('iu.onboard_platform = ANY(%L::text[])', v_arr_values);
        ELSIF v_type = 'string' AND v_value #>> '{}' <> '' THEN
          conditions := conditions || format('iu.onboard_platform = %L', v_value #>> '{}');
        END IF;

      WHEN 'ibisSynergyRole' THEN
        IF v_type = 'array' AND jsonb_array_length(v_value) > 0 THEN
          v_arr_values := ARRAY(SELECT jsonb_array_elements_text(v_value));
          conditions := conditions || format('iu.ibis_synergy_role = ANY(%L::text[])', v_arr_values);
        ELSIF v_type = 'string' AND v_value #>> '{}' <> '' THEN
          conditions := conditions || format('iu.ibis_synergy_role = %L', v_value #>> '{}');
        END IF;

      WHEN 'ibisUserRight' THEN
        IF v_type = 'array' AND jsonb_array_length(v_value) > 0 THEN
          v_arr_values := ARRAY(SELECT jsonb_array_elements_text(v_value));
          conditions := conditions || format('iu.bi_user_right = ANY(%L::text[])', v_arr_values);
        ELSIF v_type = 'string' AND v_value #>> '{}' <> '' THEN
          conditions := conditions || format('iu.bi_user_right = %L', v_value #>> '{}');
        END IF;

      WHEN 'ibisLastLoginFrom' THEN
        IF v_type = 'string' AND v_value #>> '{}' <> '' THEN
          conditions := conditions || format('iu.last_login >= %L::date', v_value #>> '{}');
        END IF;

      WHEN 'ibisLastLoginTo' THEN
        IF v_type = 'string' AND v_value #>> '{}' <> '' THEN
          conditions := conditions || format('iu.last_login <= %L::date', v_value #>> '{}');
        END IF;

      WHEN 'ibisOnboardingDateFrom' THEN
        IF v_type = 'string' AND v_value #>> '{}' <> '' THEN
          conditions := conditions || format('iu.onboarding_date >= %L::date', v_value #>> '{}');
        END IF;

      WHEN 'ibisOnboardingDateTo' THEN
        IF v_type = 'string' AND v_value #>> '{}' <> '' THEN
          conditions := conditions || format('iu.onboarding_date <= %L::date', v_value #>> '{}');
        END IF;

      WHEN 'ibisUserCreatedFrom' THEN
        IF v_type = 'string' AND v_value #>> '{}' <> '' THEN
          conditions := conditions || format('iu.created_on >= %L::timestamp', v_value #>> '{}');
        END IF;

      WHEN 'ibisUserCreatedTo' THEN
        IF v_type = 'string' AND v_value #>> '{}' <> '' THEN
          conditions := conditions || format('iu.created_on <= %L::timestamp', v_value #>> '{}');
        END IF;

      WHEN 'ibisSubscriptionStartFrom' THEN
        IF v_type = 'string' AND v_value #>> '{}' <> '' THEN
          conditions := conditions || format('iu.subscription_start >= %L::date', v_value #>> '{}');
        END IF;

      WHEN 'ibisSubscriptionStartTo' THEN
        IF v_type = 'string' AND v_value #>> '{}' <> '' THEN
          conditions := conditions || format('iu.subscription_start <= %L::date', v_value #>> '{}');
        END IF;

      WHEN 'ibisSubscriptionEndFrom' THEN
        IF v_type = 'string' AND v_value #>> '{}' <> '' THEN
          conditions := conditions || format('iu.subscription_end >= %L::date', v_value #>> '{}');
        END IF;

      WHEN 'ibisSubscriptionEndTo' THEN
        IF v_type = 'string' AND v_value #>> '{}' <> '' THEN
          conditions := conditions || format('iu.subscription_end <= %L::date', v_value #>> '{}');
        END IF;

      WHEN 'interactionDateFrom' THEN
        IF v_type = 'string' AND v_value #>> '{}' <> '' THEN
          conditions := conditions || format(
            'EXISTS (SELECT 1 FROM interactioncompanies ic_f JOIN interactions i_f ON i_f.id = ic_f.interaction_id WHERE ic_f.company_id = comp.id AND i_f.date >= %L::date)',
            v_value #>> '{}'
          );
        END IF;
      
      WHEN 'interactionDateTo' THEN
        IF v_type = 'string' AND v_value #>> '{}' <> '' THEN
          conditions := conditions || format(
            'EXISTS (SELECT 1 FROM interactioncompanies ic_t JOIN interactions i_t ON i_t.id = ic_t.interaction_id WHERE ic_t.company_id = comp.id AND i_t.date <= %L::date)',
            v_value #>> '{}'
          );
        END IF;

      WHEN 'noInteractionMonths' THEN
        IF v_type = 'number' AND (v_value #>> '{}')::int > 0 THEN
          conditions := conditions || format(
            'NOT EXISTS (SELECT 1 FROM interactioncompanies ic2 JOIN interactions i2 ON i2.id = ic2.interaction_id WHERE ic2.company_id = comp.id AND i2.date >= (CURRENT_DATE - (%L::interval)))',
            (v_value #>> '{}')::int || ' months'
          );
        END IF;

      WHEN 'subscriptionStatus' THEN
        IF v_type = 'array' AND jsonb_array_length(v_value) > 0 THEN
          v_arr_values := ARRAY(SELECT jsonb_array_elements_text(v_value));
          conditions := conditions || format(
            'EXISTS (SELECT 1 FROM subscriptions sub WHERE sub.company_id = comp.id AND sub.status = ANY(%L::text[]))',
            v_arr_values
          );
        ELSIF v_type = 'string' AND v_value #>> '{}' <> '' THEN
          conditions := conditions || format(
            'EXISTS (SELECT 1 FROM subscriptions sub WHERE sub.company_id = comp.id AND sub.status = %L)',
            v_value #>> '{}'
          );
        END IF;

      WHEN 'hasAnalyticsPack' THEN
        IF (v_type = 'boolean' AND v_value::text = 'true') OR (v_type = 'string' AND v_value #>> '{}' = 'true') THEN
          conditions := conditions || format(
            'EXISTS (SELECT 1 FROM subscriptions sub JOIN analysesubscriptions asub ON asub.subscription_id = sub.id WHERE sub.company_id = comp.id AND sub.status = %L AND asub.status = %L)',
            'Active', 'Active'
          );
        END IF;

      WHEN 'hasEnterprisePack' THEN
        IF (v_type = 'boolean' AND v_value::text = 'true') OR (v_type = 'string' AND v_value #>> '{}' = 'true') THEN
          conditions := conditions || format(
            'EXISTS (SELECT 1 FROM subscriptions sub WHERE sub.company_id = comp.id AND sub.status = %L AND sub.package_type = %L)',
            'Active', 'Enterprise'
          );
        END IF;

      WHEN 'hasIbisPack' THEN
        IF (v_type = 'boolean' AND v_value::text = 'true') OR (v_type = 'string' AND v_value #>> '{}' = 'true') THEN
          conditions := conditions || format(
            'EXISTS (SELECT 1 FROM subscriptions sub WHERE sub.company_id = comp.id AND sub.status = %L AND sub.package_type = %L)',
            'Active', 'IBIS'
          );
        END IF;

      WHEN 'hasIntegrationPack' THEN
        IF (v_type = 'boolean' AND v_value::text = 'true') OR (v_type = 'string' AND v_value #>> '{}' = 'true') THEN
          conditions := conditions || format(
            'EXISTS (SELECT 1 FROM subscriptions sub WHERE sub.company_id = comp.id AND sub.status = %L AND sub.package_type = %L)',
            'Active', 'Integration'
          );
        END IF;

      WHEN 'hasResearchPack' THEN
        IF (v_type = 'boolean' AND v_value::text = 'true') OR (v_type = 'string' AND v_value #>> '{}' = 'true') THEN
          conditions := conditions || format(
            'EXISTS (SELECT 1 FROM subscriptions sub WHERE sub.company_id = comp.id AND sub.status = %L AND sub.package_type = %L)',
            'Active', 'Research'
          );
        END IF;
      
      ELSE
        NULL;
    END CASE;
  END LOOP;

  IF array_length(conditions, 1) IS NULL THEN
    RETURN 'TRUE';
  END IF;

  RETURN array_to_string(conditions, ' AND ');
END;
$$;


ALTER FUNCTION "public"."build_criteria_where_clause"("criteria" "jsonb") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."bulk_apply_sfs_to_linked_companies"() RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
    company_record RECORD;
    processed_count INTEGER := 0;
    success_count INTEGER := 0;
    failure_count INTEGER := 0;
    current_user_id UUID;
    results jsonb := '[]'::jsonb;
    result_item jsonb;
    existing_sfs RECORD;
    now_timestamp TIMESTAMP WITH TIME ZONE := now();
BEGIN
    -- Get current user ID
    current_user_id := auth.uid();
    
    IF current_user_id IS NULL THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', 'Authentication required'
        );
    END IF;

    -- Loop through all unique company-product combinations from linked leads
    FOR company_record IN 
        SELECT DISTINCT l.linked_company_id as company_id, l.product_id
        FROM public.leads l
        WHERE l.linked_company_id IS NOT NULL
        ORDER BY l.linked_company_id, l.product_id
    LOOP
        processed_count := processed_count + 1;
        
        BEGIN
            -- Check if SFS already exists for this company-product combination
            SELECT cs.id, cs.sfsid, s.sfs as sfs_name
            INTO existing_sfs
            FROM public.company_sfs cs
            JOIN public.sfs s ON s.id = cs.sfsid
            WHERE cs.companyid = company_record.company_id 
            AND cs.productid = company_record.product_id;
            
            IF FOUND THEN
                -- SFS exists, check if it's already Target (id: 2)
                IF existing_sfs.sfsid = 2 THEN
                    -- Already Target, no change needed
                    result_item := jsonb_build_object(
                        'companyId', company_record.company_id,
                        'productId', company_record.product_id,
                        'success', true,
                        'action', 'no_change',
                        'sfsName', existing_sfs.sfs_name,
                        'reason', 'Already Target'
                    );
                    success_count := success_count + 1;
                ELSE
                    -- Update to Target
                    UPDATE public.company_sfs 
                    SET sfsid = 2,
                        updatedby = current_user_id,
                        updatedon = now_timestamp
                    WHERE id = existing_sfs.id;
                    
                    result_item := jsonb_build_object(
                        'companyId', company_record.company_id,
                        'productId', company_record.product_id,
                        'success', true,
                        'action', 'updated',
                        'sfsName', 'Target',
                        'previousSfs', existing_sfs.sfs_name
                    );
                    success_count := success_count + 1;
                END IF;
            ELSE
                -- No SFS exists, create new Target SFS
                INSERT INTO public.company_sfs (
                    companyid,
                    productid,
                    sfsid,
                    enteredby,
                    enteredon,
                    updatedby,
                    updatedon
                ) VALUES (
                    company_record.company_id,
                    company_record.product_id,
                    2, -- Target SFS
                    current_user_id,
                    now_timestamp,
                    current_user_id,
                    now_timestamp
                );
                
                result_item := jsonb_build_object(
                    'companyId', company_record.company_id,
                    'productId', company_record.product_id,
                    'success', true,
                    'action', 'created',
                    'sfsName', 'Target'
                );
                success_count := success_count + 1;
            END IF;
            
        EXCEPTION WHEN OTHERS THEN
            -- Handle any errors for this specific company
            result_item := jsonb_build_object(
                'companyId', company_record.company_id,
                'productId', company_record.product_id,
                'success', false,
                'action', 'error',
                'error', SQLERRM
            );
            failure_count := failure_count + 1;
        END;
        
        -- Add result to results array
        results := results || result_item;
    END LOOP;
    
    -- Return comprehensive results
    RETURN jsonb_build_object(
        'success', failure_count = 0,
        'processedCount', processed_count,
        'successCount', success_count,
        'failureCount', failure_count,
        'message', format('Processed %s companies: %s successful, %s failed', 
                         processed_count, success_count, failure_count),
        'results', results,
        'executedAt', now_timestamp,
        'executedBy', current_user_id
    );
END;
$$;


ALTER FUNCTION "public"."bulk_apply_sfs_to_linked_companies"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."bulk_link_companies_by_domain"() RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
    lead_record RECORD;
    lead_domain text;
    matched_company_id integer;
    match_count integer;
    match_type text;
    processed_count integer := 0;
    linked_count integer := 0;
    skipped_count integer := 0;
    current_user_id UUID;
    now_timestamp TIMESTAMP WITH TIME ZONE := now();
BEGIN
    current_user_id := auth.uid();
    
    IF current_user_id IS NULL THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', 'Authentication required'
        );
    END IF;

    FOR lead_record IN 
        SELECT id, email, linked_company_id, notes
        FROM public.leads
        WHERE email IS NOT NULL 
        AND email != ''
        AND linked_company_id IS NULL
        AND status != 'Verified'
    LOOP
        processed_count := processed_count + 1;
        lead_domain := lower(split_part(lead_record.email, '@', 2));
        matched_company_id := NULL;
        match_type := NULL;
        
        IF lead_domain IS NOT NULL AND lead_domain != '' THEN
            -- Email domain matching with count check
            SELECT COUNT(*) INTO match_count
            FROM companies c
            WHERE (
                (c.email1 IS NOT NULL AND lower(split_part(c.email1, '@', 2)) = lead_domain) OR
                (c.email2 IS NOT NULL AND lower(split_part(c.email2, '@', 2)) = lead_domain) OR
                (c.email3 IS NOT NULL AND lower(split_part(c.email3, '@', 2)) = lead_domain)
            )
            AND c.status = 'Active';
            
            IF match_count = 1 THEN
                SELECT c.id INTO matched_company_id
                FROM companies c
                WHERE (
                    (c.email1 IS NOT NULL AND lower(split_part(c.email1, '@', 2)) = lead_domain) OR
                    (c.email2 IS NOT NULL AND lower(split_part(c.email2, '@', 2)) = lead_domain) OR
                    (c.email3 IS NOT NULL AND lower(split_part(c.email3, '@', 2)) = lead_domain)
                )
                AND c.status = 'Active';
                match_type := 'email_domain';
            END IF;
            
            -- Website domain matching with count check
            IF matched_company_id IS NULL THEN
                SELECT COUNT(*) INTO match_count
                FROM companies c
                WHERE c.status = 'Active'
                  AND (
                    extract_url_domain(c.website1) = lead_domain OR
                    extract_url_domain(c.website2) = lead_domain OR
                    extract_url_domain(c.website3) = lead_domain
                  );
                
                IF match_count = 1 THEN
                    SELECT c.id INTO matched_company_id
                    FROM companies c
                    WHERE c.status = 'Active'
                      AND (
                        extract_url_domain(c.website1) = lead_domain OR
                        extract_url_domain(c.website2) = lead_domain OR
                        extract_url_domain(c.website3) = lead_domain
                      );
                    match_type := 'website_domain';
                END IF;
            END IF;
            
            -- Only link if exactly one match found
            IF matched_company_id IS NOT NULL THEN
                UPDATE public.leads
                SET linked_company_id = matched_company_id,
                    linkedby = current_user_id,
                    linkedon = now_timestamp,
                    status = 'Verified',
                    notes = COALESCE(notes || ' ', '') || 'Bulk auto-linked via ' || match_type
                WHERE id = lead_record.id;
                
                linked_count := linked_count + 1;
            ELSE
                skipped_count := skipped_count + 1;
            END IF;
        ELSE
            skipped_count := skipped_count + 1;
        END IF;
    END LOOP;
    
    RETURN jsonb_build_object(
        'success', true,
        'processed', processed_count,
        'linked', linked_count,
        'skipped', skipped_count,
        'message', format('Processed %s leads: %s linked, %s skipped (multiple or no matches)', 
                         processed_count, linked_count, skipped_count)
    );
END;
$$;


ALTER FUNCTION "public"."bulk_link_companies_by_domain"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."bulk_update_company_sfs"("p_record_ids" integer[], "p_target_sfs_id" integer, "p_user_id" "uuid" DEFAULT "auth"."uid"()) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
    record_id integer;
    processed_count INTEGER := 0;
    success_count INTEGER := 0;
    failure_count INTEGER := 0;
    current_user_id UUID;
    results jsonb := '[]'::jsonb;
    result_item jsonb;
    existing_record RECORD;
    target_sfs_name TEXT;
    now_timestamp TIMESTAMP WITH TIME ZONE := now();
BEGIN
    -- Get current user ID
    current_user_id := COALESCE(p_user_id, auth.uid());
    
    IF current_user_id IS NULL THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', 'Authentication required'
        );
    END IF;

    -- Get target SFS name for reporting
    SELECT s.sfs INTO target_sfs_name
    FROM public.sfs s
    WHERE s.id = p_target_sfs_id;

    IF target_sfs_name IS NULL THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', 'Invalid target SFS ID'
        );
    END IF;

    -- Loop through all provided record IDs
    FOREACH record_id IN ARRAY p_record_ids
    LOOP
        processed_count := processed_count + 1;
        
        BEGIN
            -- Get existing record details
            SELECT cs.id, cs.sfsid, cs.companyid, cs.productid, s.sfs as current_sfs_name
            INTO existing_record
            FROM public.company_sfs cs
            JOIN public.sfs s ON s.id = cs.sfsid
            WHERE cs.id = record_id;
            
            IF NOT FOUND THEN
                -- Record not found
                result_item := jsonb_build_object(
                    'recordId', record_id,
                    'success', false,
                    'action', 'error',
                    'error', 'Record not found'
                );
                failure_count := failure_count + 1;
            ELSIF existing_record.sfsid = p_target_sfs_id THEN
                -- Already has target SFS, no change needed
                result_item := jsonb_build_object(
                    'recordId', record_id,
                    'companyId', existing_record.companyid,
                    'productId', existing_record.productid,
                    'success', true,
                    'action', 'no_change',
                    'currentSfs', existing_record.current_sfs_name,
                    'reason', 'Already has target SFS status'
                );
                success_count := success_count + 1;
            ELSE
                -- Update the record
                UPDATE public.company_sfs 
                SET sfsid = p_target_sfs_id,
                    updatedby = current_user_id,
                    updatedon = now_timestamp
                WHERE id = record_id;
                
                result_item := jsonb_build_object(
                    'recordId', record_id,
                    'companyId', existing_record.companyid,
                    'productId', existing_record.productid,
                    'success', true,
                    'action', 'updated',
                    'previousSfs', existing_record.current_sfs_name,
                    'newSfs', target_sfs_name
                );
                success_count := success_count + 1;
            END IF;
            
        EXCEPTION WHEN OTHERS THEN
            -- Handle any errors for this specific record
            result_item := jsonb_build_object(
                'recordId', record_id,
                'success', false,
                'action', 'error',
                'error', SQLERRM
            );
            failure_count := failure_count + 1;
        END;
        
        -- Add result to results array
        results := results || result_item;
    END LOOP;
    
    -- Return comprehensive results
    RETURN jsonb_build_object(
        'success', failure_count = 0,
        'processedCount', processed_count,
        'successCount', success_count,
        'failureCount', failure_count,
        'message', format('Processed %s records: %s successful, %s failed', 
                         processed_count, success_count, failure_count),
        'results', results,
        'executedAt', now_timestamp,
        'executedBy', current_user_id
    );
END;
$$;


ALTER FUNCTION "public"."bulk_update_company_sfs"("p_record_ids" integer[], "p_target_sfs_id" integer, "p_user_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."calculate_and_set_ntd"("p_company_id" integer, "p_product_id" integer, "p_trigger_type" "text", "p_task_id" integer DEFAULT NULL::integer, "p_task_status" "text" DEFAULT NULL::"text", "p_user_id" "uuid" DEFAULT NULL::"uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
    v_ntd_date DATE;
    v_reason TEXT;
    v_source_task_id INTEGER;
    v_source_reminder_id INTEGER;
    v_task_record RECORD;
    v_earliest_reminder RECORD;
    v_result JSONB;
BEGIN
    -- Initialize
    v_source_task_id := NULL;
    v_source_reminder_id := NULL;
    
    -- Get task details if task_id provided
    IF p_task_id IS NOT NULL THEN
        SELECT taskid, taskdate, taskstatus
        INTO v_task_record
        FROM tasklist
        WHERE tasklistid = p_task_id;
    END IF;

    -- Calculate NTD based on trigger type
    CASE p_trigger_type
        WHEN 'task_created' THEN
            -- LQ/SP/MP task creation sets NTD to that task's date
            IF v_task_record.taskid IN (6, 7, 8) THEN -- LQ=6, SP=7, MP=8
                v_ntd_date := v_task_record.taskdate::DATE;
                v_source_task_id := p_task_id;
                
                CASE v_task_record.taskid
                    WHEN 6 THEN v_reason := 'lq_task_date';
                    WHEN 7 THEN v_reason := 'sp_task_date';
                    WHEN 8 THEN v_reason := 'mp_task_date';
                END CASE;
            END IF;

        WHEN 'task_completed' THEN
            -- Handle task completion scenarios
            IF p_task_status IN ('Unsuccessful', 'Void') THEN
                -- SP/MP unsuccessful sets NTD to earliest pending reminder date
                IF v_task_record.taskid IN (7, 8) THEN
                    SELECT id, due_date
                    INTO v_earliest_reminder
                    FROM reminders
                    WHERE company_id = p_company_id
                      AND product_id = p_product_id
                      AND status = 'pending'
                    ORDER BY due_date ASC
                    LIMIT 1;
                    
                    IF v_earliest_reminder.id IS NOT NULL THEN
                        v_ntd_date := v_earliest_reminder.due_date;
                        v_reason := 'reminder_date';
                        v_source_reminder_id := v_earliest_reminder.id;
                    END IF;
                END IF;
            END IF;

        WHEN 'sm_assigned' THEN
            -- Sales Manager assignment - check for MP task date
            SELECT tasklistid, taskdate
            INTO v_task_record
            FROM tasklist
            WHERE companyid = p_company_id
              AND product_id = p_product_id
              AND taskid = 8 -- MP task
              AND taskstatus = 'Open'
            ORDER BY taskdate ASC
            LIMIT 1;
            
            IF v_task_record.tasklistid IS NOT NULL THEN
                v_ntd_date := v_task_record.taskdate::DATE;
                v_reason := 'mp_task_date';
                v_source_task_id := v_task_record.tasklistid;
            END IF;
    END CASE;

    -- Update or insert NTD record if we have a date
    IF v_ntd_date IS NOT NULL THEN
        INSERT INTO company_ntd (
            company_id,
            product_id,
            ntd_date,
            reason,
            source_task_id,
            source_reminder_id,
            updated_by,
            updated_at
        ) VALUES (
            p_company_id,
            p_product_id,
            v_ntd_date,
            v_reason,
            v_source_task_id,
            v_source_reminder_id,
            COALESCE(p_user_id, auth.uid()),
            NOW()
        )
        ON CONFLICT (company_id, product_id) 
        DO UPDATE SET
            ntd_date = EXCLUDED.ntd_date,
            reason = EXCLUDED.reason,
            source_task_id = EXCLUDED.source_task_id,
            source_reminder_id = EXCLUDED.source_reminder_id,
            updated_by = EXCLUDED.updated_by,
            updated_at = NOW();
            
        v_result := jsonb_build_object(
            'success', true,
            'ntd_date', v_ntd_date,
            'reason', v_reason,
            'source_task_id', v_source_task_id,
            'source_reminder_id', v_source_reminder_id
        );
    ELSE
        v_result := jsonb_build_object(
            'success', true,
            'message', 'No NTD update required for this trigger'
        );
    END IF;

    RETURN v_result;
END;
$$;


ALTER FUNCTION "public"."calculate_and_set_ntd"("p_company_id" integer, "p_product_id" integer, "p_trigger_type" "text", "p_task_id" integer, "p_task_status" "text", "p_user_id" "uuid") OWNER TO "postgres";


