    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  -- Check if any proforma from this quotation has been converted to tax invoice
  -- Assuming there's a tax_invoices table with proforma_id reference
  RETURN NOT EXISTS (
    SELECT 1 
    FROM tax_invoices ti
    JOIN proforma_invoices pi ON pi.id = ti.proforma_id
    WHERE pi.quotation_id = p_quotation_id
  );
END;
