CREATE OR REPLACE FUNCTION "public"."check_document_access"("p_document_id" integer, "p_user_id" "uuid" DEFAULT "auth"."uid"(), "p_required_permission" "text" DEFAULT 'view'::"text") RETURNS boolean
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  -- Document owner has all permissions
  IF EXISTS (
    SELECT 1 FROM document_metadata
    WHERE id = p_document_id AND owner_id = p_user_id
  ) THEN
    RETURN true;
  END IF;

  -- Check specific permission with hierarchical mapping
  RETURN EXISTS (
    SELECT 1
    FROM document_access_controls dac
    WHERE dac.document_id = p_document_id
      AND dac.user_id = p_user_id
      AND dac.is_active = true
      AND (dac.expires_at IS NULL OR dac.expires_at > now())
      AND (
        -- adminrevise has all permissions
        dac.permission_type = 'adminrevise'
        OR
        -- View permission check
        (p_required_permission IN ('view', 'read') AND dac.permission_type IN ('view', 'edit', 'approve', 'delete', 'adminrevise'))
        OR
        -- Edit permission check
        (p_required_permission = 'edit' AND dac.permission_type IN ('edit', 'approve', 'delete', 'adminrevise'))
        OR
        -- Approve permission check
        (p_required_permission = 'approve' AND dac.permission_type IN ('approve', 'adminrevise'))
        OR
        -- Delete permission check
        (p_required_permission = 'delete' AND dac.permission_type IN ('delete', 'adminrevise'))
        OR
        -- Manage/admin permission check (map to adminrevise)
        (p_required_permission IN ('manage', 'admin') AND dac.permission_type = 'adminrevise')
      )
  );
END;
$$;


ALTER FUNCTION "public"."check_document_access"("p_document_id" integer, "p_user_id" "uuid", "p_required_permission" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."check_duplicate_saved_search"("p_owner_id" "uuid", "p_name" character varying, "p_criteria" "jsonb", "p_search_id" integer DEFAULT NULL::integer) RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_criteria_hash TEXT;
  v_exists BOOLEAN;
BEGIN
  v_criteria_hash := encode(digest(p_criteria::text, 'sha256'), 'hex');
  
  SELECT EXISTS (
    SELECT 1 FROM saved_searches
    WHERE owner_id = p_owner_id
    AND name = p_name
    AND criteria_hash = v_criteria_hash
    AND (p_search_id IS NULL OR id != p_search_id)
  ) INTO v_exists;
  
  RETURN v_exists;
END;
$$;


ALTER FUNCTION "public"."check_duplicate_saved_search"("p_owner_id" "uuid", "p_name" character varying, "p_criteria" "jsonb", "p_search_id" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."check_module_permission"("_module_name" "text", "_action_code" "text", "_user_id" "uuid" DEFAULT "auth"."uid"(), "_product_id" integer DEFAULT NULL::integer) RETURNS boolean
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  -- Super Admin has all permissions
  IF public.check_user_role(_user_id, 'Super Admin') THEN
    RETURN true;
  END IF;
  
  -- Check specific permission
  RETURN EXISTS (
    SELECT 1
    FROM public.role_permissions rp
    JOIN public.module_action_datasets mad ON mad.id = rp.module_action_dataset_id
    JOIN public.modules m ON m.id = mad.module_id
    JOIN public.actions a ON a.id = mad.action_id
    WHERE m.name = _module_name
    AND a.code = _action_code
    AND rp.is_allowed = true
    AND (_product_id IS NULL OR rp.product_id = _product_id OR rp.product_id IS NULL)
    AND (
      -- Check primary role
      EXISTS (
        SELECT 1 FROM public.users u
        WHERE u.auth_user_id = _user_id 
        AND u.role_id = rp.role_id 
        AND u.status = 'active'
      ) OR
      -- Check additional roles
      EXISTS (
        SELECT 1 FROM public.user_roles ur
        JOIN public.users u ON u.id = ur.user_id
        WHERE u.auth_user_id = _user_id 
        AND ur.role_id = rp.role_id 
        AND ur.is_active = true 
        AND u.status = 'active'
      )
    )
  );
END;
$$;


ALTER FUNCTION "public"."check_module_permission"("_module_name" "text", "_action_code" "text", "_user_id" "uuid", "_product_id" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."check_module_view_permission"("_module_id" integer, "_product_id" integer DEFAULT NULL::integer) RETURNS boolean
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  SELECT EXISTS (
    SELECT 1
    FROM public.role_permissions rp
    JOIN public.module_action_datasets mad ON mad.id = rp.module_action_dataset_id
    JOIN public.actions a ON a.id = mad.action_id
    JOIN public.users u ON u.auth_user_id = auth.uid()
    WHERE mad.module_id = _module_id
      AND a.code = 'view'
      AND rp.role_id = u.role_id
      AND rp.is_allowed = TRUE
      AND u.status = 'active'
      AND (_product_id IS NULL OR rp.product_id = _product_id)
  );
$$;


ALTER FUNCTION "public"."check_module_view_permission"("_module_id" integer, "_product_id" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."check_mp_tasks_without_handlers"() RETURNS TABLE("tasklistid" integer, "companyid" integer, "product_id" integer, "taskowner" "uuid", "created_at" timestamp with time zone, "missing_handler" boolean)
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    t.tasklistid,
    t.companyid,
    t.product_id,
    t.taskowner,
    t.enteredon as created_at,
    (ch.id IS NULL) as missing_handler
  FROM tasklist t
  LEFT JOIN company_handlers ch ON 
    ch.companyid = t.companyid AND 
    ch.product_id = t.product_id AND 
    ch.handler_type_id = 3
  WHERE t.taskid = 8
    AND t.companyid IS NOT NULL
    AND t.product_id IS NOT NULL
    AND ch.id IS NULL
  ORDER BY t.enteredon DESC;
END;
$$;


ALTER FUNCTION "public"."check_mp_tasks_without_handlers"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."check_multiple_permissions"("_permissions_json" "jsonb", "_user_id" "uuid" DEFAULT "auth"."uid"()) RETURNS TABLE("permission_key" "text", "has_permission" boolean)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  permission_item jsonb;
BEGIN
  FOR permission_item IN SELECT jsonb_array_elements(_permissions_json)
  LOOP
    RETURN QUERY SELECT 
      (permission_item->>'moduleName' || '.' || permission_item->>'actionCode')::text as permission_key,
      public.check_module_permission(
        permission_item->>'moduleName',
        permission_item->>'actionCode',
        _user_id
      ) as has_permission;
  END LOOP;
  RETURN;
END;
$$;


ALTER FUNCTION "public"."check_multiple_permissions"("_permissions_json" "jsonb", "_user_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."check_user_role"("_user_id" "uuid" DEFAULT "auth"."uid"(), "_role_name" "text" DEFAULT NULL::"text") RETURNS boolean
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  user_role_name text;
BEGIN
  -- Get user's primary role
  SELECT r.name INTO user_role_name
  FROM public.users u
  JOIN public.roles r ON r.id = u.role_id
  WHERE u.auth_user_id = _user_id
  AND u.status = 'active'
  AND r.status = 'active';
  
  -- If no role name specified, return true if user has any role
  IF _role_name IS NULL THEN
    RETURN user_role_name IS NOT NULL;
  END IF;
  
  -- Check if user has the specified role (primary or additional)
  RETURN (
    user_role_name = _role_name OR
    EXISTS (
      SELECT 1 FROM public.user_roles ur
      JOIN public.users u ON u.id = ur.user_id
      JOIN public.roles r ON r.id = ur.role_id
      WHERE u.auth_user_id = _user_id 
      AND r.name = _role_name
      AND ur.is_active = true
      AND u.status = 'active'
      AND r.status = 'active'
    )
  );
END;
$$;


ALTER FUNCTION "public"."check_user_role"("_user_id" "uuid", "_role_name" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."cleanup_abandoned_draft_quotations"() RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
    deleted_count INTEGER;
BEGIN
    DELETE FROM quotations
    WHERE status = 'draft'
    AND created_at < NOW() - INTERVAL '24 hours';
    
    GET DIAGNOSTICS deleted_count = ROW_COUNT;
    RETURN deleted_count;
END;
$$;


ALTER FUNCTION "public"."cleanup_abandoned_draft_quotations"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."complete_quotation"("p_quotation_id" bigint, "p_data" "jsonb") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
    UPDATE quotations SET
        contact_id = COALESCE((p_data->>'contact_id')::INTEGER, contact_id),
        currency = COALESCE(p_data->>'currency', currency),
        exchange_rate = COALESCE((p_data->>'exchange_rate')::NUMERIC, exchange_rate),
        terms_conditions = COALESCE(p_data->>'terms_conditions', '100% Advance / Upon Order Confirmation.'),
        proposal_validity = COALESCE(p_data->>'proposal_validity', proposal_validity),
        early_termination_fee = COALESCE((p_data->>'early_termination_fee')::NUMERIC, 20.00),
        pdf_url = COALESCE(p_data->>'pdf_url', pdf_url),
        payment_plan = COALESCE(p_data->>'payment_plan', 'Upfront'),
        percentage = COALESCE((p_data->>'percentage')::INTEGER, 50),
        number_of_payments = COALESCE((p_data->>'number_of_payments')::INTEGER, 1),
        payment1_percentage = COALESCE((p_data->>'payment1_percentage')::NUMERIC, 100),
        payment2_percentage = COALESCE((p_data->>'payment2_percentage')::NUMERIC, 0),
        payment3_percentage = COALESCE((p_data->>'payment3_percentage')::NUMERIC, 0),
        payment2_date = (p_data->>'payment2_date')::DATE,
        payment3_date = (p_data->>'payment3_date')::DATE,
        quotation_type = COALESCE((p_data->>'quotation_type')::quotation_type, quotation_type),
        status = 'under_follow_up',
        updated_by = (p_data->>'updated_by')::UUID,
        updated_at = NOW()
    WHERE id = p_quotation_id
    AND status = 'draft';
    
    IF NOT FOUND THEN
        RETURN jsonb_build_object('success', false, 'error', 'Quotation not found or not in draft status');
    END IF;
    
    RETURN jsonb_build_object('success', true, 'quotation_id', p_quotation_id);
END;
$$;


ALTER FUNCTION "public"."complete_quotation"("p_quotation_id" bigint, "p_data" "jsonb") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."complete_tour"("p_user_id" "uuid", "p_tour_id" "text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
BEGIN
  INSERT INTO public.user_onboarding_progress (user_id, completed_tours, last_tour_date)
  VALUES (
    p_user_id,
    jsonb_build_array(p_tour_id),
    now()
  )
  ON CONFLICT (user_id) 
  DO UPDATE SET
    completed_tours = CASE 
      WHEN public.user_onboarding_progress.completed_tours ? p_tour_id 
      THEN public.user_onboarding_progress.completed_tours
      ELSE public.user_onboarding_progress.completed_tours || jsonb_build_array(p_tour_id)
    END,
    last_tour_date = now(),
    updated_at = now();
END;
$$;


ALTER FUNCTION "public"."complete_tour"("p_user_id" "uuid", "p_tour_id" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."create_recipient_list"("p_campaign_dataset_id" integer, "p_list_name" "text", "p_subcampaign_id" integer DEFAULT NULL::integer) RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
    new_list_id integer;
    dataset_product_id integer;
BEGIN
    -- Get product_id from campaign_dataset
    SELECT cd.product_id INTO dataset_product_id
    FROM public.campaign_datasets cd
    WHERE cd.id = p_campaign_dataset_id;

    IF NOT FOUND THEN
        RAISE EXCEPTION 'Campaign dataset not found: %', p_campaign_dataset_id;
    END IF;

    -- Enforce product access for calling user
    IF NOT public.has_product_access(dataset_product_id) THEN
        RAISE EXCEPTION 'Access denied for product %', dataset_product_id;
    END IF;

    -- Insert new recipient list
    INSERT INTO public.recipient_lists (
        name,
        campaign_dataset_id,
        subcampaign_id,
        product_id,
        created_by,
        updated_by,
        finalized
    ) VALUES (
        p_list_name,
        p_campaign_dataset_id,
        p_subcampaign_id,
        dataset_product_id,
        auth.uid(),
        auth.uid(),
        false
    )
    RETURNING id INTO new_list_id;

    RETURN new_list_id;
END;
$$;


ALTER FUNCTION "public"."create_recipient_list"("p_campaign_dataset_id" integer, "p_list_name" "text", "p_subcampaign_id" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."create_recipient_list_for_wizard"("p_campaign_dataset_id" integer, "p_name" "text", "p_subcampaign_id" integer DEFAULT NULL::integer, "p_product_id" integer DEFAULT NULL::integer) RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_list_id integer;
  v_product_id integer;
BEGIN
  -- Get product_id from dataset if not provided
  IF p_product_id IS NULL THEN
    SELECT product_id INTO v_product_id
    FROM campaign_datasets
    WHERE id = p_campaign_dataset_id;
    
    IF v_product_id IS NULL THEN
      RAISE EXCEPTION 'Dataset not found or missing product_id';
    END IF;
  ELSE
    v_product_id := p_product_id;
  END IF;

  -- Check product access for calling user
  IF NOT has_product_access(v_product_id) THEN
    RAISE EXCEPTION 'Access denied for product %', v_product_id;
  END IF;

  -- Insert the recipient list
  INSERT INTO recipient_lists (
    campaign_dataset_id,
    name,
    subcampaign_id,
    product_id,
    finalized,
    created_by,
    updated_by
  ) VALUES (
    p_campaign_dataset_id,
    p_name,
    p_subcampaign_id,
    v_product_id,
    false,
    auth.uid(),
    auth.uid()
  )
  RETURNING id INTO v_list_id;

  RETURN v_list_id;
END;
$$;


ALTER FUNCTION "public"."create_recipient_list_for_wizard"("p_campaign_dataset_id" integer, "p_name" "text", "p_subcampaign_id" integer, "p_product_id" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."create_recipient_list_from_criteria"("p_campaign_dataset_id" integer, "p_list_name" "text", "p_subcampaign_id" integer DEFAULT NULL::integer) RETURNS TABLE("total_contacts" integer, "valid_emails" integer, "excluded_contacts" integer, "recipient_list_id" integer)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_product_id integer;
  v_criteria jsonb;
  v_where_clause text;
  v_has_ibis_filters boolean;
  v_has_sfs_filters boolean;
  v_join_clause text;
  v_query text;
  v_populated_count integer;
  v_list_id integer;
  v_total integer;
  v_valid integer;
  v_excluded integer;
BEGIN
  -- 1. Read dataset info
  SELECT cd.product_id, cd.criteria
    INTO v_product_id, v_criteria
  FROM public.campaign_datasets cd
  WHERE cd.id = p_campaign_dataset_id;

  IF v_product_id IS NULL THEN
    RAISE EXCEPTION 'Dataset not found: %', p_campaign_dataset_id;
  END IF;

  IF NOT public.has_product_access(v_product_id) THEN
    RAISE EXCEPTION 'Access denied for product %', v_product_id;
  END IF;

  IF v_criteria IS NULL THEN
    v_criteria := '{}'::jsonb;
  END IF;

  -- GUARD: If criteria is empty, check for manually linked contacts
  IF v_criteria = '{}'::jsonb THEN
    SELECT count(*) INTO v_populated_count
    FROM public.campaign_dataset_contacts
    WHERE campaign_dataset_id = p_campaign_dataset_id;

    IF v_populated_count = 0 THEN
      RAISE EXCEPTION 'Dataset has no search criteria and no linked contacts';
    END IF;
  ELSE
    -- 2. Build WHERE clause from criteria
    v_where_clause := public.build_criteria_where_clause(v_criteria);
    v_has_ibis_filters := public.has_ibis_filters(v_criteria);
    v_has_sfs_filters := public.has_sfs_filters(v_criteria);

    v_join_clause := 'LEFT JOIN public.companies comp ON c.company_id = comp.id';
    IF v_has_ibis_filters THEN
      v_join_clause := v_join_clause || ' LEFT JOIN public.ibisusers iu ON c.id = iu.prime_contact_id';
    END IF;
    IF v_has_sfs_filters THEN
      v_join_clause := v_join_clause || ' LEFT JOIN public.company_sfs csfs ON comp.id = csfs.company_id';
    END IF;

    -- 3. Populate campaign_dataset_contacts (clear + insert)
    DELETE FROM public.campaign_dataset_contacts WHERE campaign_dataset_id = p_campaign_dataset_id;

    v_query := format(
      'INSERT INTO public.campaign_dataset_contacts (campaign_dataset_id, contact_id, created_at, updated_at)
       SELECT DISTINCT %s, c.id, NOW(), NOW()
       FROM public.contacts c
       %s
       WHERE c.email1 IS NOT NULL 
         AND c.email1 <> ''''
         AND COALESCE(c.status, ''Active'') = ''Active''
         AND (%s)
       ON CONFLICT (campaign_dataset_id, contact_id) DO NOTHING',
      p_campaign_dataset_id,
      v_join_clause,
      v_where_clause
    );

    EXECUTE v_query;
    GET DIAGNOSTICS v_populated_count = ROW_COUNT;

    IF v_populated_count = 0 THEN
      RAISE EXCEPTION 'No contacts match the dataset criteria';
    END IF;
  END IF;

  -- 4. Create the recipient_lists record
  INSERT INTO public.recipient_lists (
    campaign_dataset_id,
    name,
    subcampaign_id,
    product_id,
    finalized,
    created_by,
    updated_by
  ) VALUES (
    p_campaign_dataset_id,
    p_list_name,
    p_subcampaign_id,
    v_product_id,
    false,
    auth.uid(),
    auth.uid()
  )
  RETURNING id INTO v_list_id;

  -- 5. Insert recipient_list_members
  INSERT INTO public.recipient_list_members(
    recipient_list_id,
    contact_id,
    first_name,
    last_name,
    final_email,
    designation_name,
    company_name,
    company_id,
    generated_at
  )
  SELECT
    v_list_id,
    c.id,
    c.first_name,
    c.last_name,
    lower(coalesce(c.email1, c.email2, c.email3)) as final_email,
    d.designame as designation_name,
    comp.name as company_name,
    c.company_id,
    now()
  FROM public.campaign_dataset_contacts cdc
  JOIN public.contacts c ON c.id = cdc.contact_id
  LEFT JOIN public.designations d ON d.id = c.designation_id
  LEFT JOIN public.companies comp ON comp.id = c.company_id
  WHERE cdc.campaign_dataset_id = p_campaign_dataset_id
    AND coalesce(c.email1, c.email2, c.email3) IS NOT NULL
    AND coalesce(c.email1, c.email2, c.email3) != ''
    AND coalesce(c.status, 'Active') = 'Active';

  -- 6. Apply exclusions
  IF p_subcampaign_id IS NOT NULL THEN
    DELETE FROM public.recipient_list_members rlm
    USING public.exclusions e
    WHERE e.subcampaign_id = p_subcampaign_id AND e.type = 'contact'
      AND e.value::int = rlm.contact_id
      AND rlm.recipient_list_id = v_list_id
      AND (e.exclusion_type IS NULL);

    DELETE FROM public.recipient_list_members rlm
    USING public.exclusions e, public.contacts c
    WHERE e.subcampaign_id = p_subcampaign_id AND e.type = 'company'
      AND e.value::int = c.company_id AND c.id = rlm.contact_id
      AND rlm.recipient_list_id = v_list_id
      AND (e.exclusion_type IS NULL);

    DELETE FROM public.recipient_list_members rlm
    USING public.exclusions e, public.contacts c
    WHERE e.subcampaign_id = p_subcampaign_id AND e.type = 'domain'
      AND rlm.recipient_list_id = v_list_id
      AND c.id = rlm.contact_id
      AND (
        lower(coalesce(c.email1, '')) LIKE ('%@' || lower(e.value)) OR
        lower(coalesce(c.email2, '')) LIKE ('%@' || lower(e.value)) OR
        lower(coalesce(c.email3, '')) LIKE ('%@' || lower(e.value))
      )
      AND (e.exclusion_type IS NULL);
  END IF;

  -- 7. Get stats (qualified references to avoid ambiguity with RETURNS TABLE columns)
  SELECT count(*) INTO v_total FROM public.recipient_list_members rlm2 WHERE rlm2.recipient_list_id = v_list_id;
  SELECT count(*) INTO v_valid FROM public.recipient_list_members rlm2 WHERE rlm2.recipient_list_id = v_list_id AND rlm2.final_email IS NOT NULL AND rlm2.final_email != '';
  v_excluded := v_total - v_valid;

  RETURN QUERY SELECT v_total, v_valid, v_excluded, v_list_id;
END;
$$;


ALTER FUNCTION "public"."create_recipient_list_from_criteria"("p_campaign_dataset_id" integer, "p_list_name" "text", "p_subcampaign_id" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."delete_subcampaign_for_wizard"("p_subcampaign_id" integer) RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_product_id integer;
BEGIN
  -- Get product_id from subcampaign
  SELECT product_id INTO v_product_id
  FROM subcampaigns
  WHERE id = p_subcampaign_id;
  
  IF v_product_id IS NULL THEN
    RAISE EXCEPTION 'Subcampaign not found';
  END IF;

  -- Check product access for calling user
  IF NOT has_product_access(v_product_id) THEN
    RAISE EXCEPTION 'Access denied for product %', v_product_id;
  END IF;

  -- Delete the subcampaign
  DELETE FROM subcampaigns WHERE id = p_subcampaign_id;

  RETURN true;
END;
$$;


ALTER FUNCTION "public"."delete_subcampaign_for_wizard"("p_subcampaign_id" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."dismiss_hint"("p_user_id" "uuid", "p_hint_id" "text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
BEGIN
  INSERT INTO public.user_onboarding_progress (user_id, dismissed_hints)
  VALUES (
    p_user_id,
    jsonb_build_array(p_hint_id)
  )
  ON CONFLICT (user_id) 
  DO UPDATE SET
    dismissed_hints = CASE 
      WHEN public.user_onboarding_progress.dismissed_hints ? p_hint_id 
      THEN public.user_onboarding_progress.dismissed_hints
      ELSE public.user_onboarding_progress.dismissed_hints || jsonb_build_array(p_hint_id)
    END,
    updated_at = now();
END;
$$;


