CREATE OR REPLACE FUNCTION "public"."enforce_subcampaign_dates"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
DECLARE 
  c_start timestamptz; 
  c_end timestamptz;
BEGIN
  SELECT start_date, end_date INTO c_start, c_end 
  FROM campaigns 
  WHERE id = NEW.campaign_id;
  
  IF NEW.start_date < c_start OR NEW.end_date > c_end THEN
    RAISE EXCEPTION 'Subcampaign dates must be within campaign dates';
  END IF;
  
  RETURN NEW;
END;
$$;


