CREATE OR REPLACE FUNCTION "public"."extract_url_domain"("url" "text") RETURNS "text"
    LANGUAGE "plpgsql" IMMUTABLE
    SET "search_path" TO 'public'
    AS $$
DECLARE
    domain text;
BEGIN
    IF url IS NULL OR url = '' THEN
        RETURN NULL;
    END IF;
    
    domain := regexp_replace(url, '^[a-zA-Z]+://', '');
    domain := regexp_replace(domain, '^www\.', '');
    domain := split_part(domain, '/', 1);
    domain := split_part(domain, '?', 1);
    domain := split_part(domain, '#', 1);
    domain := split_part(domain, ':', 1);
    
    RETURN lower(domain);
END;
$$;


ALTER FUNCTION "public"."extract_url_domain"("url" "text") OWNER TO "postgres";


