CREATE OR REPLACE FUNCTION "public"."generate_document_reference"("p_department_id" integer, "p_document_type_code" character varying) RETURNS character varying
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_dept_code VARCHAR;
  v_year_month VARCHAR;
  v_sequence INTEGER;
  v_reference VARCHAR;
BEGIN
  -- Get department code
  SELECT code INTO v_dept_code
  FROM public.departments
  WHERE id = p_department_id;
  
  IF v_dept_code IS NULL THEN
    v_dept_code := 'GEN'; -- Default if no department
  END IF;
  
  -- Generate year-month string (YYYYMM)
  v_year_month := TO_CHAR(CURRENT_DATE, 'YYYYMM');
  
  -- Get and increment sequence for this department-type-month combination
  INSERT INTO public.document_reference_sequences (
    department_id,
    document_type_code,
    year_month,
    last_sequence
  )
  VALUES (
    p_department_id,
    p_document_type_code,
    v_year_month,  -- Use variable with v_ prefix
    1
  )
  ON CONFLICT (department_id, document_type_code, year_month)
  DO UPDATE SET 
    last_sequence = document_reference_sequences.last_sequence + 1,
    updated_at = now()
  RETURNING last_sequence INTO v_sequence;
  
  -- Format: DEPT-TYPE-YYYYMM-NNNN
  v_reference := v_dept_code || '-' || p_document_type_code || '-' || v_year_month || '-' || LPAD(v_sequence::TEXT, 4, '0');
  
  RETURN v_reference;
END;
$$;


ALTER FUNCTION "public"."generate_document_reference"("p_department_id" integer, "p_document_type_code" character varying) OWNER TO "postgres";


