CREATE OR REPLACE FUNCTION "public"."generate_proforma_number"() RETURNS "text"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $_$
DECLARE
    next_increment integer;
    current_year text;
    generated_proforma_number text;
BEGIN
    -- Get current year (last 2 digits)
    current_year := EXTRACT(YEAR FROM NOW())::text;
    current_year := RIGHT(current_year, 2);
    
    -- Get next increment number
    SELECT COALESCE(MAX(
        CASE 
            WHEN proforma_invoices.proforma_number ~ '^ACC-PI-001-[0-9]+-[0-9]{2}$' 
            THEN (split_part(split_part(proforma_invoices.proforma_number, '-', 4), '-', 1))::integer
            ELSE 0
        END
    ), 0) + 1 
    INTO next_increment
    FROM proforma_invoices
    WHERE proforma_invoices.proforma_number LIKE 'ACC-PI-001-%' || current_year;
    
    -- Generate the proforma number in format ACC-PI-001-{increment}-{year}
    generated_proforma_number := 'ACC-PI-001-' || next_increment::text || '-' || current_year;
    
    RETURN generated_proforma_number;
END;
$_$;


ALTER FUNCTION "public"."generate_proforma_number"() OWNER TO "postgres";


