CREATE OR REPLACE FUNCTION "public"."get_bulletin_stats"("p_bulletin_id" integer DEFAULT NULL::integer, "p_bulletin_ids" integer[] DEFAULT NULL::integer[], "p_date_from" timestamp with time zone DEFAULT NULL::timestamp with time zone, "p_date_to" timestamp with time zone DEFAULT NULL::timestamp with time zone) RETURNS json
    LANGUAGE "plpgsql" STABLE
    AS $$
DECLARE
  result JSON;
BEGIN
  SELECT json_build_object(
    'totalSent', COUNT(*)::INTEGER,
    'delivered', COUNT(*) FILTER (WHERE status = 'delivered' OR (status = 'sent' AND (first_opened_at IS NOT NULL OR first_clicked_at IS NOT NULL)))::INTEGER,
    'opened', COUNT(*) FILTER (WHERE first_opened_at IS NOT NULL)::INTEGER,
    'clicked', COUNT(*) FILTER (WHERE first_clicked_at IS NOT NULL)::INTEGER,
    'bounced', COUNT(*) FILTER (WHERE status = 'bounced')::INTEGER
  ) INTO result
  FROM bulletin_sends
  WHERE
    (p_bulletin_id IS NULL OR bulletin_id = p_bulletin_id)
    AND (p_bulletin_ids IS NULL OR bulletin_id = ANY(p_bulletin_ids))
    AND (p_date_from IS NULL OR queued_at >= p_date_from)
    AND (p_date_to IS NULL OR queued_at <= p_date_to);
  
  RETURN result;
END;
$$;


ALTER FUNCTION "public"."get_bulletin_stats"("p_bulletin_id" integer, "p_bulletin_ids" integer[], "p_date_from" timestamp with time zone, "p_date_to" timestamp with time zone) OWNER TO "postgres";


