CREATE OR REPLACE FUNCTION "public"."get_dataset_companies_filtered"("p_dataset_id" integer) RETURNS TABLE("company_id" integer, "company_name" "text", "contact_count" bigint)
    LANGUAGE "plpgsql" STABLE
    AS $$
DECLARE
  v_criteria jsonb;
  v_search_type text;
  v_where_clause text;
  v_has_ibis_filters boolean := false;
  v_has_company_filters boolean := false;
  v_has_sfs_filters boolean := false;
  v_query text;
BEGIN
  -- Get dataset criteria
  SELECT d.criteria, d.search_type
  INTO v_criteria, v_search_type
  FROM campaign_datasets d
  WHERE d.id = p_dataset_id;

  IF NOT FOUND THEN
    RETURN;
  END IF;

  -- Build WHERE clause from criteria
  v_where_clause := build_criteria_where_clause(v_criteria);

  -- Detect if we need IBIS, SFS, or company joins
  IF v_criteria IS NOT NULL THEN
    v_has_ibis_filters := v_criteria ?| ARRAY['ibisUserPackage', 'ibisUserStatus', 'ibisOnboardPlatform', 
      'ibisSubscriptionStartFrom', 'ibisSubscriptionStartTo', 'ibisSubscriptionEndFrom', 
      'ibisSubscriptionEndTo', 'ibisLastLoginFrom', 'ibisLastLoginTo'];
    v_has_company_filters := v_criteria ?| ARRAY['companyName', 'companyCountry', 'companyState', 
      'companyCity', 'companyType', 'companyStatus'];
    v_has_sfs_filters := v_criteria ?| ARRAY['sfsProduct', 'sfsValue'];
  END IF;

  -- Always need company join for grouping
  v_query := 'SELECT comp.id AS company_id, comp.name::text AS company_name, COUNT(DISTINCT c.id) AS contact_count
    FROM campaign_dataset_contacts cdc
    JOIN contacts c ON c.id = cdc.contact_id
    LEFT JOIN companies comp ON comp.id = c.company_id';

  -- Add SFS join if needed
  IF v_has_sfs_filters THEN
    v_query := v_query || ' LEFT JOIN company_sfs csfs ON csfs.companyid = comp.id';
  END IF;

  -- Add IBIS join if needed
  IF v_has_ibis_filters OR v_search_type = 'ibis' THEN
    v_query := v_query || ' LEFT JOIN ibisusers iu ON iu.contact_id = c.id';
  END IF;

  v_query := v_query || format(' WHERE cdc.campaign_dataset_id = %s AND c.company_id IS NOT NULL', p_dataset_id);

  IF v_where_clause <> 'TRUE' THEN
    v_query := v_query || ' AND ' || v_where_clause;
  END IF;

  v_query := v_query || ' GROUP BY comp.id, comp.name ORDER BY contact_count DESC';

  RETURN QUERY EXECUTE v_query;
END;
$$;


ALTER FUNCTION "public"."get_dataset_companies_filtered"("p_dataset_id" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_dataset_recipient_lists_stats"("p_campaign_dataset_id" integer) RETURNS "jsonb"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
DECLARE
    stats JSONB;
    lists_count INTEGER := 0;
    last_generated TIMESTAMP WITH TIME ZONE;
BEGIN
    -- Get recipient lists count and last generation time
    SELECT 
        COUNT(rl.id),
        MAX(rl.created_at)
    INTO lists_count, last_generated
    FROM recipient_lists rl
    WHERE rl.campaign_dataset_id = p_campaign_dataset_id;
    
    stats := jsonb_build_object(
        'recipient_lists_count', COALESCE(lists_count, 0),
        'last_generated', last_generated
    );
    
    RETURN stats;
END;
$$;


ALTER FUNCTION "public"."get_dataset_recipient_lists_stats"("p_campaign_dataset_id" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_deletion_dependencies"("_table_name" "text", "_record_id" integer) RETURNS TABLE("dependent_table" "text", "record_count" integer, "description" "text")
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  -- For roles
  IF _table_name = 'roles' THEN
    RETURN QUERY
    SELECT 
      'users'::text as dependent_table,
      COUNT(*)::integer as record_count,
      'Users assigned to this role'::text as description
    FROM users u 
    WHERE u.role_id = _record_id
    UNION ALL
    SELECT 
      'user_roles'::text as dependent_table,
      COUNT(*)::integer as record_count,
      'Additional role assignments'::text as description
    FROM user_roles ur 
    WHERE ur.role_id = _record_id AND ur.is_active = true
    UNION ALL
    SELECT 
      'role_permissions'::text as dependent_table,
      COUNT(*)::integer as record_count,
      'Permission settings for this role'::text as description
    FROM role_permissions rp 
    WHERE rp.role_id = _record_id;
  END IF;

  -- For modules
  IF _table_name = 'modules' THEN
    RETURN QUERY
    SELECT 
      'module_action_datasets'::text as dependent_table,
      COUNT(*)::integer as record_count,
      'Permission configurations using this module'::text as description
    FROM module_action_datasets mad 
    WHERE mad.module_id = _record_id;
  END IF;

  -- For actions
  IF _table_name = 'actions' THEN
    RETURN QUERY
    SELECT 
      'module_action_datasets'::text as dependent_table,
      COUNT(*)::integer as record_count,
      'Permission configurations using this action'::text as description
    FROM module_action_datasets mad 
    WHERE mad.action_id = _record_id;
  END IF;

  -- For datasets
  IF _table_name = 'datasets' THEN
    RETURN QUERY
    SELECT 
      'module_action_datasets'::text as dependent_table,
      COUNT(*)::integer as record_count,
      'Permission configurations using this dataset'::text as description
    FROM module_action_datasets mad 
    WHERE mad.dataset_id = _record_id;
  END IF;

  -- For teams
  IF _table_name = 'teams' THEN
    RETURN QUERY
    SELECT 
      'team_members'::text as dependent_table,
      COUNT(*)::integer as record_count,
      'Team members'::text as description
    FROM team_members tm 
    WHERE tm.team_id = _record_id AND tm.is_active = true;
  END IF;

  -- For users
  IF _table_name = 'users' THEN
    RETURN QUERY
    SELECT 
      'team_members'::text as dependent_table,
      COUNT(*)::integer as record_count,
      'Team memberships'::text as description
    FROM team_members tm 
    WHERE tm.user_id = _record_id AND tm.is_active = true
    UNION ALL
    SELECT 
      'user_roles'::text as dependent_table,
      COUNT(*)::integer as record_count,
      'Additional role assignments'::text as description
    FROM user_roles ur 
    WHERE ur.user_id = _record_id AND ur.is_active = true;
  END IF;

  -- Add more table dependencies as needed
  RETURN;
END;
$$;


ALTER FUNCTION "public"."get_deletion_dependencies"("_table_name" "text", "_record_id" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_earliest_open_reminder"("p_company_id" integer, "p_product_id" integer) RETURNS TABLE("reminder_id" integer, "due_date" timestamp with time zone)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
    RETURN QUERY
    SELECT r.id, r.due_date
    FROM reminders r
    WHERE r.company_id = p_company_id
      AND r.product_id = p_product_id
      AND r.status = 'Pending'
      AND r.due_date >= NOW()
    ORDER BY r.due_date ASC
    LIMIT 1;
END;
$$;


