CREATE OR REPLACE FUNCTION "public"."get_filtered_company_ids"("p_permission_ids" integer[] DEFAULT NULL::integer[], "p_subscription_status" "text"[] DEFAULT NULL::"text"[], "p_subscription_start_from" "date" DEFAULT NULL::"date", "p_subscription_start_to" "date" DEFAULT NULL::"date", "p_subscription_end_from" "date" DEFAULT NULL::"date", "p_subscription_end_to" "date" DEFAULT NULL::"date", "p_user_count_min" integer DEFAULT NULL::integer, "p_user_count_max" integer DEFAULT NULL::integer, "p_auto_renewal" boolean DEFAULT NULL::boolean, "p_subscription_created_from" timestamp with time zone DEFAULT NULL::timestamp with time zone, "p_subscription_created_to" timestamp with time zone DEFAULT NULL::timestamp with time zone, "p_has_ibis" boolean DEFAULT false, "p_has_research" boolean DEFAULT false, "p_has_analytics" boolean DEFAULT false, "p_has_integration" boolean DEFAULT false, "p_sfs_product_ids" integer[] DEFAULT NULL::integer[], "p_sfs_ids" integer[] DEFAULT NULL::integer[], "p_handler_type_ids" integer[] DEFAULT NULL::integer[], "p_handler_user_ids" "text"[] DEFAULT NULL::"text"[], "p_handler_assigned_from" "date" DEFAULT NULL::"date", "p_handler_assigned_to" "date" DEFAULT NULL::"date", "p_competitor_ids" integer[] DEFAULT NULL::integer[], "p_competitor_product_ids" integer[] DEFAULT NULL::integer[], "p_competitor_end_from" "date" DEFAULT NULL::"date", "p_competitor_end_to" "date" DEFAULT NULL::"date", "p_competitor_created_by" "text"[] DEFAULT NULL::"text"[], "p_competitor_updated_by" "text"[] DEFAULT NULL::"text"[], "p_competitor_created_from" timestamp with time zone DEFAULT NULL::timestamp with time zone, "p_competitor_created_to" timestamp with time zone DEFAULT NULL::timestamp with time zone, "p_competitor_updated_from" timestamp with time zone DEFAULT NULL::timestamp with time zone, "p_competitor_updated_to" timestamp with time zone DEFAULT NULL::timestamp with time zone) RETURNS TABLE("id" integer)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  has_subscription_filter boolean;
  has_sfs_filter boolean;
  has_handler_filter boolean;
  has_competitor_filter boolean;
  handler_uuids uuid[];
  comp_created_by_uuids uuid[];
  comp_updated_by_uuids uuid[];
BEGIN
  has_subscription_filter := (
    p_subscription_status IS NOT NULL OR
    p_subscription_start_from IS NOT NULL OR p_subscription_start_to IS NOT NULL OR
    p_subscription_end_from IS NOT NULL OR p_subscription_end_to IS NOT NULL OR
    p_user_count_min IS NOT NULL OR p_user_count_max IS NOT NULL OR
    p_auto_renewal IS NOT NULL OR
    p_subscription_created_from IS NOT NULL OR p_subscription_created_to IS NOT NULL OR
    p_has_ibis OR p_has_research OR p_has_analytics OR p_has_integration
  );
  has_sfs_filter := (p_sfs_product_ids IS NOT NULL OR p_sfs_ids IS NOT NULL);
  has_handler_filter := (
    p_handler_type_ids IS NOT NULL OR p_handler_user_ids IS NOT NULL OR
    p_handler_assigned_from IS NOT NULL OR p_handler_assigned_to IS NOT NULL
  );
  has_competitor_filter := (
    p_competitor_ids IS NOT NULL OR p_competitor_product_ids IS NOT NULL OR
    p_competitor_end_from IS NOT NULL OR p_competitor_end_to IS NOT NULL OR
    p_competitor_created_by IS NOT NULL OR p_competitor_updated_by IS NOT NULL OR
    p_competitor_created_from IS NOT NULL OR p_competitor_created_to IS NOT NULL OR
    p_competitor_updated_from IS NOT NULL OR p_competitor_updated_to IS NOT NULL
  );

  IF p_handler_user_ids IS NOT NULL THEN
    handler_uuids := p_handler_user_ids::uuid[];
  END IF;
  IF p_competitor_created_by IS NOT NULL THEN
    comp_created_by_uuids := p_competitor_created_by::uuid[];
  END IF;
  IF p_competitor_updated_by IS NOT NULL THEN
    comp_updated_by_uuids := p_competitor_updated_by::uuid[];
  END IF;

  RETURN QUERY
  SELECT c.id
  FROM companies c
  WHERE
    (p_permission_ids IS NULL OR c.id = ANY(p_permission_ids))
    AND (NOT has_subscription_filter OR EXISTS (
      SELECT 1 FROM subscriptions s
      WHERE s.company_id = c.id
        AND (p_subscription_status IS NULL OR s.status = ANY(p_subscription_status))
        AND (p_subscription_start_from IS NULL OR s.start_date >= p_subscription_start_from)
        AND (p_subscription_start_to IS NULL OR s.start_date <= p_subscription_start_to)
        AND (p_subscription_end_from IS NULL OR s.end_date >= p_subscription_end_from)
        AND (p_subscription_end_to IS NULL OR s.end_date <= p_subscription_end_to)
        AND (p_user_count_min IS NULL OR s.user_count >= p_user_count_min)
        AND (p_user_count_max IS NULL OR s.user_count <= p_user_count_max)
        AND (p_auto_renewal IS NULL OR s.auto_renewal = p_auto_renewal)
        AND (p_subscription_created_from IS NULL OR s.created >= p_subscription_created_from)
        AND (p_subscription_created_to IS NULL OR s.created <= p_subscription_created_to)
        AND (NOT p_has_ibis OR EXISTS (SELECT 1 FROM ibissubscriptions i WHERE i.subscription_id = s.id))
        AND (NOT p_has_research OR EXISTS (SELECT 1 FROM researchsubscriptions r WHERE r.subscription_id = s.id))
        AND (NOT p_has_analytics OR EXISTS (SELECT 1 FROM analysesubscriptions a WHERE a.subscription_id = s.id AND a.pack_id NOT IN (38, 40, 54, 56, 69, 71, 84, 86)))
        AND (NOT p_has_integration OR EXISTS (SELECT 1 FROM integrationsubscriptions it WHERE it.subscription_id = s.id))
    ))
    AND (NOT has_sfs_filter OR EXISTS (
      SELECT 1 FROM company_sfs cs
      WHERE cs.companyid = c.id
        AND (p_sfs_product_ids IS NULL OR cs.productid = ANY(p_sfs_product_ids))
        AND (p_sfs_ids IS NULL OR cs.sfsid = ANY(p_sfs_ids))
    ))
    AND (NOT has_handler_filter OR EXISTS (
      SELECT 1 FROM company_handlers ch
      WHERE ch.companyid = c.id
        AND (p_handler_type_ids IS NULL OR ch.handler_type_id = ANY(p_handler_type_ids))
        AND (handler_uuids IS NULL OR ch.handler_id = ANY(handler_uuids))
        AND (p_handler_assigned_from IS NULL OR ch.entered_on >= p_handler_assigned_from)
        AND (p_handler_assigned_to IS NULL OR ch.entered_on <= (p_handler_assigned_to + interval '1 day' - interval '1 second'))
    ))
    AND (NOT has_competitor_filter OR EXISTS (
      SELECT 1 FROM competitor_subscriptions cs2
      WHERE cs2.company_id = c.id
        AND (p_competitor_ids IS NULL OR cs2.competitor_id = ANY(p_competitor_ids))
        AND (p_competitor_product_ids IS NULL OR cs2.product_id = ANY(p_competitor_product_ids))
        AND (p_competitor_end_from IS NULL OR cs2.end_date >= p_competitor_end_from)
        AND (p_competitor_end_to IS NULL OR cs2.end_date <= p_competitor_end_to)
        AND (comp_created_by_uuids IS NULL OR cs2.created_by = ANY(comp_created_by_uuids))
        AND (comp_updated_by_uuids IS NULL OR cs2.updated_by = ANY(comp_updated_by_uuids))
        AND (p_competitor_created_from IS NULL OR cs2.created_at >= p_competitor_created_from)
        AND (p_competitor_created_to IS NULL OR cs2.created_at <= p_competitor_created_to)
        AND (p_competitor_updated_from IS NULL OR cs2.updated_at >= p_competitor_updated_from)
        AND (p_competitor_updated_to IS NULL OR cs2.updated_at <= p_competitor_updated_to)
    ));
END;
$$;


