CREATE OR REPLACE FUNCTION "public"."get_filtered_users"("_user_id" "uuid" DEFAULT "auth"."uid"()) RETURNS TABLE("id" integer, "username" "text", "email" "text", "status" "text", "role_name" "text", "company_name" "text", "created_at" timestamp with time zone, "updated_at" timestamp with time zone)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  filter_condition text;
BEGIN
  -- Get dataset filter for Administration module view action
  filter_condition := public.apply_dataset_filter('Administration', 'view', _user_id);
  
  -- Apply filter and return user data
  RETURN QUERY EXECUTE format('
    SELECT 
      u.id,
      u.username,
      COALESCE(au.email, '''') as email,
      u.status,
      r.name as role_name,
      c.name as company_name,
      u.created_at,
      u.updated_at
    FROM users u
    LEFT JOIN auth.users au ON au.id = u.auth_user_id
    LEFT JOIN roles r ON r.id = u.role_id
    LEFT JOIN companies c ON c.id = u.company_id
    WHERE %s
    ORDER BY u.created_at DESC', filter_condition);
END;
$$;


ALTER FUNCTION "public"."get_filtered_users"("_user_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_handler_performance"("p_from_date" "date" DEFAULT NULL::"date", "p_to_date" "date" DEFAULT NULL::"date", "p_handler_id" integer DEFAULT NULL::integer, "p_include_projects_approved" boolean DEFAULT true, "p_include_projects_submitted" boolean DEFAULT true, "p_include_projects_created" boolean DEFAULT true, "p_include_projects_reviewed" boolean DEFAULT true, "p_include_irs_closed" boolean DEFAULT true, "p_include_keycontacts_added" boolean DEFAULT true, "p_include_contacts_created" boolean DEFAULT true) RETURNS TABLE("handler_id" integer, "handler_name" "text", "projects_approved" bigint, "projects_submitted" bigint, "projects_created" bigint, "projects_reviewed" bigint, "irs_closed" bigint, "keycontacts_added" bigint, "contacts_created" bigint)
    LANGUAGE "sql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
WITH params AS (
  SELECT
    p_from_date AS from_date,
    p_to_date AS to_date,
    CASE WHEN p_from_date IS NULL THEN NULL ELSE (p_from_date::timestamptz) END AS from_ts,
    CASE WHEN p_to_date IS NULL THEN NULL ELSE ((p_to_date + 1)::timestamptz) END AS to_ts
),
projectlog_base AS (
  SELECT pl.performed_by_id AS hid, pl.description
  FROM public.projectlog pl
  CROSS JOIN params pa
  WHERE (p_include_projects_approved OR p_include_projects_submitted OR p_include_projects_reviewed)
    AND pl.performed_by_id IS NOT NULL
    AND (p_handler_id IS NULL OR pl.performed_by_id = p_handler_id)
    -- IMPORTANT: keep timestamp filter index-friendly (no ::date casts)
    AND (pa.from_ts IS NULL OR pl."timestamp" >= pa.from_ts)
    AND (pa.to_ts IS NULL OR pl."timestamp" < pa.to_ts)
),
projectlog_agg AS (
  SELECT
    hid,
    COUNT(*) FILTER (
      WHERE p_include_projects_approved
        AND description LIKE '%to ''Approved''%'
        AND description NOT LIKE '%from ''Approved''%'
    ) AS projects_approved,
    COUNT(*) FILTER (
      WHERE p_include_projects_submitted
        AND description LIKE '%to ''Pending Review''%'
        AND description NOT LIKE '%from ''Pending Review''%'
    ) AS projects_submitted,
    COUNT(*) FILTER (
      WHERE p_include_projects_reviewed
        AND (
          -- Reviewed = QA actions moving away from Pending Review/Approval
          (description LIKE '%from ''Pending Review''%'
            AND (description LIKE '%to ''Approved''%' OR description LIKE '%to ''Rejected''%' OR description LIKE '%to ''WIP''%'))
          OR
          (description LIKE '%from ''Pending Approval''%'
            AND (description LIKE '%to ''Approved''%' OR description LIKE '%to ''Rejected''%' OR description LIKE '%to ''WIP''%'))
        )
    ) AS projects_reviewed
  FROM projectlog_base
  GROUP BY hid
),
projects_created_agg AS (
  SELECT pr.added_by_id AS hid, COUNT(*) AS projects_created
  FROM public.projects pr
  CROSS JOIN params pa
  WHERE p_include_projects_created
    AND pr.added_by_id IS NOT NULL
    AND (p_handler_id IS NULL OR pr.added_by_id = p_handler_id)
    AND pr.created::date = pr.updated::date
    AND (pa.from_date IS NULL OR pr.created::date >= pa.from_date)
    AND (pa.to_date IS NULL OR pr.created::date <= pa.to_date)
  GROUP BY pr.added_by_id
),
irs_closed_agg AS (
  SELECT ir.ir_handler_id AS hid, COUNT(*) AS irs_closed
  FROM public.informationrequests ir
  CROSS JOIN params pa
  WHERE p_include_irs_closed
    AND ir.ir_handler_id IS NOT NULL
    AND (p_handler_id IS NULL OR ir.ir_handler_id = p_handler_id)
    AND ir.status = 'Completed'
    AND (pa.from_date IS NULL OR ir.closed_on::date >= pa.from_date)
    AND (pa.to_date IS NULL OR ir.closed_on::date <= pa.to_date)
  GROUP BY ir.ir_handler_id
),
keycontacts_agg AS (
  SELECT pkc.created_by_id AS hid, COUNT(*) AS keycontacts_added
  FROM public.projectcompanykeycontacts pkc
  CROSS JOIN params pa
  WHERE p_include_keycontacts_added
    AND pkc.created_by_id IS NOT NULL
    AND (p_handler_id IS NULL OR pkc.created_by_id = p_handler_id)
    AND (pa.from_date IS NULL OR pkc.created_on::date >= pa.from_date)
    AND (pa.to_date IS NULL OR pkc.created_on::date <= pa.to_date)
  GROUP BY pkc.created_by_id
),
contacts_created_agg AS (
  SELECT ct.created_by_id AS hid, COUNT(*) AS contacts_created
  FROM public.contacts ct
  CROSS JOIN params pa
  WHERE p_include_contacts_created
    AND ct.created_by_id IS NOT NULL
    AND (p_handler_id IS NULL OR ct.created_by_id = p_handler_id)
    AND (pa.from_date IS NULL OR ct.created_at::date >= pa.from_date)
    AND (pa.to_date IS NULL OR ct.created_at::date <= pa.to_date)
  GROUP BY ct.created_by_id
),
all_handlers AS (
  SELECT hid FROM projectlog_agg
  UNION
  SELECT hid FROM projects_created_agg
  UNION
  SELECT hid FROM irs_closed_agg
  UNION
  SELECT hid FROM keycontacts_agg
  UNION
  SELECT hid FROM contacts_created_agg
),
handler_names AS (
  SELECT
    ah.hid,
    COALESCE(
      NULLIF(TRIM(CONCAT(c.first_name, ' ', c.last_name)), ''),
      INITCAP(REPLACE(SPLIT_PART(iu.username, '@', 1), '.', ' '))
    ) AS hname
  FROM all_handlers ah
  JOIN public.ibisusers iu ON iu.id = ah.hid
  LEFT JOIN public.contacts c ON c.id = iu.prime_contact_id
)
SELECT
  hn.hid AS handler_id,
  hn.hname AS handler_name,
  COALESCE(pl.projects_approved, 0) AS projects_approved,
  COALESCE(pl.projects_submitted, 0) AS projects_submitted,
  COALESCE(pc.projects_created, 0) AS projects_created,
  COALESCE(pl.projects_reviewed, 0) AS projects_reviewed,
  COALESCE(ir.irs_closed, 0) AS irs_closed,
  COALESCE(kc.keycontacts_added, 0) AS keycontacts_added,
  COALESCE(cc.contacts_created, 0) AS contacts_created
FROM handler_names hn
LEFT JOIN projectlog_agg pl ON pl.hid = hn.hid
LEFT JOIN projects_created_agg pc ON pc.hid = hn.hid
LEFT JOIN irs_closed_agg ir ON ir.hid = hn.hid
LEFT JOIN keycontacts_agg kc ON kc.hid = hn.hid
LEFT JOIN contacts_created_agg cc ON cc.hid = hn.hid
ORDER BY
  (COALESCE(pl.projects_approved,0)
   + COALESCE(pl.projects_submitted,0)
   + COALESCE(pc.projects_created,0)
   + COALESCE(pl.projects_reviewed,0)
   + COALESCE(ir.irs_closed,0)
   + COALESCE(kc.keycontacts_added,0)
   + COALESCE(cc.contacts_created,0)
  ) DESC,
  hn.hname ASC;
$$;


ALTER FUNCTION "public"."get_handler_performance"("p_from_date" "date", "p_to_date" "date", "p_handler_id" integer, "p_include_projects_approved" boolean, "p_include_projects_submitted" boolean, "p_include_projects_created" boolean, "p_include_projects_reviewed" boolean, "p_include_irs_closed" boolean, "p_include_keycontacts_added" boolean, "p_include_contacts_created" boolean) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_ibis_usage_statistics"("p_company_id" integer, "p_from_date" timestamp without time zone, "p_to_date" timestamp without time zone, "p_user_ids" integer[] DEFAULT NULL::integer[], "p_site_ids" integer[] DEFAULT NULL::integer[]) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  result JSONB;
  v_summary JSONB;
  v_timeline JSONB;
  v_monthly JSONB;
  v_user_wise JSONB;
  v_by_stage JSONB;
  v_by_user_projects JSONB;
  v_by_user_companies JSONB;
  v_exported_projects JSONB;
  v_exported_companies JSONB;
  v_device JSONB;
  v_logins_by_user JSONB;
  v_peak_hours JSONB;
  v_content_engagement JSONB;
  v_purchase_intent JSONB;
BEGIN
  -- Summary KPIs
  SELECT jsonb_build_object(
    'total_logins', COUNT(*) FILTER (WHERE log_type = 'Login'),
    'total_searches', COUNT(*) FILTER (WHERE log_type IN ('Project', 'Company')),
    'projects_viewed', COUNT(*) FILTER (WHERE log_type = 'Project Display'),
    'companies_viewed', COUNT(*) FILTER (WHERE log_type = 'Company Display'),
    'total_exports', COUNT(*) FILTER (WHERE log_type IN ('Project Intelligence Export', 'Company Intelligence Export', 'Project Analytics Export', 'Print Project', 'Print Company')),
    'unique_users', COUNT(DISTINCT user_id)
  ) INTO v_summary
  FROM ibisusagelog
  WHERE user_id IN (SELECT id FROM ibisusers WHERE prime_company_id = p_company_id)
    AND log_date >= p_from_date AND log_date <= p_to_date
    AND (p_user_ids IS NULL OR user_id = ANY(p_user_ids))
    AND (p_site_ids IS NULL OR site_id = ANY(p_site_ids));

  -- Activity timeline
  SELECT COALESCE(jsonb_agg(row_to_json(t)::jsonb ORDER BY t.date), '[]'::jsonb) INTO v_timeline
  FROM (
    SELECT DATE(log_date) as date,
      COUNT(*) FILTER (WHERE log_type IN ('Project', 'Company')) as searches,
      COUNT(*) FILTER (WHERE log_type IN ('Project Display', 'Company Display')) as views,
      COUNT(*) FILTER (WHERE log_type IN ('Project Intelligence Export', 'Company Intelligence Export', 'Project Analytics Export', 'Print Project', 'Print Company')) as exports,
      COUNT(*) FILTER (WHERE log_type = 'Login') as logins,
      COUNT(*) as total
    FROM ibisusagelog
    WHERE user_id IN (SELECT id FROM ibisusers WHERE prime_company_id = p_company_id) AND log_date >= p_from_date AND log_date <= p_to_date
      AND (p_user_ids IS NULL OR user_id = ANY(p_user_ids)) AND (p_site_ids IS NULL OR site_id = ANY(p_site_ids))
    GROUP BY DATE(log_date)
  ) t;

  -- Monthly summary
  SELECT COALESCE(jsonb_agg(row_to_json(t)::jsonb), '[]'::jsonb) INTO v_monthly
  FROM (
    SELECT log_type, TO_CHAR(log_date, 'YYYY-MM') as month, COUNT(*) as count
    FROM ibisusagelog
    WHERE user_id IN (SELECT id FROM ibisusers WHERE prime_company_id = p_company_id) AND log_date >= p_from_date AND log_date <= p_to_date
      AND (p_user_ids IS NULL OR user_id = ANY(p_user_ids)) AND (p_site_ids IS NULL OR site_id = ANY(p_site_ids))
    GROUP BY log_type, TO_CHAR(log_date, 'YYYY-MM') ORDER BY log_type, month
  ) t;

  -- User-wise usage
  SELECT COALESCE(jsonb_agg(row_to_json(t)::jsonb ORDER BY t.total_actions DESC), '[]'::jsonb) INTO v_user_wise
  FROM (
    SELECT u.user_id, COALESCE(c.first_name || ' ' || c.last_name, iu.username) as name,
      c.other_designation as designation, iu.package, iu.status, iu.last_login,
      COUNT(*) FILTER (WHERE u.log_type = 'Project') as project_searches,
      COUNT(*) FILTER (WHERE u.log_type = 'Project Display') as projects_viewed,
      COUNT(*) FILTER (WHERE u.log_type = 'Company Display') as companies_viewed,
      COUNT(*) FILTER (WHERE u.log_type = 'Company') as company_searches,
      COUNT(*) FILTER (WHERE u.log_type IN ('Project Intelligence Export', 'Project Analytics Export', 'Print Project')) as project_exports,
      COUNT(*) FILTER (WHERE u.log_type IN ('Company Intelligence Export', 'Print Company')) as company_exports,
      COUNT(*) FILTER (WHERE u.log_type = 'Login') as logins,
      COUNT(*) FILTER (WHERE u.log_type IN ('Login', 'Project', 'Project Display', 'Company', 'Company Display', 'Project Intelligence Export', 'Company Intelligence Export', 'Project Analytics Export', 'Print Project', 'Print Company')) as total_actions
    FROM ibisusagelog u LEFT JOIN ibisusers iu ON iu.id = u.user_id LEFT JOIN contacts c ON c.id = iu.prime_contact_id
    WHERE u.user_id IN (SELECT id FROM ibisusers WHERE prime_company_id = p_company_id) AND u.log_date >= p_from_date AND u.log_date <= p_to_date
      AND (p_user_ids IS NULL OR u.user_id = ANY(p_user_ids)) AND (p_site_ids IS NULL OR u.site_id = ANY(p_site_ids))
    GROUP BY u.user_id, c.first_name, c.last_name, iu.username, c.other_designation, iu.package, iu.status, iu.last_login
  ) t;

  -- Projects by stage
  SELECT COALESCE(jsonb_agg(row_to_json(t)::jsonb ORDER BY t.count DESC), '[]'::jsonb) INTO v_by_stage
  FROM (
    SELECT COALESCE(ps.name, 'Unknown') as name, COUNT(*) as count
    FROM ibisusagelog u LEFT JOIN project_stages ps ON ps.id = u.stage_id
    WHERE u.user_id IN (SELECT id FROM ibisusers WHERE prime_company_id = p_company_id) AND u.log_type = 'Project Display'
      AND u.log_date >= p_from_date AND u.log_date <= p_to_date
      AND (p_user_ids IS NULL OR u.user_id = ANY(p_user_ids)) AND (p_site_ids IS NULL OR u.site_id = ANY(p_site_ids))
    GROUP BY ps.name LIMIT 20
  ) t;

  -- Content engagement
  SELECT COALESCE(jsonb_agg(row_to_json(t)::jsonb ORDER BY t.count DESC), '[]'::jsonb) INTO v_content_engagement
  FROM (
    SELECT
      CASE log_type
        WHEN 'News Display' THEN 'News'
        WHEN 'Journal Display' THEN 'Journals'
        WHEN 'Journal Download' THEN 'Journal Downloads'
        WHEN 'Infographics Display' THEN 'Infographics'
        WHEN 'Infographics Download' THEN 'Infographic Downloads'
        WHEN 'Report Display' THEN 'Reports'
        WHEN 'Report Download' THEN 'Report Downloads'
        WHEN 'Analytic Display' THEN 'Analytics'
        WHEN 'Market Analysis Display' THEN 'Market Analysis'
        ELSE log_type
      END as name,
      COUNT(*) as count
    FROM ibisusagelog
    WHERE user_id IN (SELECT id FROM ibisusers WHERE prime_company_id = p_company_id)
      AND log_type IN ('News Display', 'Journal Display', 'Journal Download', 'Infographics Display', 'Infographics Download', 'Report Display', 'Report Download', 'Analytic Display', 'Market Analysis Display')
      AND log_date >= p_from_date AND log_date <= p_to_date
      AND (p_user_ids IS NULL OR user_id = ANY(p_user_ids)) AND (p_site_ids IS NULL OR site_id = ANY(p_site_ids))
    GROUP BY log_type LIMIT 20
  ) t;

  -- Purchase intent
  SELECT COALESCE(jsonb_agg(row_to_json(t)::jsonb ORDER BY t.count DESC), '[]'::jsonb) INTO v_purchase_intent
  FROM (
    SELECT
      CASE log_type
        WHEN 'Button Click - Buy Project' THEN 'Buy Project Clicks'
        WHEN 'Button Click - Buy Company' THEN 'Buy Company Clicks'
        WHEN 'Button Click - Buy News' THEN 'Buy News Clicks'
        WHEN 'Button Click - Buy Market Analysis' THEN 'Buy Analysis Clicks'
        WHEN 'Project Unlocked' THEN 'Projects Unlocked'
        WHEN 'Analytic Unlocked' THEN 'Analytics Unlocked'
        WHEN 'News Unlocked' THEN 'News Unlocked'
        WHEN 'Market Analysis Unlocked' THEN 'Analysis Unlocked'
        WHEN 'Unaccessible Project' THEN 'Blocked Projects'
        WHEN 'Unaccessible Analytic' THEN 'Blocked Analytics'
        WHEN 'Unaccessible Company' THEN 'Blocked Companies'
        ELSE log_type
      END as name,
      COUNT(*) as count
    FROM ibisusagelog
    WHERE user_id IN (SELECT id FROM ibisusers WHERE prime_company_id = p_company_id)
      AND log_type IN ('Button Click - Buy Project', 'Button Click - Buy Company', 'Button Click - Buy News', 'Button Click - Buy Market Analysis', 'Project Unlocked', 'Analytic Unlocked', 'News Unlocked', 'Market Analysis Unlocked', 'Unaccessible Project', 'Unaccessible Analytic', 'Unaccessible Company')
      AND log_date >= p_from_date AND log_date <= p_to_date
      AND (p_user_ids IS NULL OR user_id = ANY(p_user_ids)) AND (p_site_ids IS NULL OR site_id = ANY(p_site_ids))
    GROUP BY log_type LIMIT 20
  ) t;

  -- Projects viewed by user
  SELECT COALESCE(jsonb_agg(row_to_json(t)::jsonb ORDER BY t.count DESC), '[]'::jsonb) INTO v_by_user_projects
  FROM (
    SELECT COALESCE(c.first_name || ' ' || c.last_name, iu.username, 'User ' || u.user_id::text) as name, COUNT(*) as count
    FROM ibisusagelog u LEFT JOIN ibisusers iu ON iu.id = u.user_id LEFT JOIN contacts c ON c.id = iu.prime_contact_id
    WHERE u.user_id IN (SELECT id FROM ibisusers WHERE prime_company_id = p_company_id) AND u.log_type = 'Project Display'
      AND u.log_date >= p_from_date AND u.log_date <= p_to_date
      AND (p_user_ids IS NULL OR u.user_id = ANY(p_user_ids)) AND (p_site_ids IS NULL OR u.site_id = ANY(p_site_ids))
    GROUP BY c.first_name, c.last_name, iu.username, u.user_id LIMIT 20
  ) t;

  -- Companies viewed by user
  SELECT COALESCE(jsonb_agg(row_to_json(t)::jsonb ORDER BY t.count DESC), '[]'::jsonb) INTO v_by_user_companies
  FROM (
    SELECT COALESCE(c.first_name || ' ' || c.last_name, iu.username, 'User ' || u.user_id::text) as name, COUNT(*) as count
    FROM ibisusagelog u LEFT JOIN ibisusers iu ON iu.id = u.user_id LEFT JOIN contacts c ON c.id = iu.prime_contact_id
    WHERE u.user_id IN (SELECT id FROM ibisusers WHERE prime_company_id = p_company_id) AND u.log_type = 'Company Display'
      AND u.log_date >= p_from_date AND u.log_date <= p_to_date
      AND (p_user_ids IS NULL OR u.user_id = ANY(p_user_ids)) AND (p_site_ids IS NULL OR u.site_id = ANY(p_site_ids))
    GROUP BY c.first_name, c.last_name, iu.username, u.user_id LIMIT 20
  ) t;

  -- Project exports by user
  SELECT COALESCE(jsonb_agg(row_to_json(t)::jsonb ORDER BY t.count DESC), '[]'::jsonb) INTO v_exported_projects
  FROM (
    SELECT COALESCE(c.first_name || ' ' || c.last_name, iu.username, 'User ' || u.user_id::text) as name, COUNT(*) as count
    FROM ibisusagelog u LEFT JOIN ibisusers iu ON iu.id = u.user_id LEFT JOIN contacts c ON c.id = iu.prime_contact_id
    WHERE u.user_id IN (SELECT id FROM ibisusers WHERE prime_company_id = p_company_id) AND u.log_type IN ('Project Intelligence Export', 'Project Analytics Export', 'Print Project')
      AND u.log_date >= p_from_date AND u.log_date <= p_to_date
      AND (p_user_ids IS NULL OR u.user_id = ANY(p_user_ids)) AND (p_site_ids IS NULL OR u.site_id = ANY(p_site_ids))
    GROUP BY c.first_name, c.last_name, iu.username, u.user_id LIMIT 20
  ) t;

  -- Company exports by user
  SELECT COALESCE(jsonb_agg(row_to_json(t)::jsonb ORDER BY t.count DESC), '[]'::jsonb) INTO v_exported_companies
  FROM (
    SELECT COALESCE(c.first_name || ' ' || c.last_name, iu.username, 'User ' || u.user_id::text) as name, COUNT(*) as count
    FROM ibisusagelog u LEFT JOIN ibisusers iu ON iu.id = u.user_id LEFT JOIN contacts c ON c.id = iu.prime_contact_id
    WHERE u.user_id IN (SELECT id FROM ibisusers WHERE prime_company_id = p_company_id) AND u.log_type IN ('Company Intelligence Export', 'Print Company')
      AND u.log_date >= p_from_date AND u.log_date <= p_to_date
      AND (p_user_ids IS NULL OR u.user_id = ANY(p_user_ids)) AND (p_site_ids IS NULL OR u.site_id = ANY(p_site_ids))
    GROUP BY c.first_name, c.last_name, iu.username, u.user_id LIMIT 20
  ) t;

  -- Device usage
  SELECT COALESCE(jsonb_agg(row_to_json(t)::jsonb ORDER BY t.count DESC), '[]'::jsonb) INTO v_device
  FROM (
    SELECT CASE site_id WHEN 6 THEN 'AIR' WHEN 7 THEN 'Mobile' WHEN 8 THEN 'IBIS' ELSE 'Other' END as name, COUNT(*) as count
    FROM ibisusagelog
    WHERE user_id IN (SELECT id FROM ibisusers WHERE prime_company_id = p_company_id) AND log_date >= p_from_date AND log_date <= p_to_date
      AND (p_user_ids IS NULL OR user_id = ANY(p_user_ids)) AND (p_site_ids IS NULL OR site_id = ANY(p_site_ids))
    GROUP BY site_id
  ) t;

  -- Logins by user
  SELECT COALESCE(jsonb_agg(row_to_json(t)::jsonb ORDER BY t.count DESC), '[]'::jsonb) INTO v_logins_by_user
  FROM (
    SELECT COALESCE(c.first_name || ' ' || c.last_name, iu.username, 'User ' || u.user_id::text) as name, COUNT(*) as count
    FROM ibisusagelog u LEFT JOIN ibisusers iu ON iu.id = u.user_id LEFT JOIN contacts c ON c.id = iu.prime_contact_id
    WHERE u.user_id IN (SELECT id FROM ibisusers WHERE prime_company_id = p_company_id) AND u.log_type = 'Login'
      AND u.log_date >= p_from_date AND u.log_date <= p_to_date
      AND (p_user_ids IS NULL OR u.user_id = ANY(p_user_ids)) AND (p_site_ids IS NULL OR u.site_id = ANY(p_site_ids))
    GROUP BY c.first_name, c.last_name, iu.username, u.user_id LIMIT 20
  ) t;

  -- Peak hours
  SELECT COALESCE(jsonb_agg(row_to_json(t)::jsonb ORDER BY t.hour), '[]'::jsonb) INTO v_peak_hours
  FROM (
    SELECT EXTRACT(HOUR FROM log_date)::int as hour, COUNT(*) as count
    FROM ibisusagelog
    WHERE user_id IN (SELECT id FROM ibisusers WHERE prime_company_id = p_company_id) AND log_date >= p_from_date AND log_date <= p_to_date
      AND (p_user_ids IS NULL OR user_id = ANY(p_user_ids)) AND (p_site_ids IS NULL OR site_id = ANY(p_site_ids))
    GROUP BY EXTRACT(HOUR FROM log_date)
  ) t;

  -- Build final result
  result := jsonb_build_object(
    'summary', v_summary, 'activityTimeline', v_timeline, 'monthlySummary', v_monthly,
    'userWiseUsage', v_user_wise, 'projectsByStage', v_by_stage,
    'projectsByUser', v_by_user_projects, 'companiesByUser', v_by_user_companies,
    'projectsExportedByUser', v_exported_projects, 'companiesExportedByUser', v_exported_companies,
    'deviceUsage', v_device, 'loginsByUser', v_logins_by_user, 'peakHours', v_peak_hours,
    'contentEngagement', v_content_engagement, 'purchaseIntent', v_purchase_intent
  );

  RETURN result;
END;
$$;


ALTER FUNCTION "public"."get_ibis_usage_statistics"("p_company_id" integer, "p_from_date" timestamp without time zone, "p_to_date" timestamp without time zone, "p_user_ids" integer[], "p_site_ids" integer[]) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_ibis_usage_statistics"("p_company_id" integer, "p_from_date" timestamp without time zone, "p_to_date" timestamp without time zone, "p_user_id" integer DEFAULT NULL::integer, "p_site_ids" integer[] DEFAULT NULL::integer[]) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  result JSONB;
  v_summary JSONB;
  v_timeline JSONB;
  v_monthly JSONB;
  v_user_wise JSONB;
  v_by_stage JSONB;
  v_by_user_projects JSONB;
  v_by_user_companies JSONB;
  v_exported_projects JSONB;
  v_exported_companies JSONB;
  v_device JSONB;
  v_logins_by_user JSONB;
  v_peak_hours JSONB;
  v_content_engagement JSONB;
  v_purchase_intent JSONB;
BEGIN
  -- Summary KPIs
  SELECT jsonb_build_object(
    'total_logins', COUNT(*) FILTER (WHERE log_type = 'Login'),
    'total_searches', COUNT(*) FILTER (WHERE log_type IN ('Project', 'Company')),
    'projects_viewed', COUNT(*) FILTER (WHERE log_type = 'Project Display'),
    'companies_viewed', COUNT(*) FILTER (WHERE log_type = 'Company Display'),
    'total_exports', COUNT(*) FILTER (WHERE log_type IN ('Project Intelligence Export', 'Company Intelligence Export', 'Project Analytics Export', 'Print Project', 'Print Company')),
    'unique_users', COUNT(DISTINCT user_id)
  ) INTO v_summary
  FROM ibisusagelog
  WHERE user_id IN (SELECT id FROM ibisusers WHERE prime_company_id = p_company_id)
    AND log_date >= p_from_date AND log_date <= p_to_date
    AND (p_user_id IS NULL OR user_id = p_user_id)
    AND (p_site_ids IS NULL OR site_id = ANY(p_site_ids));

  -- Activity timeline
  SELECT COALESCE(jsonb_agg(row_to_json(t)::jsonb ORDER BY t.date), '[]'::jsonb) INTO v_timeline
  FROM (
    SELECT DATE(log_date) as date,
      COUNT(*) FILTER (WHERE log_type IN ('Project', 'Company')) as searches,
      COUNT(*) FILTER (WHERE log_type IN ('Project Display', 'Company Display')) as views,
      COUNT(*) FILTER (WHERE log_type IN ('Project Intelligence Export', 'Company Intelligence Export', 'Project Analytics Export', 'Print Project', 'Print Company')) as exports,
      COUNT(*) FILTER (WHERE log_type = 'Login') as logins,
      COUNT(*) as total
    FROM ibisusagelog
    WHERE user_id IN (SELECT id FROM ibisusers WHERE prime_company_id = p_company_id) AND log_date >= p_from_date AND log_date <= p_to_date
      AND (p_user_id IS NULL OR user_id = p_user_id) AND (p_site_ids IS NULL OR site_id = ANY(p_site_ids))
    GROUP BY DATE(log_date)
  ) t;

  -- Monthly summary
  SELECT COALESCE(jsonb_agg(row_to_json(t)::jsonb), '[]'::jsonb) INTO v_monthly
  FROM (
    SELECT log_type, TO_CHAR(log_date, 'YYYY-MM') as month, COUNT(*) as count
    FROM ibisusagelog
    WHERE user_id IN (SELECT id FROM ibisusers WHERE prime_company_id = p_company_id) AND log_date >= p_from_date AND log_date <= p_to_date
      AND (p_user_id IS NULL OR user_id = p_user_id) AND (p_site_ids IS NULL OR site_id = ANY(p_site_ids))
    GROUP BY log_type, TO_CHAR(log_date, 'YYYY-MM') ORDER BY log_type, month
  ) t;

  -- User-wise usage
  SELECT COALESCE(jsonb_agg(row_to_json(t)::jsonb ORDER BY t.total_actions DESC), '[]'::jsonb) INTO v_user_wise
  FROM (
    SELECT u.user_id, COALESCE(c.first_name || ' ' || c.last_name, iu.username) as name,
      c.other_designation as designation, iu.package, iu.status, iu.last_login,
      COUNT(*) FILTER (WHERE u.log_type = 'Project') as project_searches,
      COUNT(*) FILTER (WHERE u.log_type = 'Project Display') as projects_viewed,
      COUNT(*) FILTER (WHERE u.log_type = 'Company Display') as companies_viewed,
      COUNT(*) FILTER (WHERE u.log_type = 'Company') as company_searches,
      COUNT(*) FILTER (WHERE u.log_type IN ('Project Intelligence Export', 'Project Analytics Export', 'Print Project')) as project_exports,
      COUNT(*) FILTER (WHERE u.log_type IN ('Company Intelligence Export', 'Print Company')) as company_exports,
      COUNT(*) FILTER (WHERE u.log_type = 'Login') as logins,
      COUNT(*) FILTER (WHERE u.log_type IN ('Login', 'Project', 'Project Display', 'Company', 'Company Display', 'Project Intelligence Export', 'Company Intelligence Export', 'Project Analytics Export', 'Print Project', 'Print Company')) as total_actions
    FROM ibisusagelog u LEFT JOIN ibisusers iu ON iu.id = u.user_id LEFT JOIN contacts c ON c.id = iu.prime_contact_id
    WHERE u.user_id IN (SELECT id FROM ibisusers WHERE prime_company_id = p_company_id) AND u.log_date >= p_from_date AND u.log_date <= p_to_date
      AND (p_user_id IS NULL OR u.user_id = p_user_id) AND (p_site_ids IS NULL OR u.site_id = ANY(p_site_ids))
    GROUP BY u.user_id, c.first_name, c.last_name, iu.username, c.other_designation, iu.package, iu.status, iu.last_login
  ) t;

  -- Projects by stage
  SELECT COALESCE(jsonb_agg(row_to_json(t)::jsonb ORDER BY t.count DESC), '[]'::jsonb) INTO v_by_stage
  FROM (
    SELECT COALESCE(ps.name, 'Unknown') as name, COUNT(*) as count
    FROM ibisusagelog u LEFT JOIN project_stages ps ON ps.id = u.stage_id
    WHERE u.user_id IN (SELECT id FROM ibisusers WHERE prime_company_id = p_company_id) AND u.log_type = 'Project Display'
      AND u.log_date >= p_from_date AND u.log_date <= p_to_date
      AND (p_user_id IS NULL OR u.user_id = p_user_id) AND (p_site_ids IS NULL OR u.site_id = ANY(p_site_ids))
    GROUP BY ps.name LIMIT 20
  ) t;

  -- Content engagement
  SELECT COALESCE(jsonb_agg(row_to_json(t)::jsonb ORDER BY t.count DESC), '[]'::jsonb) INTO v_content_engagement
  FROM (
    SELECT
      CASE log_type
        WHEN 'News Display' THEN 'News'
        WHEN 'Journal Display' THEN 'Journals'
        WHEN 'Journal Download' THEN 'Journal Downloads'
        WHEN 'Infographics Display' THEN 'Infographics'
        WHEN 'Infographics Download' THEN 'Infographic Downloads'
        WHEN 'Report Display' THEN 'Reports'
        WHEN 'Report Download' THEN 'Report Downloads'
        WHEN 'Analytic Display' THEN 'Analytics'
        WHEN 'Market Analysis Display' THEN 'Market Analysis'
        ELSE log_type
      END as name,
      COUNT(*) as count
    FROM ibisusagelog
    WHERE user_id IN (SELECT id FROM ibisusers WHERE prime_company_id = p_company_id)
      AND log_type IN ('News Display', 'Journal Display', 'Journal Download', 'Infographics Display', 'Infographics Download', 'Report Display', 'Report Download', 'Analytic Display', 'Market Analysis Display')
      AND log_date >= p_from_date AND log_date <= p_to_date
      AND (p_user_id IS NULL OR user_id = p_user_id) AND (p_site_ids IS NULL OR site_id = ANY(p_site_ids))
    GROUP BY log_type LIMIT 20
  ) t;

  -- Purchase intent
  SELECT COALESCE(jsonb_agg(row_to_json(t)::jsonb ORDER BY t.count DESC), '[]'::jsonb) INTO v_purchase_intent
  FROM (
    SELECT
      CASE log_type
        WHEN 'Button Click - Buy Project' THEN 'Buy Project Clicks'
        WHEN 'Button Click - Buy Company' THEN 'Buy Company Clicks'
        WHEN 'Button Click - Buy News' THEN 'Buy News Clicks'
        WHEN 'Button Click - Buy Market Analysis' THEN 'Buy Analysis Clicks'
        WHEN 'Project Unlocked' THEN 'Projects Unlocked'
        WHEN 'Analytic Unlocked' THEN 'Analytics Unlocked'
        WHEN 'News Unlocked' THEN 'News Unlocked'
        WHEN 'Market Analysis Unlocked' THEN 'Analysis Unlocked'
        WHEN 'Unaccessible Project' THEN 'Blocked Projects'
        WHEN 'Unaccessible Analytic' THEN 'Blocked Analytics'
        WHEN 'Unaccessible Company' THEN 'Blocked Companies'
        ELSE log_type
      END as name,
      COUNT(*) as count
    FROM ibisusagelog
    WHERE user_id IN (SELECT id FROM ibisusers WHERE prime_company_id = p_company_id)
      AND log_type IN ('Button Click - Buy Project', 'Button Click - Buy Company', 'Button Click - Buy News', 'Button Click - Buy Market Analysis', 'Project Unlocked', 'Analytic Unlocked', 'News Unlocked', 'Market Analysis Unlocked', 'Unaccessible Project', 'Unaccessible Analytic', 'Unaccessible Company')
      AND log_date >= p_from_date AND log_date <= p_to_date
      AND (p_user_id IS NULL OR user_id = p_user_id) AND (p_site_ids IS NULL OR site_id = ANY(p_site_ids))
    GROUP BY log_type LIMIT 20
  ) t;

  -- Projects viewed by user
  SELECT COALESCE(jsonb_agg(row_to_json(t)::jsonb ORDER BY t.count DESC), '[]'::jsonb) INTO v_by_user_projects
  FROM (
    SELECT COALESCE(c.first_name || ' ' || c.last_name, iu.username, 'User ' || u.user_id::text) as name, COUNT(*) as count
    FROM ibisusagelog u LEFT JOIN ibisusers iu ON iu.id = u.user_id LEFT JOIN contacts c ON c.id = iu.prime_contact_id
    WHERE u.user_id IN (SELECT id FROM ibisusers WHERE prime_company_id = p_company_id) AND u.log_type = 'Project Display'
      AND u.log_date >= p_from_date AND u.log_date <= p_to_date
      AND (p_user_id IS NULL OR u.user_id = p_user_id) AND (p_site_ids IS NULL OR u.site_id = ANY(p_site_ids))
    GROUP BY c.first_name, c.last_name, iu.username, u.user_id LIMIT 20
  ) t;

  -- Companies viewed by user
  SELECT COALESCE(jsonb_agg(row_to_json(t)::jsonb ORDER BY t.count DESC), '[]'::jsonb) INTO v_by_user_companies
  FROM (
    SELECT COALESCE(c.first_name || ' ' || c.last_name, iu.username, 'User ' || u.user_id::text) as name, COUNT(*) as count
    FROM ibisusagelog u LEFT JOIN ibisusers iu ON iu.id = u.user_id LEFT JOIN contacts c ON c.id = iu.prime_contact_id
    WHERE u.user_id IN (SELECT id FROM ibisusers WHERE prime_company_id = p_company_id) AND u.log_type = 'Company Display'
      AND u.log_date >= p_from_date AND u.log_date <= p_to_date
      AND (p_user_id IS NULL OR u.user_id = p_user_id) AND (p_site_ids IS NULL OR u.site_id = ANY(p_site_ids))
    GROUP BY c.first_name, c.last_name, iu.username, u.user_id LIMIT 20
  ) t;

  -- Project exports by user
  SELECT COALESCE(jsonb_agg(row_to_json(t)::jsonb ORDER BY t.count DESC), '[]'::jsonb) INTO v_exported_projects
  FROM (
    SELECT COALESCE(c.first_name || ' ' || c.last_name, iu.username, 'User ' || u.user_id::text) as name, COUNT(*) as count
    FROM ibisusagelog u LEFT JOIN ibisusers iu ON iu.id = u.user_id LEFT JOIN contacts c ON c.id = iu.prime_contact_id
    WHERE u.user_id IN (SELECT id FROM ibisusers WHERE prime_company_id = p_company_id) AND u.log_type IN ('Project Intelligence Export', 'Project Analytics Export', 'Print Project')
      AND u.log_date >= p_from_date AND u.log_date <= p_to_date
      AND (p_user_id IS NULL OR u.user_id = p_user_id) AND (p_site_ids IS NULL OR u.site_id = ANY(p_site_ids))
    GROUP BY c.first_name, c.last_name, iu.username, u.user_id LIMIT 20
  ) t;

  -- Company exports by user
  SELECT COALESCE(jsonb_agg(row_to_json(t)::jsonb ORDER BY t.count DESC), '[]'::jsonb) INTO v_exported_companies
  FROM (
    SELECT COALESCE(c.first_name || ' ' || c.last_name, iu.username, 'User ' || u.user_id::text) as name, COUNT(*) as count
    FROM ibisusagelog u LEFT JOIN ibisusers iu ON iu.id = u.user_id LEFT JOIN contacts c ON c.id = iu.prime_contact_id
    WHERE u.user_id IN (SELECT id FROM ibisusers WHERE prime_company_id = p_company_id) AND u.log_type IN ('Company Intelligence Export', 'Print Company')
      AND u.log_date >= p_from_date AND u.log_date <= p_to_date
      AND (p_user_id IS NULL OR u.user_id = p_user_id) AND (p_site_ids IS NULL OR u.site_id = ANY(p_site_ids))
    GROUP BY c.first_name, c.last_name, iu.username, u.user_id LIMIT 20
  ) t;

  -- Platform usage (updated labels: IBIS = current, AIR = legacy, BNC App = mobile)
  SELECT COALESCE(jsonb_agg(row_to_json(t)::jsonb ORDER BY t.count DESC), '[]'::jsonb) INTO v_device
  FROM (
    SELECT CASE site_id WHEN 6 THEN 'AIR (Legacy)' WHEN 7 THEN 'BNC App' WHEN 8 THEN 'IBIS' ELSE 'Other' END as name, COUNT(*) as count
    FROM ibisusagelog
    WHERE user_id IN (SELECT id FROM ibisusers WHERE prime_company_id = p_company_id) AND log_date >= p_from_date AND log_date <= p_to_date
      AND (p_user_id IS NULL OR user_id = p_user_id) AND (p_site_ids IS NULL OR site_id = ANY(p_site_ids))
    GROUP BY site_id
  ) t;

  -- Logins by user
  SELECT COALESCE(jsonb_agg(row_to_json(t)::jsonb ORDER BY t.count DESC), '[]'::jsonb) INTO v_logins_by_user
  FROM (
    SELECT COALESCE(c.first_name || ' ' || c.last_name, iu.username, 'User ' || u.user_id::text) as name, COUNT(*) as count
    FROM ibisusagelog u LEFT JOIN ibisusers iu ON iu.id = u.user_id LEFT JOIN contacts c ON c.id = iu.prime_contact_id
    WHERE u.user_id IN (SELECT id FROM ibisusers WHERE prime_company_id = p_company_id) AND u.log_type = 'Login'
      AND u.log_date >= p_from_date AND u.log_date <= p_to_date
      AND (p_user_id IS NULL OR u.user_id = p_user_id) AND (p_site_ids IS NULL OR u.site_id = ANY(p_site_ids))
    GROUP BY c.first_name, c.last_name, iu.username, u.user_id LIMIT 20
  ) t;

  -- Peak hours
  SELECT COALESCE(jsonb_agg(row_to_json(t)::jsonb ORDER BY t.hour), '[]'::jsonb) INTO v_peak_hours
  FROM (
    SELECT EXTRACT(HOUR FROM log_date)::int as hour, COUNT(*) as count
    FROM ibisusagelog
    WHERE user_id IN (SELECT id FROM ibisusers WHERE prime_company_id = p_company_id) AND log_date >= p_from_date AND log_date <= p_to_date
      AND (p_user_id IS NULL OR user_id = p_user_id) AND (p_site_ids IS NULL OR site_id = ANY(p_site_ids))
    GROUP BY EXTRACT(HOUR FROM log_date)
  ) t;

  -- Build final result
  result := jsonb_build_object(
    'summary', v_summary, 'activityTimeline', v_timeline, 'monthlySummary', v_monthly,
    'userWiseUsage', v_user_wise, 'projectsByStage', v_by_stage,
    'projectsByUser', v_by_user_projects, 'companiesByUser', v_by_user_companies,
    'projectsExportedByUser', v_exported_projects, 'companiesExportedByUser', v_exported_companies,
    'deviceUsage', v_device, 'loginsByUser', v_logins_by_user, 'peakHours', v_peak_hours,
    'contentEngagement', v_content_engagement, 'purchaseIntent', v_purchase_intent
  );

  RETURN result;
END;
$$;


ALTER FUNCTION "public"."get_ibis_usage_statistics"("p_company_id" integer, "p_from_date" timestamp without time zone, "p_to_date" timestamp without time zone, "p_user_id" integer, "p_site_ids" integer[]) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_ibis_usage_statistics"("p_company_id" integer, "p_from_date" timestamp without time zone, "p_to_date" timestamp without time zone, "p_user_id" integer DEFAULT NULL::integer, "p_site_ids" integer[] DEFAULT NULL::integer[], "p_user_ids" integer[] DEFAULT NULL::integer[]) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  result JSONB;
  v_summary JSONB;
  v_timeline JSONB;
  v_monthly JSONB;
  v_user_wise JSONB;
  v_by_stage JSONB;
  v_by_user_projects JSONB;
  v_by_user_companies JSONB;
  v_exported_projects JSONB;
  v_exported_companies JSONB;
  v_device JSONB;
  v_logins_by_user JSONB;
  v_peak_hours JSONB;
  v_content_engagement JSONB;
  v_purchase_intent JSONB;
BEGIN
  -- Summary KPIs
  SELECT jsonb_build_object(
    'total_logins', COUNT(*) FILTER (WHERE log_type = 'Login'),
    'total_searches', COUNT(*) FILTER (WHERE log_type IN ('Project', 'Company')),
    'projects_viewed', COUNT(*) FILTER (WHERE log_type = 'Project Display'),
    'companies_viewed', COUNT(*) FILTER (WHERE log_type = 'Company Display'),
    'total_exports', COUNT(*) FILTER (WHERE log_type IN ('Project Intelligence Export', 'Company Intelligence Export', 'Project Analytics Export', 'Print Project', 'Print Company')),
    'unique_users', COUNT(DISTINCT user_id)
  ) INTO v_summary
  FROM ibisusagelog
  WHERE user_id IN (SELECT id FROM ibisusers WHERE prime_company_id = p_company_id)
    AND log_date >= p_from_date AND log_date <= p_to_date
    AND (p_user_id IS NULL OR user_id = p_user_id)
    AND (p_user_ids IS NULL OR user_id = ANY(p_user_ids))
    AND (p_site_ids IS NULL OR site_id = ANY(p_site_ids));

  -- Activity timeline
  SELECT COALESCE(jsonb_agg(row_to_json(t)::jsonb ORDER BY t.date), '[]'::jsonb) INTO v_timeline
  FROM (
    SELECT DATE(log_date) as date,
      COUNT(*) FILTER (WHERE log_type IN ('Project', 'Company')) as searches,
      COUNT(*) FILTER (WHERE log_type IN ('Project Display', 'Company Display')) as views,
      COUNT(*) FILTER (WHERE log_type IN ('Project Intelligence Export', 'Company Intelligence Export', 'Project Analytics Export', 'Print Project', 'Print Company')) as exports,
      COUNT(*) FILTER (WHERE log_type = 'Login') as logins,
      COUNT(*) as total
    FROM ibisusagelog
    WHERE user_id IN (SELECT id FROM ibisusers WHERE prime_company_id = p_company_id) AND log_date >= p_from_date AND log_date <= p_to_date
      AND (p_user_id IS NULL OR user_id = p_user_id) AND (p_user_ids IS NULL OR user_id = ANY(p_user_ids)) AND (p_site_ids IS NULL OR site_id = ANY(p_site_ids))
    GROUP BY DATE(log_date)
  ) t;

  -- Monthly summary
  SELECT COALESCE(jsonb_agg(row_to_json(t)::jsonb), '[]'::jsonb) INTO v_monthly
  FROM (
    SELECT log_type, TO_CHAR(log_date, 'YYYY-MM') as month, COUNT(*) as count
    FROM ibisusagelog
    WHERE user_id IN (SELECT id FROM ibisusers WHERE prime_company_id = p_company_id) AND log_date >= p_from_date AND log_date <= p_to_date
      AND (p_user_id IS NULL OR user_id = p_user_id) AND (p_user_ids IS NULL OR user_id = ANY(p_user_ids)) AND (p_site_ids IS NULL OR site_id = ANY(p_site_ids))
    GROUP BY log_type, TO_CHAR(log_date, 'YYYY-MM') ORDER BY log_type, month
  ) t;

  -- User-wise usage
  SELECT COALESCE(jsonb_agg(row_to_json(t)::jsonb ORDER BY t.total_actions DESC), '[]'::jsonb) INTO v_user_wise
  FROM (
    SELECT u.user_id, COALESCE(c.first_name || ' ' || c.last_name, iu.username) as name,
      c.other_designation as designation, iu.package, iu.status, iu.last_login,
      COUNT(*) FILTER (WHERE u.log_type = 'Project') as project_searches,
      COUNT(*) FILTER (WHERE u.log_type = 'Project Display') as projects_viewed,
      COUNT(*) FILTER (WHERE u.log_type = 'Company Display') as companies_viewed,
      COUNT(*) FILTER (WHERE u.log_type = 'Company') as company_searches,
      COUNT(*) FILTER (WHERE u.log_type IN ('Project Intelligence Export', 'Project Analytics Export', 'Print Project')) as project_exports,
      COUNT(*) FILTER (WHERE u.log_type IN ('Company Intelligence Export', 'Print Company')) as company_exports,
      COUNT(*) FILTER (WHERE u.log_type = 'Login') as logins,
      COUNT(*) FILTER (WHERE u.log_type IN ('Login', 'Project', 'Project Display', 'Company', 'Company Display', 'Project Intelligence Export', 'Company Intelligence Export', 'Project Analytics Export', 'Print Project', 'Print Company')) as total_actions
    FROM ibisusagelog u LEFT JOIN ibisusers iu ON iu.id = u.user_id LEFT JOIN contacts c ON c.id = iu.prime_contact_id
    WHERE u.user_id IN (SELECT id FROM ibisusers WHERE prime_company_id = p_company_id) AND u.log_date >= p_from_date AND u.log_date <= p_to_date
      AND (p_user_id IS NULL OR u.user_id = p_user_id) AND (p_user_ids IS NULL OR u.user_id = ANY(p_user_ids)) AND (p_site_ids IS NULL OR u.site_id = ANY(p_site_ids))
    GROUP BY u.user_id, c.first_name, c.last_name, iu.username, c.other_designation, iu.package, iu.status, iu.last_login
  ) t;

  -- Projects by stage
  SELECT COALESCE(jsonb_agg(row_to_json(t)::jsonb ORDER BY t.count DESC), '[]'::jsonb) INTO v_by_stage
  FROM (
    SELECT COALESCE(ps.name, 'Unknown') as name, COUNT(*) as count
    FROM ibisusagelog u LEFT JOIN project_stages ps ON ps.id = u.stage_id
    WHERE u.user_id IN (SELECT id FROM ibisusers WHERE prime_company_id = p_company_id) AND u.log_type = 'Project Display'
      AND u.log_date >= p_from_date AND u.log_date <= p_to_date
      AND (p_user_id IS NULL OR u.user_id = p_user_id) AND (p_user_ids IS NULL OR u.user_id = ANY(p_user_ids)) AND (p_site_ids IS NULL OR u.site_id = ANY(p_site_ids))
    GROUP BY ps.name LIMIT 20
  ) t;

  -- Content engagement
  SELECT COALESCE(jsonb_agg(row_to_json(t)::jsonb ORDER BY t.count DESC), '[]'::jsonb) INTO v_content_engagement
  FROM (
    SELECT
      CASE log_type
        WHEN 'News Display' THEN 'News'
        WHEN 'Journal Display' THEN 'Journals'
        WHEN 'Journal Download' THEN 'Journal Downloads'
        WHEN 'Infographics Display' THEN 'Infographics'
        WHEN 'Infographics Download' THEN 'Infographic Downloads'
        WHEN 'Report Display' THEN 'Reports'
        WHEN 'Report Download' THEN 'Report Downloads'
        WHEN 'Analytic Display' THEN 'Analytics'
        WHEN 'Market Analysis Display' THEN 'Market Analysis'
        ELSE log_type
      END as name,
      COUNT(*) as count
    FROM ibisusagelog
    WHERE user_id IN (SELECT id FROM ibisusers WHERE prime_company_id = p_company_id)
      AND log_type IN ('News Display', 'Journal Display', 'Journal Download', 'Infographics Display', 'Infographics Download', 'Report Display', 'Report Download', 'Analytic Display', 'Market Analysis Display')
      AND log_date >= p_from_date AND log_date <= p_to_date
      AND (p_user_id IS NULL OR user_id = p_user_id) AND (p_user_ids IS NULL OR user_id = ANY(p_user_ids)) AND (p_site_ids IS NULL OR site_id = ANY(p_site_ids))
    GROUP BY log_type LIMIT 20
  ) t;

  -- Purchase intent
  SELECT COALESCE(jsonb_agg(row_to_json(t)::jsonb ORDER BY t.count DESC), '[]'::jsonb) INTO v_purchase_intent
  FROM (
    SELECT
      CASE log_type
        WHEN 'Button Click - Buy Project' THEN 'Buy Project Clicks'
        WHEN 'Button Click - Buy Company' THEN 'Buy Company Clicks'
        WHEN 'Button Click - Buy News' THEN 'Buy News Clicks'
        WHEN 'Button Click - Buy Market Analysis' THEN 'Buy Analysis Clicks'
        WHEN 'Project Unlocked' THEN 'Projects Unlocked'
        WHEN 'Analytic Unlocked' THEN 'Analytics Unlocked'
        WHEN 'News Unlocked' THEN 'News Unlocked'
        WHEN 'Market Analysis Unlocked' THEN 'Analysis Unlocked'
        WHEN 'Unaccessible Project' THEN 'Blocked Projects'
        WHEN 'Unaccessible Analytic' THEN 'Blocked Analytics'
        WHEN 'Unaccessible Company' THEN 'Blocked Companies'
        ELSE log_type
      END as name,
      COUNT(*) as count
    FROM ibisusagelog
    WHERE user_id IN (SELECT id FROM ibisusers WHERE prime_company_id = p_company_id)
      AND log_type IN ('Button Click - Buy Project', 'Button Click - Buy Company', 'Button Click - Buy News', 'Button Click - Buy Market Analysis', 'Project Unlocked', 'Analytic Unlocked', 'News Unlocked', 'Market Analysis Unlocked', 'Unaccessible Project', 'Unaccessible Analytic', 'Unaccessible Company')
      AND log_date >= p_from_date AND log_date <= p_to_date
      AND (p_user_id IS NULL OR user_id = p_user_id) AND (p_user_ids IS NULL OR user_id = ANY(p_user_ids)) AND (p_site_ids IS NULL OR site_id = ANY(p_site_ids))
    GROUP BY log_type LIMIT 20
  ) t;

  -- Projects viewed by user
  SELECT COALESCE(jsonb_agg(row_to_json(t)::jsonb ORDER BY t.count DESC), '[]'::jsonb) INTO v_by_user_projects
  FROM (
    SELECT COALESCE(c.first_name || ' ' || c.last_name, iu.username, 'User ' || u.user_id::text) as name, COUNT(*) as count
    FROM ibisusagelog u LEFT JOIN ibisusers iu ON iu.id = u.user_id LEFT JOIN contacts c ON c.id = iu.prime_contact_id
    WHERE u.user_id IN (SELECT id FROM ibisusers WHERE prime_company_id = p_company_id) AND u.log_type = 'Project Display'
      AND u.log_date >= p_from_date AND u.log_date <= p_to_date
      AND (p_user_id IS NULL OR u.user_id = p_user_id) AND (p_user_ids IS NULL OR u.user_id = ANY(p_user_ids)) AND (p_site_ids IS NULL OR u.site_id = ANY(p_site_ids))
    GROUP BY c.first_name, c.last_name, iu.username, u.user_id LIMIT 20
  ) t;

  -- Companies viewed by user
  SELECT COALESCE(jsonb_agg(row_to_json(t)::jsonb ORDER BY t.count DESC), '[]'::jsonb) INTO v_by_user_companies
  FROM (
    SELECT COALESCE(c.first_name || ' ' || c.last_name, iu.username, 'User ' || u.user_id::text) as name, COUNT(*) as count
    FROM ibisusagelog u LEFT JOIN ibisusers iu ON iu.id = u.user_id LEFT JOIN contacts c ON c.id = iu.prime_contact_id
    WHERE u.user_id IN (SELECT id FROM ibisusers WHERE prime_company_id = p_company_id) AND u.log_type = 'Company Display'
      AND u.log_date >= p_from_date AND u.log_date <= p_to_date
      AND (p_user_id IS NULL OR u.user_id = p_user_id) AND (p_user_ids IS NULL OR u.user_id = ANY(p_user_ids)) AND (p_site_ids IS NULL OR u.site_id = ANY(p_site_ids))
    GROUP BY c.first_name, c.last_name, iu.username, u.user_id LIMIT 20
  ) t;

  -- Project exports by user
  SELECT COALESCE(jsonb_agg(row_to_json(t)::jsonb ORDER BY t.count DESC), '[]'::jsonb) INTO v_exported_projects
  FROM (
    SELECT COALESCE(c.first_name || ' ' || c.last_name, iu.username, 'User ' || u.user_id::text) as name, COUNT(*) as count
    FROM ibisusagelog u LEFT JOIN ibisusers iu ON iu.id = u.user_id LEFT JOIN contacts c ON c.id = iu.prime_contact_id
    WHERE u.user_id IN (SELECT id FROM ibisusers WHERE prime_company_id = p_company_id) AND u.log_type IN ('Project Intelligence Export', 'Project Analytics Export', 'Print Project')
      AND u.log_date >= p_from_date AND u.log_date <= p_to_date
      AND (p_user_id IS NULL OR u.user_id = p_user_id) AND (p_user_ids IS NULL OR u.user_id = ANY(p_user_ids)) AND (p_site_ids IS NULL OR u.site_id = ANY(p_site_ids))
    GROUP BY c.first_name, c.last_name, iu.username, u.user_id LIMIT 20
  ) t;

  -- Company exports by user
  SELECT COALESCE(jsonb_agg(row_to_json(t)::jsonb ORDER BY t.count DESC), '[]'::jsonb) INTO v_exported_companies
  FROM (
    SELECT COALESCE(c.first_name || ' ' || c.last_name, iu.username, 'User ' || u.user_id::text) as name, COUNT(*) as count
    FROM ibisusagelog u LEFT JOIN ibisusers iu ON iu.id = u.user_id LEFT JOIN contacts c ON c.id = iu.prime_contact_id
    WHERE u.user_id IN (SELECT id FROM ibisusers WHERE prime_company_id = p_company_id) AND u.log_type IN ('Company Intelligence Export', 'Print Company')
      AND u.log_date >= p_from_date AND u.log_date <= p_to_date
      AND (p_user_id IS NULL OR u.user_id = p_user_id) AND (p_user_ids IS NULL OR u.user_id = ANY(p_user_ids)) AND (p_site_ids IS NULL OR u.site_id = ANY(p_site_ids))
    GROUP BY c.first_name, c.last_name, iu.username, u.user_id LIMIT 20
  ) t;

  -- Platform usage
  SELECT COALESCE(jsonb_agg(row_to_json(t)::jsonb ORDER BY t.count DESC), '[]'::jsonb) INTO v_device
  FROM (
    SELECT CASE site_id WHEN 6 THEN 'AIR (Legacy)' WHEN 7 THEN 'BNC App' WHEN 8 THEN 'IBIS' ELSE 'Other' END as name, COUNT(*) as count
    FROM ibisusagelog
    WHERE user_id IN (SELECT id FROM ibisusers WHERE prime_company_id = p_company_id) AND log_date >= p_from_date AND log_date <= p_to_date
      AND (p_user_id IS NULL OR user_id = p_user_id) AND (p_user_ids IS NULL OR user_id = ANY(p_user_ids)) AND (p_site_ids IS NULL OR site_id = ANY(p_site_ids))
    GROUP BY site_id
  ) t;

  -- Logins by user
  SELECT COALESCE(jsonb_agg(row_to_json(t)::jsonb ORDER BY t.count DESC), '[]'::jsonb) INTO v_logins_by_user
  FROM (
    SELECT COALESCE(c.first_name || ' ' || c.last_name, iu.username, 'User ' || u.user_id::text) as name, COUNT(*) as count
    FROM ibisusagelog u LEFT JOIN ibisusers iu ON iu.id = u.user_id LEFT JOIN contacts c ON c.id = iu.prime_contact_id
    WHERE u.user_id IN (SELECT id FROM ibisusers WHERE prime_company_id = p_company_id) AND u.log_type = 'Login'
      AND u.log_date >= p_from_date AND u.log_date <= p_to_date
      AND (p_user_id IS NULL OR u.user_id = p_user_id) AND (p_user_ids IS NULL OR u.user_id = ANY(p_user_ids)) AND (p_site_ids IS NULL OR u.site_id = ANY(p_site_ids))
    GROUP BY c.first_name, c.last_name, iu.username, u.user_id LIMIT 20
  ) t;

  -- Peak hours
  SELECT COALESCE(jsonb_agg(row_to_json(t)::jsonb ORDER BY t.hour), '[]'::jsonb) INTO v_peak_hours
  FROM (
    SELECT EXTRACT(HOUR FROM log_date)::int as hour, COUNT(*) as count
    FROM ibisusagelog
    WHERE user_id IN (SELECT id FROM ibisusers WHERE prime_company_id = p_company_id) AND log_date >= p_from_date AND log_date <= p_to_date
      AND (p_user_id IS NULL OR user_id = p_user_id) AND (p_user_ids IS NULL OR user_id = ANY(p_user_ids)) AND (p_site_ids IS NULL OR site_id = ANY(p_site_ids))
    GROUP BY EXTRACT(HOUR FROM log_date)
  ) t;

  -- Build final result
  result := jsonb_build_object(
    'summary', v_summary, 'activityTimeline', v_timeline, 'monthlySummary', v_monthly,
    'userWiseUsage', v_user_wise, 'projectsByStage', v_by_stage,
    'projectsByUser', v_by_user_projects, 'companiesByUser', v_by_user_companies,
    'projectsExportedByUser', v_exported_projects, 'companiesExportedByUser', v_exported_companies,
    'deviceUsage', v_device, 'loginsByUser', v_logins_by_user, 'peakHours', v_peak_hours,
    'contentEngagement', v_content_engagement, 'purchaseIntent', v_purchase_intent
  );

  RETURN result;
END;
$$;


