CREATE OR REPLACE FUNCTION "public"."get_job_run_count"("p_job_id" bigint DEFAULT NULL::bigint, "p_status" "text" DEFAULT NULL::"text", "p_date_from" timestamp with time zone DEFAULT NULL::timestamp with time zone, "p_date_to" timestamp with time zone DEFAULT NULL::timestamp with time zone) RETURNS bigint
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'cron'
    AS $$
DECLARE
  v_count bigint;
BEGIN
  SELECT COUNT(*)
  INTO v_count
  FROM cron.job_run_details r
  WHERE (p_job_id IS NULL OR r.jobid = p_job_id)
    AND (p_status IS NULL OR r.status = p_status)
    AND (p_date_from IS NULL OR r.start_time >= p_date_from)
    AND (p_date_to IS NULL OR r.start_time <= p_date_to);
  
  RETURN v_count;
END;
$$;


ALTER FUNCTION "public"."get_job_run_count"("p_job_id" bigint, "p_status" "text", "p_date_from" timestamp with time zone, "p_date_to" timestamp with time zone) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_job_run_history"("p_job_id" bigint DEFAULT NULL::bigint, "p_status" "text" DEFAULT NULL::"text", "p_limit" integer DEFAULT 100, "p_offset" integer DEFAULT 0, "p_date_from" timestamp with time zone DEFAULT NULL::timestamp with time zone, "p_date_to" timestamp with time zone DEFAULT NULL::timestamp with time zone) RETURNS TABLE("jobid" bigint, "runid" bigint, "job_pid" integer, "database" "text", "username" "text", "command" "text", "status" "text", "return_message" "text", "start_time" timestamp with time zone, "end_time" timestamp with time zone)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'cron'
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    r.jobid,
    r.runid,
    r.job_pid,
    r.database,
    r.username,
    r.command,
    r.status,
    r.return_message,
    r.start_time,
    r.end_time
  FROM cron.job_run_details r
  WHERE (p_job_id IS NULL OR r.jobid = p_job_id)
    AND (p_status IS NULL OR r.status = p_status)
    AND (p_date_from IS NULL OR r.start_time >= p_date_from)
    AND (p_date_to IS NULL OR r.start_time <= p_date_to)
  ORDER BY r.start_time DESC
  LIMIT p_limit
  OFFSET p_offset;
END;
$$;


ALTER FUNCTION "public"."get_job_run_history"("p_job_id" bigint, "p_status" "text", "p_limit" integer, "p_offset" integer, "p_date_from" timestamp with time zone, "p_date_to" timestamp with time zone) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_job_stats"() RETURNS TABLE("jobid" bigint, "jobname" "text", "schedule" "text", "active" boolean, "success_count" bigint, "failure_count" bigint, "total_runs" bigint, "last_run_at" timestamp with time zone, "avg_duration_ms" integer)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'cron'
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    j.jobid,
    j.jobname,
    j.schedule,
    j.active,
    COUNT(CASE WHEN r.status = 'succeeded' THEN 1 END) as success_count,
    COUNT(CASE WHEN r.status = 'failed' THEN 1 END) as failure_count,
    COUNT(r.runid) as total_runs,
    MAX(r.start_time) as last_run_at,
    AVG(EXTRACT(EPOCH FROM (r.end_time - r.start_time)) * 1000)::int as avg_duration_ms
  FROM cron.job j
  LEFT JOIN cron.job_run_details r ON j.jobid = r.jobid
  GROUP BY j.jobid, j.jobname, j.schedule, j.active
  ORDER BY j.jobname;
END;
$$;


ALTER FUNCTION "public"."get_job_stats"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_max_receipt_sequence"("year_prefix" "text") RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $_$
DECLARE
  max_seq integer;
BEGIN
  SELECT MAX(CAST(SPLIT_PART(receipt_no, '-', 2) AS INTEGER))
  INTO max_seq
  FROM receipts
  WHERE receipt_no LIKE year_prefix || '-%'
    AND SPLIT_PART(receipt_no, '-', 2) ~ '^\d+$';
  
  RETURN COALESCE(max_seq, 0);
END;
$_$;


ALTER FUNCTION "public"."get_max_receipt_sequence"("year_prefix" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_recipient_list_stats"("p_campaign_dataset_id" integer) RETURNS "jsonb"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
DECLARE
    stats JSONB;
    recipient_count INTEGER := 0;
    last_generated TIMESTAMP WITH TIME ZONE;
BEGIN
    -- Get recipient count and last generation time
    SELECT 
        COUNT(rlm.contact_id),
        MAX(rlm.generated_at)
    INTO recipient_count, last_generated
    FROM recipient_list_members rlm
    JOIN recipient_lists rl ON rl.id = rlm.recipient_list_id
    WHERE rl.campaign_dataset_id = p_campaign_dataset_id;
    
    stats := jsonb_build_object(
        'recipient_count', COALESCE(recipient_count, 0),
        'last_generated', last_generated
    );
    
    RETURN stats;
END;
$$;


ALTER FUNCTION "public"."get_recipient_list_stats"("p_campaign_dataset_id" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_recipient_preview_stats"("p_campaign_dataset_id" integer) RETURNS TABLE("total_contacts" integer, "valid_emails" integer, "excluded_contacts" integer, "generated_at" "text")
    LANGUAGE "plpgsql"
    AS $$
DECLARE
  v_total integer;
  v_valid integer;
  v_has_direct_contacts boolean;
  dataset_criteria jsonb;
  v_where_clause text;
  v_has_ibis_filters boolean;
  v_has_sfs boolean;
  v_join_clause text;
BEGIN
  SELECT EXISTS(
    SELECT 1 FROM public.campaign_dataset_contacts
    WHERE campaign_dataset_id = p_campaign_dataset_id
    LIMIT 1
  ) INTO v_has_direct_contacts;

  IF v_has_direct_contacts THEN
    SELECT COUNT(DISTINCT c.id)::integer
    INTO v_total
    FROM public.campaign_dataset_contacts cdc
    JOIN public.contacts c ON c.id = cdc.contact_id
    WHERE cdc.campaign_dataset_id = p_campaign_dataset_id
      AND c.email1 IS NOT NULL
      AND c.email1 <> ''
      AND COALESCE(c.status, 'Active') = 'Active';
  ELSE
    SELECT cd.criteria INTO dataset_criteria
    FROM public.campaign_datasets cd
    WHERE cd.id = p_campaign_dataset_id;

    IF dataset_criteria IS NULL THEN
      dataset_criteria := '{}'::jsonb;
    END IF;

    v_where_clause := public.build_criteria_where_clause(dataset_criteria);
    v_has_ibis_filters := public.has_ibis_filters(dataset_criteria);
    v_has_sfs := public.has_sfs_filters(dataset_criteria);

    v_join_clause := 'LEFT JOIN public.companies comp ON c.company_id = comp.id';
    IF v_has_ibis_filters THEN
      v_join_clause := v_join_clause || ' LEFT JOIN public.ibisusers iu ON c.id = iu.prime_contact_id';
    END IF;
    IF v_has_sfs THEN
      v_join_clause := v_join_clause || ' JOIN public.company_sfs csfs ON csfs.companyid = comp.id';
    END IF;

    EXECUTE format(
      'SELECT COUNT(DISTINCT c.id)::integer
       FROM public.contacts c %s
       WHERE c.email1 IS NOT NULL
         AND c.email1 <> ''''
         AND COALESCE(c.status, ''Active'') = ''Active''
         AND (%s)',
      v_join_clause, v_where_clause
    ) INTO v_total;
  END IF;

  v_valid := v_total;

  RETURN QUERY SELECT
    v_total as total_contacts,
    v_valid as valid_emails,
    0 as excluded_contacts,
    NOW()::text as generated_at;
END;
$$;


ALTER FUNCTION "public"."get_recipient_preview_stats"("p_campaign_dataset_id" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_sector_kpi_matrix"("p_countries" "text"[] DEFAULT NULL::"text"[], "p_stage_ids" integer[] DEFAULT NULL::integer[], "p_min_value" numeric DEFAULT NULL::numeric, "p_max_value" numeric DEFAULT NULL::numeric, "p_exclude_master_projects" boolean DEFAULT false, "p_exclude_signpost_ids" integer[] DEFAULT NULL::integer[], "p_include_companies" boolean DEFAULT true, "p_include_cud" boolean DEFAULT true, "p_include_dnt" boolean DEFAULT true, "p_include_keycontacts" boolean DEFAULT true) RETURNS TABLE("sector" "text", "country" "text", "project_count" bigint, "company_availability" numeric, "cud_percent" numeric, "dnt_percent" numeric, "contacts_percent" numeric)
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
BEGIN
  RETURN QUERY
  WITH country_filter AS (
    SELECT co.id AS country_id, co.country AS country_name, co.zone_id
    FROM countries co
    WHERE p_countries IS NULL OR co.country = ANY(p_countries)
  ),
  project_base AS (
    SELECT 
      p.id AS project_id,
      p.sector_id,
      p.project_stage_id,
      p.value,
      cf.country_name,
      cf.zone_id,
      p.new_project_type_id,
      p.new_subtype_id,
      CASE 
        WHEN p.value > 20000000 THEN 'Above 20 M'
        WHEN p.value > 0 AND p.value < 20000000 THEN 'Below 20 M'
        ELSE 'All'
      END AS value_range
    FROM projects p
    INNER JOIN cities ct ON p.city_id = ct.id
    INNER JOIN country_filter cf ON ct.country_id = cf.country_id
    WHERE p.sector_id IS NOT NULL
      AND (p_stage_ids IS NULL OR p.project_stage_id = ANY(p_stage_ids))
      AND (p_min_value IS NULL OR p.value >= p_min_value)
      AND (p_max_value IS NULL OR p.value <= p_max_value)
      AND (NOT p_exclude_master_projects OR NOT EXISTS (
        SELECT 1 FROM projecttree pt WHERE pt.mainproject_id = p.id
      ))
      AND (p_exclude_signpost_ids IS NULL OR NOT EXISTS (
        SELECT 1 FROM projectsignposts pss
        WHERE pss.project_id = p.id AND pss.signpost_id = ANY(p_exclude_signpost_ids)
      ))
  ),
  projects_with_companies AS (
    SELECT pb.project_id
    FROM project_base pb
    CROSS JOIN LATERAL (
      SELECT psrc.required_companies, psrc.conditional_roles
      FROM project_stage_sector_required_companies psrc
      WHERE psrc.stage_id = pb.project_stage_id
        AND (psrc.sector_id = pb.sector_id OR psrc.sector_id IS NULL)
        AND (psrc.value_range = pb.value_range OR psrc.value_range = 'All')
      ORDER BY
        (psrc.sector_id IS NOT NULL)::int DESC,
        (psrc.value_range <> 'All')::int DESC
      LIMIT 1
    ) rule
    CROSS JOIN LATERAL unnest(
      COALESCE(rule.required_companies, ARRAY[]::text[])
    ) AS rn(req_role)
    INNER JOIN project_role_category_mapping prcm
      ON prcm.role_name = rn.req_role
    WHERE p_include_companies
      AND rn.req_role IS NOT NULL
      AND btrim(rn.req_role) <> ''
      AND prcm.category_ids IS NOT NULL
    GROUP BY pb.project_id
    HAVING
      COUNT(*) FILTER (WHERE
        (
          rule.conditional_roles IS NULL
          OR NOT rule.conditional_roles ? rn.req_role
          OR (
            EXISTS (
              SELECT 1 FROM jsonb_array_elements(rule.conditional_roles -> rn.req_role -> 'conditions') cond
              WHERE cond->>'type' = 'hospitality' AND pb.new_project_type_id = 104000
            )
            OR
            EXISTS (
              SELECT 1 FROM jsonb_array_elements(rule.conditional_roles -> rn.req_role -> 'conditions') cond
              WHERE cond->>'type' = 'gcc_high_value_subtype'
                AND pb.zone_id = 1
                AND pb.value > 20000000
                AND pb.new_subtype_id IN (SELECT (jsonb_array_elements_text(cond->'subtypes'))::int)
            )
          )
        )
      )
      =
      COUNT(*) FILTER (WHERE
        (
          rule.conditional_roles IS NULL
          OR NOT rule.conditional_roles ? rn.req_role
          OR (
            EXISTS (
              SELECT 1 FROM jsonb_array_elements(rule.conditional_roles -> rn.req_role -> 'conditions') cond
              WHERE cond->>'type' = 'hospitality' AND pb.new_project_type_id = 104000
            )
            OR
            EXISTS (
              SELECT 1 FROM jsonb_array_elements(rule.conditional_roles -> rn.req_role -> 'conditions') cond
              WHERE cond->>'type' = 'gcc_high_value_subtype'
                AND pb.zone_id = 1
                AND pb.value > 20000000
                AND pb.new_subtype_id IN (SELECT (jsonb_array_elements_text(cond->'subtypes'))::int)
            )
          )
        )
        AND
        (
          (rn.req_role NOT LIKE '%Bidders'
            AND EXISTS (SELECT 1 FROM projectcompanies pc
                        WHERE pc.project_id = pb.project_id
                          AND pc.category_id = ANY(prcm.category_ids)))
          OR
          (rn.req_role LIKE '%Bidders'
            AND EXISTS (SELECT 1 FROM projectbidders pbd
                        WHERE pbd.project_id = pb.project_id
                          AND pbd.category_id = ANY(prcm.category_ids)))
        )
      )
  ),
  projects_with_cud AS (
    SELECT DISTINCT pss.project_id
    FROM projectsignposts pss
    INNER JOIN project_signpost psp ON pss.signpost_id = psp.id
    INNER JOIN project_base pb ON pb.project_id = pss.project_id
    WHERE p_include_cud AND psp.post_type = 'CUD'
  ),
  projects_with_dnt AS (
    SELECT DISTINCT pss.project_id
    FROM projectsignposts pss
    INNER JOIN project_signpost psp ON pss.signpost_id = psp.id
    INNER JOIN project_base pb ON pb.project_id = pss.project_id
    WHERE p_include_dnt AND psp.post_type ILIKE 'DNT%'
  ),
  projects_with_contacts AS (
    SELECT DISTINCT pc.project_id
    FROM projectcompanykeycontacts pckc
    INNER JOIN projectcompanies pc ON pc.id = pckc.project_company_id
    INNER JOIN project_base pb ON pb.project_id = pc.project_id
    WHERE p_include_keycontacts
  ),
  aggregated AS (
    SELECT
      s.name::text AS sector_name,
      pb.country_name::text AS country_name,
      COUNT(DISTINCT pb.project_id) AS proj_count,
      CASE
        WHEN NOT p_include_companies THEN NULL
        ELSE ROUND(
          (COUNT(DISTINCT pwc.project_id)::numeric / NULLIF(COUNT(DISTINCT pb.project_id), 0)) * 100, 1
        )
      END AS company_pct,
      CASE
        WHEN NOT p_include_cud THEN NULL
        ELSE ROUND(
          ((COUNT(DISTINCT pb.project_id) - COUNT(DISTINCT pcud.project_id))::numeric / NULLIF(COUNT(DISTINCT pb.project_id), 0)) * 100, 1
        )
      END AS cud_pct,
      CASE
        WHEN NOT p_include_dnt THEN NULL
        ELSE ROUND(
          ((COUNT(DISTINCT pb.project_id) - COUNT(DISTINCT pdnt.project_id))::numeric / NULLIF(COUNT(DISTINCT pb.project_id), 0)) * 100, 1
        )
      END AS dnt_pct,
      CASE
        WHEN NOT p_include_keycontacts THEN NULL
        ELSE ROUND(
          (COUNT(DISTINCT pcon.project_id)::numeric / NULLIF(COUNT(DISTINCT pb.project_id), 0)) * 100, 1
        )
      END AS contacts_pct
    FROM project_base pb
    INNER JOIN project_sector s ON s.id = pb.sector_id
    LEFT JOIN projects_with_companies pwc ON pwc.project_id = pb.project_id
    LEFT JOIN projects_with_cud pcud ON pcud.project_id = pb.project_id
    LEFT JOIN projects_with_dnt pdnt ON pdnt.project_id = pb.project_id
    LEFT JOIN projects_with_contacts pcon ON pcon.project_id = pb.project_id
    GROUP BY s.name, pb.country_name
    ORDER BY s.name, pb.country_name
  )
  SELECT
    aggregated.sector_name AS sector,
    aggregated.country_name AS country,
    aggregated.proj_count AS project_count,
    aggregated.company_pct AS company_availability,
    aggregated.cud_pct AS cud_percent,
    aggregated.dnt_pct AS dnt_percent,
    aggregated.contacts_pct AS contacts_percent
  FROM aggregated;
END;
$$;


ALTER FUNCTION "public"."get_sector_kpi_matrix"("p_countries" "text"[], "p_stage_ids" integer[], "p_min_value" numeric, "p_max_value" numeric, "p_exclude_master_projects" boolean, "p_exclude_signpost_ids" integer[], "p_include_companies" boolean, "p_include_cud" boolean, "p_include_dnt" boolean, "p_include_keycontacts" boolean) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_sector_kpi_matrix_v2"("p_countries" "text"[] DEFAULT NULL::"text"[], "p_stage_ids" integer[] DEFAULT NULL::integer[], "p_min_value" numeric DEFAULT NULL::numeric, "p_max_value" numeric DEFAULT NULL::numeric, "p_exclude_master_projects" boolean DEFAULT false, "p_exclude_signpost_ids" integer[] DEFAULT NULL::integer[], "p_include_companies" boolean DEFAULT true, "p_include_cud" boolean DEFAULT true, "p_include_dnt" boolean DEFAULT true, "p_include_keycontacts" boolean DEFAULT true) RETURNS TABLE("sector" "text", "country" "text", "project_count" bigint, "company_availability" numeric, "cud_percent" numeric, "dnt_percent" numeric, "contacts_percent" numeric)
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
BEGIN
  RETURN QUERY

  -- 1. Filter countries
  WITH country_filter AS (
    SELECT co.id AS country_id, co.country AS country_name, co.zone_id
    FROM countries co
    WHERE p_countries IS NULL OR co.country = ANY(p_countries)
  ),

  -- 2. Base project set with all exclusions applied
  project_base AS (
    SELECT
      p.id AS project_id,
      p.sector_id,
      p.project_stage_id,
      p.value,
      cf.country_name,
      cf.zone_id,
      p.new_project_type_id,
      p.new_subtype_id,
      CASE
        WHEN p.value > 20000000 THEN 'Above 20 M'
        WHEN p.value > 0 AND p.value < 20000000 THEN 'Below 20 M'
        ELSE 'All'
      END AS value_range
    FROM projects p
    INNER JOIN cities ct ON p.city_id = ct.id
    INNER JOIN country_filter cf ON ct.country_id = cf.country_id
    WHERE p.sector_id IS NOT NULL
      AND (p_stage_ids IS NULL OR p.project_stage_id = ANY(p_stage_ids))
      AND (p_min_value IS NULL OR p.value >= p_min_value)
      AND (p_max_value IS NULL OR p.value <= p_max_value)
      AND (NOT p_exclude_master_projects OR NOT EXISTS (
        SELECT 1 FROM projecttree pt WHERE pt.mainproject_id = p.id
      ))
      AND (p_exclude_signpost_ids IS NULL OR NOT EXISTS (
        SELECT 1 FROM projectsignposts pss
        WHERE pss.project_id = p.id AND pss.signpost_id = ANY(p_exclude_signpost_ids)
      ))
  ),

  -- 3. Matrix-driven company availability check
  -- For each project, find the matching matrix row and check all required roles
  projects_with_companies AS (
    SELECT pb.project_id
    FROM project_base pb
    -- Find the best-matching matrix rule for this project
    CROSS JOIN LATERAL (
      SELECT psrc.required_companies, psrc.conditional_roles
      FROM project_stage_sector_required_companies psrc
      WHERE psrc.stage_id = pb.project_stage_id
        AND (psrc.sector_id = pb.sector_id OR psrc.sector_id IS NULL)
        AND (psrc.value_range = pb.value_range OR psrc.value_range = 'All')
      ORDER BY
        (psrc.sector_id IS NOT NULL)::int DESC,
        (psrc.value_range <> 'All')::int DESC
      LIMIT 1
    ) rule
    -- Unnest required roles from the matched rule
    CROSS JOIN LATERAL unnest(
      COALESCE(rule.required_companies, ARRAY[]::text[])
    ) AS rn(req_role)
    -- Resolve role name to category IDs
    INNER JOIN project_role_category_mapping prcm
      ON prcm.role_name = rn.req_role
    WHERE p_include_companies
      AND rn.req_role IS NOT NULL
      AND btrim(rn.req_role) <> ''
      AND prcm.category_ids IS NOT NULL
    GROUP BY pb.project_id
    HAVING
      -- Count roles that APPLY (unconditional + conditional where condition is met)
      COUNT(*) FILTER (WHERE
        (
          rule.conditional_roles IS NULL
          OR NOT rule.conditional_roles ? rn.req_role
          OR (
            -- Hospitality condition: project type = 104000
            EXISTS (
              SELECT 1 FROM jsonb_array_elements(rule.conditional_roles -> rn.req_role -> 'conditions') cond
              WHERE cond->>'type' = 'hospitality' AND pb.new_project_type_id = 104000
            )
            OR
            -- GCC high-value subtype condition: zone=1, value>20M, matching subtype
            EXISTS (
              SELECT 1 FROM jsonb_array_elements(rule.conditional_roles -> rn.req_role -> 'conditions') cond
              WHERE cond->>'type' = 'gcc_high_value_subtype'
                AND pb.zone_id = 1
                AND pb.value > 20000000
                AND pb.new_subtype_id IN (SELECT (jsonb_array_elements_text(cond->'subtypes'))::int)
            )
          )
        )
      )
      =
      -- Count roles that APPLY AND ARE FILLED
      COUNT(*) FILTER (WHERE
        (
          rule.conditional_roles IS NULL
          OR NOT rule.conditional_roles ? rn.req_role
          OR (
            EXISTS (
              SELECT 1 FROM jsonb_array_elements(rule.conditional_roles -> rn.req_role -> 'conditions') cond
              WHERE cond->>'type' = 'hospitality' AND pb.new_project_type_id = 104000
            )
            OR
            EXISTS (
              SELECT 1 FROM jsonb_array_elements(rule.conditional_roles -> rn.req_role -> 'conditions') cond
              WHERE cond->>'type' = 'gcc_high_value_subtype'
                AND pb.zone_id = 1
                AND pb.value > 20000000
                AND pb.new_subtype_id IN (SELECT (jsonb_array_elements_text(cond->'subtypes'))::int)
            )
          )
        )
        AND
        (
          -- Check projectcompanies for non-Bidders roles
          (rn.req_role NOT LIKE '%Bidders'
            AND EXISTS (SELECT 1 FROM projectcompanies pc
                        WHERE pc.project_id = pb.project_id
                          AND pc.category_id = ANY(prcm.category_ids)))
          OR
          -- Check projectbidders for Bidders roles
          (rn.req_role LIKE '%Bidders'
            AND EXISTS (SELECT 1 FROM projectbidders pbd
                        WHERE pbd.project_id = pb.project_id
                          AND pbd.category_id = ANY(prcm.category_ids)))
        )
      )
  ),

  -- 4. CUD signpost check (inverted: % WITHOUT CUD flag)
  projects_with_cud AS (
    SELECT DISTINCT pss.project_id
    FROM projectsignposts pss
    INNER JOIN project_signpost psp ON pss.signpost_id = psp.id
    INNER JOIN project_base pb ON pb.project_id = pss.project_id
    WHERE p_include_cud AND psp.post_type = 'CUD'
  ),

  -- 5. DNT signpost check (inverted: % WITHOUT DNT flag)
  projects_with_dnt AS (
    SELECT DISTINCT pss.project_id
    FROM projectsignposts pss
    INNER JOIN project_signpost psp ON pss.signpost_id = psp.id
    INNER JOIN project_base pb ON pb.project_id = pss.project_id
    WHERE p_include_dnt AND psp.post_type ILIKE 'DNT%'
  ),

  -- 6. Key contacts check
  projects_with_contacts AS (
    SELECT DISTINCT pc.project_id
    FROM projectcompanykeycontacts pckc
    INNER JOIN projectcompanies pc ON pc.id = pckc.project_company_id
    INNER JOIN project_base pb ON pb.project_id = pc.project_id
    WHERE p_include_keycontacts
  ),

  -- 7. Aggregate by sector and country
  aggregated AS (
    SELECT
      s.name::text AS sector_name,
      pb.country_name::text AS country_name,
      COUNT(DISTINCT pb.project_id) AS proj_count,
      CASE
        WHEN NOT p_include_companies THEN NULL
        ELSE ROUND(
          (COUNT(DISTINCT pwc.project_id)::numeric / NULLIF(COUNT(DISTINCT pb.project_id), 0)) * 100, 1
        )
      END AS company_pct,
      CASE
        WHEN NOT p_include_cud THEN NULL
        ELSE ROUND(
          ((COUNT(DISTINCT pb.project_id) - COUNT(DISTINCT pcud.project_id))::numeric / NULLIF(COUNT(DISTINCT pb.project_id), 0)) * 100, 1
        )
      END AS cud_pct,
      CASE
        WHEN NOT p_include_dnt THEN NULL
        ELSE ROUND(
          ((COUNT(DISTINCT pb.project_id) - COUNT(DISTINCT pdnt.project_id))::numeric / NULLIF(COUNT(DISTINCT pb.project_id), 0)) * 100, 1
        )
      END AS dnt_pct,
      CASE
        WHEN NOT p_include_keycontacts THEN NULL
        ELSE ROUND(
          (COUNT(DISTINCT pcon.project_id)::numeric / NULLIF(COUNT(DISTINCT pb.project_id), 0)) * 100, 1
        )
      END AS contacts_pct
    FROM project_base pb
    INNER JOIN project_sector s ON s.id = pb.sector_id
    LEFT JOIN projects_with_companies pwc ON pwc.project_id = pb.project_id
    LEFT JOIN projects_with_cud pcud ON pcud.project_id = pb.project_id
    LEFT JOIN projects_with_dnt pdnt ON pdnt.project_id = pb.project_id
    LEFT JOIN projects_with_contacts pcon ON pcon.project_id = pb.project_id
    GROUP BY s.name, pb.country_name
    ORDER BY s.name, pb.country_name
  )

  SELECT
    aggregated.sector_name AS sector,
    aggregated.country_name AS country,
    aggregated.proj_count AS project_count,
    aggregated.company_pct AS company_availability,
    aggregated.cud_pct AS cud_percent,
    aggregated.dnt_pct AS dnt_percent,
    aggregated.contacts_pct AS contacts_percent
  FROM aggregated;

END;
$$;


ALTER FUNCTION "public"."get_sector_kpi_matrix_v2"("p_countries" "text"[], "p_stage_ids" integer[], "p_min_value" numeric, "p_max_value" numeric, "p_exclude_master_projects" boolean, "p_exclude_signpost_ids" integer[], "p_include_companies" boolean, "p_include_cud" boolean, "p_include_dnt" boolean, "p_include_keycontacts" boolean) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_subcampaign_social_metrics"("p_subcampaign_id" integer) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_metrics JSONB;
BEGIN
  SELECT jsonb_build_object(
    'total_posts', COUNT(*),
    'published', COUNT(*) FILTER (WHERE status = 'published'),
    'scheduled', COUNT(*) FILTER (WHERE status = 'scheduled'),
    'failed', COUNT(*) FILTER (WHERE status = 'failed'),
    'platforms', jsonb_object_agg(
      platform,
      jsonb_build_object(
        'count', COUNT(*),
        'engagement', COALESCE(SUM((engagement_metrics->>'likes')::INTEGER), 0) + 
                     COALESCE(SUM((engagement_metrics->>'shares')::INTEGER), 0) +
                     COALESCE(SUM((engagement_metrics->>'comments')::INTEGER), 0)
      )
    ),
    'total_engagement', COALESCE(SUM((engagement_metrics->>'likes')::INTEGER), 0) + 
                        COALESCE(SUM((engagement_metrics->>'shares')::INTEGER), 0) +
                        COALESCE(SUM((engagement_metrics->>'comments')::INTEGER), 0),
    'total_impressions', COALESCE(SUM((engagement_metrics->>'impressions')::INTEGER), 0)
  ) INTO v_metrics
  FROM blaze_posts
  WHERE subcampaign_id = p_subcampaign_id
  GROUP BY subcampaign_id;

  RETURN COALESCE(v_metrics, '{}'::jsonb);
END;
$$;


ALTER FUNCTION "public"."get_subcampaign_social_metrics"("p_subcampaign_id" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_subcampaign_task_stats"("p_subcampaign_id" integer) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  stats JSONB;
BEGIN
  SELECT jsonb_build_object(
    'total', COUNT(*),
    'open', COUNT(*) FILTER (WHERE taskstatus = 'Open'),
    'successful', COUNT(*) FILTER (WHERE taskstatus = 'Successful'),
    'unsuccessful', COUNT(*) FILTER (WHERE taskstatus = 'Unsuccessful'),
    'void', COUNT(*) FILTER (WHERE taskstatus = 'Void'),
    'quote_requested', COUNT(*) FILTER (WHERE taskstatus = 'Quote Requested'),
    'completion_rate', 
      ROUND(
        (COUNT(*) FILTER (WHERE taskstatus IN ('Successful', 'Unsuccessful', 'Void'))::NUMERIC / 
        NULLIF(COUNT(*), 0) * 100
      ), 2),
    'success_rate',
      ROUND(
        (COUNT(*) FILTER (WHERE taskstatus = 'Successful')::NUMERIC / 
        NULLIF(COUNT(*) FILTER (WHERE taskstatus IN ('Successful', 'Unsuccessful')), 0) * 100
      ), 2),
    'avg_completion_days',
      ROUND(
        AVG(
          EXTRACT(EPOCH FROM (closedon - enteredon)) / 86400
        ) FILTER (WHERE closedon IS NOT NULL),
        1
      )
  ) INTO stats
  FROM tasklist
  WHERE subcampaign_id = p_subcampaign_id;
  
  RETURN COALESCE(stats, '{}'::jsonb);
END;
$$;


ALTER FUNCTION "public"."get_subcampaign_task_stats"("p_subcampaign_id" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_task_chain_for_lead"("p_lead_id" integer) RETURNS TABLE("tasklistid" integer, "taskid" integer, "taskstatus" "text", "enteredon" timestamp with time zone, "closedon" timestamp with time zone, "taskdate" timestamp with time zone, "remarks" "text", "previous_task_id" integer, "calendar_event_id" integer, "task_order" integer)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  WITH RECURSIVE task_chain AS (
    -- Base case: find root tasks (no previous_task_id) for the lead
    SELECT 
      t.tasklistid,
      t.taskid,
      t.taskstatus::text,
      t.enteredon,
      t.closedon,
      t.taskdate,
      t.remarks,
      t.previous_task_id,
      t.calendar_event_id,
      1 as task_order
    FROM tasklist t
    WHERE t.leadid = p_lead_id 
      AND t.previous_task_id IS NULL
    
    UNION ALL
    
    -- Recursive case: find tasks that follow from the current task
    SELECT 
      t.tasklistid,
      t.taskid,
      t.taskstatus::text,
      t.enteredon,
      t.closedon,
      t.taskdate,
      t.remarks,
      t.previous_task_id,
      t.calendar_event_id,
      tc.task_order + 1
    FROM tasklist t
    INNER JOIN task_chain tc ON t.previous_task_id = tc.tasklistid
    WHERE t.leadid = p_lead_id
  )
  SELECT * FROM task_chain
  ORDER BY task_order, enteredon;
END;
$$;


ALTER FUNCTION "public"."get_task_chain_for_lead"("p_lead_id" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_task_interactions"("p_task_id" integer) RETURNS TABLE("interaction_id" integer, "interaction_type_id" integer, "created_at" timestamp with time zone, "created_by" "uuid")
