CREATE OR REPLACE FUNCTION "public"."get_unsynced_events"("hours_back" integer DEFAULT 24) RETURNS TABLE("event_id" integer, "integration_id" integer, "calendar_collection_id" integer, "title" "text", "created_at" timestamp with time zone)
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  cutoff_time TIMESTAMP WITH TIME ZONE;
BEGIN
  cutoff_time := now() - (hours_back || ' hours')::interval;
  
  RETURN QUERY
  SELECT 
    ce.id as event_id,
    ci.id as integration_id,
    ce.calendar_collection_id,
    ce.title::TEXT,  -- Cast to TEXT to match return type
    ce.created_at
  FROM calendar_events ce
  JOIN calendar_integrations ci ON ci.calendar_collection_id = ce.calendar_collection_id
  WHERE 
    ce.created_at >= cutoff_time
    AND ci.status = 'active'
    AND (
      ce.sync_status = 'pending' 
      OR ce.sync_status = 'failed'
      OR NOT EXISTS (
        SELECT 1 FROM event_mappings em 
        WHERE em.calendar_event_id = ce.id 
        AND em.integration_id = ci.id
      )
    )
  ORDER BY ce.created_at DESC;
END;
$$;


ALTER FUNCTION "public"."get_unsynced_events"("hours_back" integer) OWNER TO "postgres";


