CREATE OR REPLACE FUNCTION "public"."get_user_calendar_permissions"("p_calendar_id" integer, "p_user_id" "uuid" DEFAULT "auth"."uid"()) RETURNS "text"
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  SELECT 
    CASE 
      WHEN cc.owner_id = p_user_id THEN 'admin'
      WHEN cs.permission_level IS NOT NULL THEN cs.permission_level
      ELSE NULL
    END
  FROM public.calendar_collections cc
  LEFT JOIN public.calendar_shares cs ON cs.calendar_id = cc.id AND cs.shared_with_user_id = p_user_id
  WHERE cc.id = p_calendar_id
  LIMIT 1;
$$;


