CREATE OR REPLACE FUNCTION "public"."get_user_effective_permissions"("_module_name" "text", "_user_id" "uuid" DEFAULT "auth"."uid"()) RETURNS TABLE("action_code" "text", "dataset_code" "text", "is_allowed" boolean, "dataset_filter" "text")
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  -- Super Admin gets all permissions
  IF public.check_user_role(_user_id, 'Super Admin') THEN
    RETURN QUERY
    SELECT 
      a.code::text as action_code,
      'all_records'::text as dataset_code,
      true as is_allowed,
      '1=1'::text as dataset_filter
    FROM public.actions a
    WHERE a.name IN ('View', 'Add', 'Edit', 'Delete', 'Export', 'Assign', 'Approve');
    RETURN;
  END IF;
  
  -- Get user's specific permissions
  RETURN QUERY
  SELECT DISTINCT
    a.code::text as action_code,
    d.code::text as dataset_code,
    COALESCE(rp.is_allowed, false) as is_allowed,
    public.apply_dataset_filter(_module_name, a.code, _user_id) as dataset_filter
  FROM public.modules m
  CROSS JOIN public.actions a
  CROSS JOIN public.datasets d
  LEFT JOIN public.module_action_datasets mad ON mad.module_id = m.id AND mad.action_id = a.id AND mad.dataset_id = d.id
  LEFT JOIN public.role_permissions rp ON rp.module_action_dataset_id = mad.id
  WHERE m.name = _module_name
    AND rp.is_allowed = true
    AND (
      -- Check primary role
      EXISTS (
        SELECT 1 FROM public.users u
        WHERE u.auth_user_id = _user_id AND u.role_id = rp.role_id AND u.status = 'active'
      ) OR
      -- Check additional roles
      EXISTS (
        SELECT 1 FROM public.user_roles ur
        JOIN public.users u ON u.id = ur.user_id
        WHERE u.auth_user_id = _user_id AND ur.role_id = rp.role_id 
        AND ur.is_active = true AND u.status = 'active'
      )
    )
  ORDER BY a.code, d.code DESC;
END;
$$;


ALTER FUNCTION "public"."get_user_effective_permissions"("_module_name" "text", "_user_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_user_module_permissions"("_module_name" "text", "_user_id" "uuid" DEFAULT "auth"."uid"()) RETURNS TABLE("module_name" "text", "action_code" "text", "dataset_code" "text", "is_allowed" boolean, "dataset_filter" "text")
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    m.name::text as module_name,
    a.code::text as action_code,
    d.code::text as dataset_code,
    COALESCE(rp.is_allowed, false) as is_allowed,
    public.apply_dataset_filter(m.name, a.code, _user_id) as dataset_filter
  FROM modules m
  CROSS JOIN actions a
  CROSS JOIN datasets d
  LEFT JOIN module_action_datasets mad ON mad.module_id = m.id AND mad.action_id = a.id AND mad.dataset_id = d.id
  LEFT JOIN role_permissions rp ON rp.module_action_dataset_id = mad.id
  WHERE m.name = _module_name
    AND (
      -- Check primary role
      EXISTS (
        SELECT 1 FROM users u
        WHERE u.auth_user_id = _user_id AND u.role_id = rp.role_id AND u.status = 'active'
      ) OR
      -- Check additional roles
      EXISTS (
        SELECT 1 FROM user_roles ur
        JOIN users u ON u.id = ur.user_id
        WHERE u.auth_user_id = _user_id AND ur.role_id = rp.role_id 
        AND ur.is_active = true AND u.status = 'active'
      )
    )
    AND rp.is_allowed = true
  ORDER BY a.code, d.code DESC;
END;
$$;


ALTER FUNCTION "public"."get_user_module_permissions"("_module_name" "text", "_user_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_user_pending_approvals"("p_user_id" "uuid" DEFAULT "auth"."uid"()) RETURNS TABLE("workflow_id" integer, "document_version_id" integer, "workflow_name" character varying, "current_step" integer, "total_steps" integer, "status" "text", "initiated_at" timestamp with time zone, "approval_deadline" timestamp with time zone, "document_reference" character varying)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    dw.id as workflow_id,
    dw.document_version_id,
    dw.workflow_name,
    dw.current_step,
    dw.total_steps,
    dw.status::text,
    dw.initiated_at,
    dw.approval_deadline,
    dv.reference_number as document_reference
  FROM document_approval_workflows dw
  JOIN document_versions dv ON dv.id = dw.document_version_id
  JOIN document_approval_steps das ON das.workflow_id = dw.id AND das.step_number = dw.current_step
  WHERE dw.status = 'pending'
    AND das.status = 'pending'
    AND (
      das.approver_id = p_user_id
      OR das.approver_role_id IN (
        SELECT role_id FROM user_roles WHERE user_id = (
          SELECT id FROM users WHERE auth_user_id = p_user_id
        ) AND is_active = true
      )
    );
END;
$$;


ALTER FUNCTION "public"."get_user_pending_approvals"("p_user_id" "uuid") OWNER TO "postgres";


