    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  -- Ensure owner gets highest permission level available (adminrevise)
  INSERT INTO public.document_access_controls (
    document_id,
    user_id,
    permission_type,
    granted_by,
    is_active
  ) VALUES (
    NEW.id,
    NEW.owner_id,
    'adminrevise',
    NEW.owner_id,
    true
  );

  RETURN NEW;
END;
$$;


