CREATE OR REPLACE FUNCTION "public"."handle_mad_activation"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  -- When a module_action_dataset is activated, grant to Super Admin if not exists
  IF NEW.is_active = true AND (OLD.is_active = false OR OLD.is_active IS NULL) THEN
    INSERT INTO role_permissions (role_id, module_action_dataset_id, dataset_id)
    VALUES (4, NEW.id, NULL)
    ON CONFLICT DO NOTHING;
  END IF;
  RETURN NEW;
END;
$$;


