    SET "search_path" TO 'public'
    AS $$
DECLARE
  default_role_id bigint;
BEGIN
  SELECT id INTO default_role_id FROM public.roles WHERE name = 'IRIS User' LIMIT 1;
  
  INSERT INTO public.users (auth_user_id, username, role_id, status)
  VALUES (new.id, new.email, default_role_id, 'active')
  ON CONFLICT (auth_user_id) DO NOTHING;
  RETURN new;
END;
$$;


