CREATE OR REPLACE FUNCTION "public"."has_ibis_filters"("criteria" "jsonb") RETURNS boolean
    LANGUAGE "plpgsql" IMMUTABLE
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN (
    (jsonb_typeof(criteria->'ibisUserPackage') = 'array' AND jsonb_array_length(criteria->'ibisUserPackage') > 0) OR
    (jsonb_typeof(criteria->'ibisUserStatus') = 'array' AND jsonb_array_length(criteria->'ibisUserStatus') > 0) OR
    (jsonb_typeof(criteria->'ibisOnboardPlatform') = 'array' AND jsonb_array_length(criteria->'ibisOnboardPlatform') > 0) OR
    (jsonb_typeof(criteria->'ibisSynergyRole') = 'array' AND jsonb_array_length(criteria->'ibisSynergyRole') > 0) OR
    (jsonb_typeof(criteria->'ibisUserRight') = 'array' AND jsonb_array_length(criteria->'ibisUserRight') > 0) OR
    (jsonb_typeof(criteria->'package') = 'array' AND jsonb_array_length(criteria->'package') > 0) OR
    COALESCE(criteria->>'ibisLastLoginFrom', '') <> '' OR
    COALESCE(criteria->>'ibisLastLoginTo', '') <> '' OR
    COALESCE(criteria->>'ibisOnboardingDateFrom', '') <> '' OR
    COALESCE(criteria->>'ibisOnboardingDateTo', '') <> '' OR
    COALESCE(criteria->>'ibisUserCreatedFrom', '') <> '' OR
    COALESCE(criteria->>'ibisUserCreatedTo', '') <> '' OR
    COALESCE(criteria->>'ibisSubscriptionStartFrom', '') <> '' OR
    COALESCE(criteria->>'ibisSubscriptionStartTo', '') <> '' OR
    COALESCE(criteria->>'ibisSubscriptionEndFrom', '') <> '' OR
    COALESCE(criteria->>'ibisSubscriptionEndTo', '') <> ''
  );
END;
$$;


ALTER FUNCTION "public"."has_ibis_filters"("criteria" "jsonb") OWNER TO "postgres";


