CREATE OR REPLACE FUNCTION "public"."has_role_multi"("_role_name" "text") RETURNS boolean
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  SELECT EXISTS (
    -- Check primary role
    SELECT 1 FROM public.users u
    JOIN public.roles r ON r.id = u.role_id
    WHERE u.auth_user_id = auth.uid()
    AND r.name = _role_name
    AND u.status = 'active'
    AND r.status = 'active'
  ) OR EXISTS (
    -- Check additional roles
    SELECT 1 FROM public.user_roles ur
    JOIN public.users u ON u.id = ur.user_id
    JOIN public.roles r ON r.id = ur.role_id
    WHERE u.auth_user_id = auth.uid()
    AND r.name = _role_name
    AND ur.is_active = true
    AND u.status = 'active'
    AND r.status = 'active'
  );
$$;


ALTER FUNCTION "public"."has_role_multi"("_role_name" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."has_sfs_filters"("criteria" "jsonb") RETURNS boolean
    LANGUAGE "plpgsql"
    AS $$
BEGIN
  IF criteria IS NULL THEN RETURN false; END IF;
  RETURN (
    (criteria ? 'sfsProduct' AND jsonb_typeof(criteria->'sfsProduct') = 'array' AND jsonb_array_length(criteria->'sfsProduct') > 0)
    OR
    (criteria ? 'sfsValue' AND jsonb_typeof(criteria->'sfsValue') = 'array' AND jsonb_array_length(criteria->'sfsValue') > 0)
  );
END;
$$;


ALTER FUNCTION "public"."has_sfs_filters"("criteria" "jsonb") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."initiate_document_approval"("p_document_version_id" integer, "p_workflow_name" character varying, "p_steps" "jsonb", "p_requester_notes" "text" DEFAULT NULL::"text") RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_workflow_id integer;
  v_step jsonb;
  v_step_number integer := 1;
BEGIN
  INSERT INTO document_approval_workflows (
    document_version_id,
    workflow_name,
    current_step,
    total_steps,
    status,
    initiated_by,
    initiated_at,
    requester_notes
  ) VALUES (
    p_document_version_id,
    p_workflow_name,
    1,
    jsonb_array_length(p_steps),
    'pending',
    auth.uid(),
    now(),
    p_requester_notes
  ) RETURNING id INTO v_workflow_id;
  
  FOR v_step IN SELECT jsonb_array_elements(p_steps)
  LOOP
    INSERT INTO document_approval_steps (
      workflow_id,
      step_number,
      approver_id,
      approver_role_id,
      status,
      step_type
    ) VALUES (
      v_workflow_id,
      v_step_number,
      (v_step->>'approver_id')::uuid,
      (v_step->>'approver_role_id')::integer,
      CASE WHEN v_step_number = 1 THEN 'pending' ELSE 'waiting' END,
      COALESCE(v_step->>'step_type', 'approval')
    );
    
    v_step_number := v_step_number + 1;
  END LOOP;
  
  RETURN v_workflow_id;
END;
$$;


ALTER FUNCTION "public"."initiate_document_approval"("p_document_version_id" integer, "p_workflow_name" character varying, "p_steps" "jsonb", "p_requester_notes" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."initiate_document_approval"("p_document_id" integer, "p_workflow_name" "text", "p_approval_strategy" "public"."approval_strategy", "p_approval_deadline" timestamp with time zone, "p_approvers" "jsonb", "p_requester_notes" "text" DEFAULT NULL::"text") RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_workflow_id INTEGER;
  v_version_id INTEGER;
  v_approver JSONB;
  v_step_number INTEGER := 1;
BEGIN
  -- Get current document version
  SELECT current_version_id INTO v_version_id
  FROM document_metadata
  WHERE id = p_document_id;
  
  IF v_version_id IS NULL THEN
    RAISE EXCEPTION 'Document has no current version';
  END IF;
  
  -- Create workflow
  INSERT INTO document_approval_workflows (
    document_version_id,
    workflow_name,
    approval_strategy,
    approval_deadline,
    requester_notes,
    total_steps,
    initiated_by
  ) VALUES (
    v_version_id,
    p_workflow_name,
    p_approval_strategy,
    p_approval_deadline,
    p_requester_notes,
    jsonb_array_length(p_approvers),
    auth.uid()
  ) RETURNING id INTO v_workflow_id;
  
  -- Create approval steps
  FOR v_approver IN SELECT * FROM jsonb_array_elements(p_approvers)
  LOOP
    INSERT INTO document_approval_steps (
      workflow_id,
      step_number,
      approver_user_id,
      approver_role_id,
      deadline
    ) VALUES (
      v_workflow_id,
      v_step_number,
      (v_approver->>'user_id')::UUID,
      (v_approver->>'role_id')::INTEGER,
      COALESCE((v_approver->>'deadline')::TIMESTAMPTZ, p_approval_deadline)
    );
    
    v_step_number := v_step_number + 1;
  END LOOP;
  
  -- Log action
  INSERT INTO document_approval_history (
    workflow_id,
    action_type,
    action_by,
    comments
  ) VALUES (
    v_workflow_id,
    'created',
    auth.uid(),
    p_requester_notes
  );
  
  RETURN v_workflow_id;
END;
$$;


ALTER FUNCTION "public"."initiate_document_approval"("p_document_id" integer, "p_workflow_name" "text", "p_approval_strategy" "public"."approval_strategy", "p_approval_deadline" timestamp with time zone, "p_approvers" "jsonb", "p_requester_notes" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."insert_company_document"("p_company_id" integer, "p_contact_id" integer, "p_document_type" "text", "p_source_table" "text", "p_source_id" bigint, "p_reference_number" "text", "p_s3_url" "text", "p_file_name" "text" DEFAULT NULL::"text", "p_document_date" "date" DEFAULT NULL::"date", "p_amount" numeric DEFAULT NULL::numeric, "p_currency" "text" DEFAULT 'AED'::"text", "p_created_by" "uuid" DEFAULT NULL::"uuid") RETURNS bigint
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_id BIGINT;
BEGIN
  INSERT INTO company_documents (
    company_id, contact_id, document_type, source_table, source_id,
    reference_number, s3_url, file_name, document_date, amount, currency, created_by
  ) VALUES (
    p_company_id, p_contact_id, p_document_type, p_source_table, p_source_id,
    p_reference_number, p_s3_url, p_file_name, p_document_date, p_amount, p_currency, p_created_by
  )
  ON CONFLICT (source_table, source_id) WHERE status = 'active'
  DO UPDATE SET
    s3_url = EXCLUDED.s3_url,
    file_name = EXCLUDED.file_name,
    amount = EXCLUDED.amount,
    updated_at = NOW(),
    updated_by = p_created_by
  RETURNING id INTO v_id;
  
  RETURN v_id;
END;
$$;


ALTER FUNCTION "public"."insert_company_document"("p_company_id" integer, "p_contact_id" integer, "p_document_type" "text", "p_source_table" "text", "p_source_id" bigint, "p_reference_number" "text", "p_s3_url" "text", "p_file_name" "text", "p_document_date" "date", "p_amount" numeric, "p_currency" "text", "p_created_by" "uuid") OWNER TO "postgres";


