CREATE OR REPLACE FUNCTION "public"."log_competitor_subscription_changes"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  changed_fields_arr text[] := ARRAY[]::text[];
  old_vals jsonb := '{}'::jsonb;
  new_vals jsonb := '{}'::jsonb;
  change_desc text;
BEGIN
  IF TG_OP = 'UPDATE' THEN
    -- Check each field and build arrays properly
    IF OLD.competitor_id IS DISTINCT FROM NEW.competitor_id THEN
      changed_fields_arr := array_append(changed_fields_arr, 'competitor_id');
      old_vals := old_vals || jsonb_build_object('competitor_id', OLD.competitor_id);
      new_vals := new_vals || jsonb_build_object('competitor_id', NEW.competitor_id);
    END IF;
    
    IF OLD.product_id IS DISTINCT FROM NEW.product_id THEN
      changed_fields_arr := array_append(changed_fields_arr, 'product_id');
      old_vals := old_vals || jsonb_build_object('product_id', OLD.product_id);
      new_vals := new_vals || jsonb_build_object('product_id', NEW.product_id);
    END IF;
    
    IF OLD.start_date IS DISTINCT FROM NEW.start_date THEN
      changed_fields_arr := array_append(changed_fields_arr, 'start_date');
      old_vals := old_vals || jsonb_build_object('start_date', OLD.start_date);
      new_vals := new_vals || jsonb_build_object('start_date', NEW.start_date);
    END IF;
    
    IF OLD.end_date IS DISTINCT FROM NEW.end_date THEN
      changed_fields_arr := array_append(changed_fields_arr, 'end_date');
      old_vals := old_vals || jsonb_build_object('end_date', OLD.end_date);
      new_vals := new_vals || jsonb_build_object('end_date', NEW.end_date);
    END IF;
    
    IF OLD.amount_paid IS DISTINCT FROM NEW.amount_paid THEN
      changed_fields_arr := array_append(changed_fields_arr, 'amount_paid');
      old_vals := old_vals || jsonb_build_object('amount_paid', OLD.amount_paid);
      new_vals := new_vals || jsonb_build_object('amount_paid', NEW.amount_paid);
    END IF;
    
    IF OLD.currency IS DISTINCT FROM NEW.currency THEN
      changed_fields_arr := array_append(changed_fields_arr, 'currency');
      old_vals := old_vals || jsonb_build_object('currency', OLD.currency);
      new_vals := new_vals || jsonb_build_object('currency', NEW.currency);
    END IF;
    
    IF OLD.status IS DISTINCT FROM NEW.status THEN
      changed_fields_arr := array_append(changed_fields_arr, 'status');
      old_vals := old_vals || jsonb_build_object('status', OLD.status);
      new_vals := new_vals || jsonb_build_object('status', NEW.status);
    END IF;
    
    IF OLD.notes IS DISTINCT FROM NEW.notes THEN
      changed_fields_arr := array_append(changed_fields_arr, 'notes');
      old_vals := old_vals || jsonb_build_object('notes', OLD.notes);
      new_vals := new_vals || jsonb_build_object('notes', NEW.notes);
    END IF;
    
    IF OLD.renewal_reminder_days IS DISTINCT FROM NEW.renewal_reminder_days THEN
      changed_fields_arr := array_append(changed_fields_arr, 'renewal_reminder_days');
      old_vals := old_vals || jsonb_build_object('renewal_reminder_days', OLD.renewal_reminder_days);
      new_vals := new_vals || jsonb_build_object('renewal_reminder_days', NEW.renewal_reminder_days);
    END IF;

    -- Only log if something changed
    IF array_length(changed_fields_arr, 1) > 0 THEN
      change_desc := 'Updated ' || array_to_string(changed_fields_arr, ', ');
      
      INSERT INTO competitor_subscription_logs (
        competitor_subscription_id,
        change_type,
        changed_fields,
        old_values,
        new_values,
        description,
        performed_by,
        performed_at
      ) VALUES (
        NEW.id,
        'edit',
        changed_fields_arr,
        old_vals,
        new_vals,
        change_desc,
        NEW.updated_by,
        NOW()
      );
    END IF;
    
    RETURN NEW;
  ELSIF TG_OP = 'INSERT' THEN
    INSERT INTO competitor_subscription_logs (
      competitor_subscription_id,
      change_type,
      changed_fields,
      old_values,
      new_values,
      description,
      performed_by,
      performed_at
    ) VALUES (
      NEW.id,
      'add',
      NULL,
      NULL,
      to_jsonb(NEW),
      'Created competitor subscription',
      NEW.created_by,
      NOW()
    );
    
    RETURN NEW;
  END IF;
  
  RETURN NULL;
END;
$$;


ALTER FUNCTION "public"."log_competitor_subscription_changes"() OWNER TO "postgres";


