CREATE OR REPLACE FUNCTION "public"."log_document_flow_changes"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_has_changes BOOLEAN := false;
  v_change_type VARCHAR(50) := 'manual';
BEGIN
  -- Only log if there are actual changes to tracked fields
  IF TG_OP = 'UPDATE' THEN
    v_has_changes := (
      OLD.company_id IS DISTINCT FROM NEW.company_id OR
      OLD.contact_id IS DISTINCT FROM NEW.contact_id OR
      OLD.flow_direction IS DISTINCT FROM NEW.flow_direction
    );
    
    -- Determine change type based on context
    IF NEW.updated_by IS NULL THEN
      v_change_type := 'system_generated';
    ELSIF OLD.company_id IS NULL AND NEW.company_id IS NOT NULL AND OLD.contact_id IS NOT NULL THEN
      v_change_type := 'auto_populated';
    END IF;
    
  ELSIF TG_OP = 'INSERT' THEN
    -- Log initial state for new documents
    v_has_changes := true;
    v_change_type := 'created';
  END IF;
  
  -- Insert into history if changes detected
  IF v_has_changes THEN
    INSERT INTO document_flow_history (
      document_id,
      from_company_id,
      to_company_id,
      from_contact_id,
      to_contact_id,
      from_flow_direction,
      to_flow_direction,
      changed_by,
      changed_at,
      change_type,
      notes
    ) VALUES (
      NEW.id,
      CASE WHEN TG_OP = 'UPDATE' THEN OLD.company_id ELSE NULL END,
      NEW.company_id,
      CASE WHEN TG_OP = 'UPDATE' THEN OLD.contact_id ELSE NULL END,
      NEW.contact_id,
      CASE WHEN TG_OP = 'UPDATE' THEN OLD.flow_direction ELSE NULL END,
      NEW.flow_direction,
      COALESCE(NEW.updated_by, NEW.created_by, auth.uid()),
      now(),
      v_change_type,
      CASE 
        WHEN TG_OP = 'INSERT' THEN 'Document created'
        WHEN v_change_type = 'auto_populated' THEN 'Company auto-populated from contact'
        ELSE NULL
      END
    );
  END IF;
  
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."log_document_flow_changes"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."log_document_flow_changes"() IS 'Automatically logs document flow changes to audit history';



