CREATE OR REPLACE FUNCTION "public"."log_pricing_config_change"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
    changed_cols TEXT[];
    col_name TEXT;
    old_val JSONB;
    new_val JSONB;
    v_record_id INT;
BEGIN
    -- Build list of changed columns for UPDATE
    IF TG_OP = 'UPDATE' THEN
        FOR col_name IN SELECT column_name FROM information_schema.columns 
                        WHERE table_name = TG_TABLE_NAME AND table_schema = TG_TABLE_SCHEMA
        LOOP
            old_val := to_jsonb(OLD) -> col_name;
            new_val := to_jsonb(NEW) -> col_name;
            IF old_val IS DISTINCT FROM new_val THEN
                changed_cols := array_append(changed_cols, col_name);
            END IF;
        END LOOP;
    END IF;

    -- Determine record_id based on table
    IF TG_OP = 'DELETE' THEN
        IF TG_TABLE_NAME = 'countryvat' THEN
            v_record_id := OLD.quotationvatid;
        ELSE
            v_record_id := OLD.id;
        END IF;
    ELSE
        IF TG_TABLE_NAME = 'countryvat' THEN
            v_record_id := NEW.quotationvatid;
        ELSE
            v_record_id := NEW.id;
        END IF;
    END IF;

    IF TG_OP = 'INSERT' THEN
        INSERT INTO public.pricing_config_audit_log (table_name, record_id, action, new_values, changed_by)
        VALUES (TG_TABLE_NAME, v_record_id, 'INSERT', to_jsonb(NEW), auth.uid());
        RETURN NEW;
    ELSIF TG_OP = 'UPDATE' THEN
        INSERT INTO public.pricing_config_audit_log (table_name, record_id, action, old_values, new_values, changed_fields, changed_by)
        VALUES (TG_TABLE_NAME, v_record_id, 'UPDATE', to_jsonb(OLD), to_jsonb(NEW), changed_cols, auth.uid());
        RETURN NEW;
    ELSIF TG_OP = 'DELETE' THEN
        INSERT INTO public.pricing_config_audit_log (table_name, record_id, action, old_values, changed_by)
        VALUES (TG_TABLE_NAME, v_record_id, 'DELETE', to_jsonb(OLD), auth.uid());
        RETURN OLD;
    END IF;
    
    RETURN NULL;
END;
$$;


ALTER FUNCTION "public"."log_pricing_config_change"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."match_lead_to_subcampaign"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_subcampaign_id INTEGER;
  v_email_job_id INTEGER;
BEGIN
  -- Only proceed if lead has UTM parameters
  IF NEW.campaign_lead IS NULL AND NEW.campaign_medium IS NULL AND NEW.campaign_content IS NULL THEN
    RETURN NEW;
  END IF;

  -- Strategy 1: Direct UTM match against email_jobs
  -- Match email_jobs where UTM parameters match
  SELECT ej.id, ej.subcampaign_id INTO v_email_job_id, v_subcampaign_id
  FROM email_jobs ej
  WHERE 
    (NEW.campaign_lead IS NULL OR ej.utm_campaign = NEW.campaign_lead)
    AND (NEW.campaign_medium IS NULL OR ej.utm_medium = NEW.campaign_medium)
    AND (NEW.campaign_content IS NULL OR ej.utm_content = NEW.campaign_content OR ej.utm_content IS NULL)
  ORDER BY ej.created_at DESC
  LIMIT 1;

  -- Strategy 2: Match against campaign names directly
  IF v_subcampaign_id IS NULL AND NEW.campaign_lead IS NOT NULL THEN
    SELECT s.id INTO v_subcampaign_id
    FROM subcampaigns s
    INNER JOIN campaigns c ON s.campaign_id = c.id
    WHERE 
      c.name ILIKE NEW.campaign_lead
      AND (NEW.campaign_medium IS NULL OR s.channel ILIKE NEW.campaign_medium)
    ORDER BY s.created_at DESC
    LIMIT 1;
  END IF;

  -- Strategy 3: Match against subcampaign names directly
  IF v_subcampaign_id IS NULL AND NEW.campaign_lead IS NOT NULL THEN
    SELECT s.id INTO v_subcampaign_id
    FROM subcampaigns s
    WHERE 
      s.name ILIKE NEW.campaign_lead
      AND (NEW.campaign_medium IS NULL OR s.channel ILIKE NEW.campaign_medium)
    ORDER BY s.created_at DESC
    LIMIT 1;
  END IF;

  -- If we found a match, insert into campaign_leads
  IF v_subcampaign_id IS NOT NULL THEN
    INSERT INTO campaign_leads (lead_id, subcampaign_id, email_job_id, matched_via, matched_at)
    VALUES (
      NEW.id,
      v_subcampaign_id,
      v_email_job_id,
      CASE 
        WHEN v_email_job_id IS NOT NULL THEN 'utm_match'
        ELSE 'name_match'
      END,
      NOW()
    )
    ON CONFLICT (lead_id, subcampaign_id) DO NOTHING;
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."match_lead_to_subcampaign"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."materialize_recipient_list"("p_recipient_list_id" integer) RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare v_cd int; v_subc int; v_prod int;
begin
  select campaign_dataset_id, subcampaign_id, product_id
    into v_cd, v_subc, v_prod
  from public.recipient_lists where id = p_recipient_list_id;

  if v_cd is null then raise exception 'Recipient list not found'; end if;

  -- Enforce product access for calling user
  IF NOT public.has_product_access(v_prod) THEN
    RAISE EXCEPTION 'Access denied for product %', v_prod;
  END IF;

  -- reset current members
  delete from public.recipient_list_members where recipient_list_id = p_recipient_list_id;

  -- base: contacts from campaign_dataset with full contact details
  insert into public.recipient_list_members(
    recipient_list_id, 
    contact_id, 
    first_name, 
    last_name, 
    final_email, 
    designation_name, 
    company_name, 
    generated_at
  )
  select 
    p_recipient_list_id, 
    c.id,
    c.first_name,
    c.last_name,
    lower(coalesce(c.email1, c.email2, c.email3)) as final_email,
    d.designame as designation_name,
    comp.name as company_name,
    now()
  from public.campaign_dataset_contacts cdc
  join public.contacts c on c.id = cdc.contact_id
  left join public.designations d on d.id = c.designation_id
  left join public.companies comp on comp.id = c.company_id
  where cdc.campaign_dataset_id = v_cd
    and coalesce(c.email1, c.email2, c.email3) is not null
    and coalesce(c.email1, c.email2, c.email3) != '';

  -- exclusions: contact
  delete from public.recipient_list_members rlm
  using public.exclusions e
  where e.subcampaign_id = v_subc and e.type='contact'
    and e.value::int = rlm.contact_id
    and rlm.recipient_list_id = p_recipient_list_id;

  -- exclusions: company
  delete from public.recipient_list_members rlm
  using public.exclusions e, public.contacts c
  where e.subcampaign_id = v_subc and e.type='company'
    and e.value::int = c.company_id and c.id = rlm.contact_id
    and rlm.recipient_list_id = p_recipient_list_id;

  -- exclusions: domain (matches email1/email2/email3)
  delete from public.recipient_list_members rlm
  using public.exclusions e, public.contacts c
  where e.subcampaign_id = v_subc and e.type='domain'
    and rlm.recipient_list_id = p_recipient_list_id
    and c.id = rlm.contact_id
    and (
      lower(coalesce(c.email1,'')) like ('%@'||lower(e.value)) or
      lower(coalesce(c.email2,'')) like ('%@'||lower(e.value)) or
      lower(coalesce(c.email3,'')) like ('%@'||lower(e.value))
    );

  -- suppression: global/product (unsubscribe/bounce/complaint)
  update public.recipient_list_members rlm
  set suppressed = true, suppression_reason = 'suppression_list'
  from public.contacts c
  where rlm.recipient_list_id = p_recipient_list_id
    and c.id = rlm.contact_id
    and exists (
      select 1 from public.suppression_lists s
      where s.email = lower(coalesce(c.email1,c.email2,c.email3))
        and (s.scope='global' or (s.scope='product' and s.product_id = v_prod))
        and s.kind in ('unsubscribe','bounce','complaint')
    );
end $$;


ALTER FUNCTION "public"."materialize_recipient_list"("p_recipient_list_id" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."materialize_recipient_list"("p_recipient_list_id" integer, "p_template_category" "text" DEFAULT NULL::"text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare v_cd int; v_subc int; v_prod int;
begin
  select campaign_dataset_id, subcampaign_id, product_id
    into v_cd, v_subc, v_prod
  from public.recipient_lists where id = p_recipient_list_id;

  if v_cd is null then raise exception 'Recipient list not found'; end if;

  -- Enforce product access for calling user
  IF NOT public.has_product_access(v_prod) THEN
    RAISE EXCEPTION 'Access denied for product %', v_prod;
  END IF;

  -- reset current members
  delete from public.recipient_list_members where recipient_list_id = p_recipient_list_id;

  -- base: contacts from campaign_dataset with full contact details
  insert into public.recipient_list_members(
    recipient_list_id, 
    contact_id, 
    first_name, 
    last_name, 
    final_email, 
    designation_name, 
    company_name, 
    company_id,
    generated_at
  )
  select 
    p_recipient_list_id, 
    c.id,
    c.first_name,
    c.last_name,
    lower(coalesce(c.email1, c.email2, c.email3)) as final_email,
    d.designame as designation_name,
    comp.name as company_name,
    c.company_id,
    now()
  from public.campaign_dataset_contacts cdc
  join public.contacts c on c.id = cdc.contact_id
  left join public.designations d on d.id = c.designation_id
  left join public.companies comp on comp.id = c.company_id
  where cdc.campaign_dataset_id = v_cd
    and coalesce(c.email1, c.email2, c.email3) is not null
    and coalesce(c.email1, c.email2, c.email3) != ''
    and coalesce(c.status, 'Active') = 'Active';

  -- exclusions: contact (with category filter)
  delete from public.recipient_list_members rlm
  using public.exclusions e
  where e.subcampaign_id = v_subc and e.type='contact'
    and e.value::int = rlm.contact_id
    and rlm.recipient_list_id = p_recipient_list_id
    and (e.exclusion_type IS NULL OR e.exclusion_type = p_template_category);

  -- exclusions: company (with category filter)
  delete from public.recipient_list_members rlm
  using public.exclusions e, public.contacts c
  where e.subcampaign_id = v_subc and e.type='company'
    and e.value::int = c.company_id and c.id = rlm.contact_id
    and rlm.recipient_list_id = p_recipient_list_id
    and (e.exclusion_type IS NULL OR e.exclusion_type = p_template_category);

  -- exclusions: domain (matches email1/email2/email3, with category filter)
  delete from public.recipient_list_members rlm
  using public.exclusions e, public.contacts c
  where e.subcampaign_id = v_subc and e.type='domain'
    and rlm.recipient_list_id = p_recipient_list_id
    and c.id = rlm.contact_id
    and (
      lower(coalesce(c.email1,'')) like ('%@'||lower(e.value)) or
      lower(coalesce(c.email2,'')) like ('%@'||lower(e.value)) or
      lower(coalesce(c.email3,'')) like ('%@'||lower(e.value))
    )
    and (e.exclusion_type IS NULL OR e.exclusion_type = p_template_category);

  -- suppression: global/product (unsubscribe/bounce/complaint)
  update public.recipient_list_members rlm
  set suppressed = true, suppression_reason = 'suppression_list'
  from public.contacts c
  where rlm.recipient_list_id = p_recipient_list_id
    and c.id = rlm.contact_id
    and exists (
      select 1 from public.suppression_lists s
      where s.email = lower(coalesce(c.email1,c.email2,c.email3))
        and (s.scope='global' or (s.scope='product' and s.product_id = v_prod))
        and s.kind in ('unsubscribe','bounce','complaint')
    );
end $$;


ALTER FUNCTION "public"."materialize_recipient_list"("p_recipient_list_id" integer, "p_template_category" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."materialize_recipient_list_api"("p_recipient_list_id" integer) RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  -- Call the 2-parameter version explicitly to avoid ambiguity
  -- This wrapper resolves the PostgREST PGRST203 function overload ambiguity
  PERFORM public.materialize_recipient_list(
    p_recipient_list_id := p_recipient_list_id,
    p_template_category := NULL  -- Explicitly pass NULL to disambiguate
  );
  
  -- Auto-finalize the recipient list after successful materialization
  UPDATE public.recipient_lists 
  SET finalized = true, 
      updated_at = now()
  WHERE id = p_recipient_list_id;
END;
$$;


ALTER FUNCTION "public"."materialize_recipient_list_api"("p_recipient_list_id" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."materialize_recipient_list_direct"("p_campaign_dataset_id" integer) RETURNS TABLE("contact_id" integer, "email" "text", "first_name" "text", "last_name" "text", "company_name" "text")
    LANGUAGE "plpgsql"
    AS $$
DECLARE
  dataset_criteria jsonb;
  v_where_clause text;
  v_has_ibis_filters boolean;
  v_has_sfs boolean;
  v_join_clause text;
  v_query text;
BEGIN
  SELECT cd.criteria INTO dataset_criteria
  FROM public.campaign_datasets cd
  WHERE cd.id = p_campaign_dataset_id;

  IF dataset_criteria IS NULL THEN
    dataset_criteria := '{}'::jsonb;
  END IF;

  v_where_clause := public.build_criteria_where_clause(dataset_criteria);
  v_has_ibis_filters := public.has_ibis_filters(dataset_criteria);
  v_has_sfs := public.has_sfs_filters(dataset_criteria);
  
  v_join_clause := 'LEFT JOIN public.companies comp ON c.company_id = comp.id';
  IF v_has_ibis_filters THEN
    v_join_clause := v_join_clause || ' LEFT JOIN public.ibisusers iu ON c.id = iu.prime_contact_id';
  END IF;
  IF v_has_sfs THEN
    v_join_clause := v_join_clause || ' JOIN public.company_sfs csfs ON csfs.companyid = comp.id';
  END IF;

  v_query := format(
    'SELECT DISTINCT ON (c.id) 
      c.id as contact_id,
      c.email1 as email,
      c.first_name,
      c.last_name,
      comp.name as company_name
    FROM public.contacts c
    %s
    WHERE c.email1 IS NOT NULL 
      AND c.email1 <> ''''
      AND COALESCE(c.status, ''Active'') = ''Active''
      AND (%s)
    ORDER BY c.id',
    v_join_clause,
    v_where_clause
  );

  RETURN QUERY EXECUTE v_query;
END;
$$;


ALTER FUNCTION "public"."materialize_recipient_list_direct"("p_campaign_dataset_id" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."materialize_recipient_list_direct"("p_recipient_list_id" integer, "p_criteria" "jsonb", "p_search_type" "text" DEFAULT 'contacts'::"text") RETURNS integer
    LANGUAGE "plpgsql"
    AS $$
DECLARE
  v_where_clause text;
  v_query text;
  v_count integer;
  v_has_ibis_filters boolean;
BEGIN
  -- Build the WHERE clause from criteria
  v_where_clause := public.build_criteria_where_clause(p_criteria);
  
  -- Check if we need to join ibisusers
  v_has_ibis_filters := public.has_ibis_filters(p_criteria);
  
  -- Delete existing members for this recipient list
  DELETE FROM public.recipient_list_members WHERE recipient_list_id = p_recipient_list_id;
  
  -- Build and execute dynamic query
  v_query := format(
    'INSERT INTO public.recipient_list_members (recipient_list_id, contact_id, email, first_name, last_name, company_id, company_name)
     SELECT DISTINCT 
       %L::integer,
       c.id,
       c.email1,
       c.first_name,
       c.last_name,
       c.company_id,
       comp.name
     FROM public.contacts c
     LEFT JOIN public.companies comp ON c.company_id = comp.id
     %s
     WHERE c.email1 IS NOT NULL 
       AND c.email1 != ''''
       AND COALESCE(c.status, ''Active'') = ''Active''
       AND (%s)',
    p_recipient_list_id,
    CASE WHEN v_has_ibis_filters THEN 'LEFT JOIN public.ibisusers iu ON c.id = iu.prime_contact_id' ELSE '' END,
    v_where_clause
  );
  
  EXECUTE v_query;
  
  GET DIAGNOSTICS v_count = ROW_COUNT;
  
  -- Update the recipient list with the count
  UPDATE public.recipient_lists 
  SET total_count = v_count, 
      updated_at = now() 
  WHERE id = p_recipient_list_id;
  
  RETURN v_count;
END;
$$;


ALTER FUNCTION "public"."materialize_recipient_list_direct"("p_recipient_list_id" integer, "p_criteria" "jsonb", "p_search_type" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."notify_approval_action"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_requester_email TEXT;
  v_requester_name TEXT;
  v_actioner_email TEXT;
  v_actioner_name TEXT;
  v_document_title TEXT;
  v_workflow_id INTEGER;
  v_workflow_name TEXT;
  v_document_id INTEGER;
  v_auth_token TEXT;
  v_function_url TEXT;
BEGIN
  -- Only trigger on status change to approved, rejected, or forwarded
  IF OLD.status = NEW.status OR NEW.status NOT IN ('approved', 'rejected', 'forwarded') THEN
    RETURN NEW;
  END IF;

  -- Get workflow details
  SELECT 
    daw.id,
    daw.workflow_name,
    daw.initiated_by,
    dv.document_id
  INTO v_workflow_id, v_workflow_name, v_requester_email, v_document_id
  FROM document_approval_workflows daw
  JOIN document_versions dv ON dv.id = daw.document_version_id
  WHERE daw.id = NEW.workflow_id
  LIMIT 1;

  -- Get requester details
  SELECT 
    COALESCE(au.email, ''),
    COALESCE(u.username, 'Requester')
  INTO v_requester_email, v_requester_name
  FROM users u
  LEFT JOIN auth.users au ON au.id = u.auth_user_id
  WHERE u.auth_user_id = (
    SELECT initiated_by 
    FROM document_approval_workflows 
    WHERE id = NEW.workflow_id
  )
  LIMIT 1;

  -- Get actioner details
  SELECT 
    COALESCE(au.email, ''),
    COALESCE(u.username, 'Approver')
  INTO v_actioner_email, v_actioner_name
  FROM users u
  LEFT JOIN auth.users au ON au.id = u.auth_user_id
  WHERE u.auth_user_id = NEW.actioned_by
  LIMIT 1;

  -- Get document title
  SELECT dm.title INTO v_document_title
  FROM document_metadata dm
  WHERE dm.id = v_document_id
  LIMIT 1;

  -- Skip if no requester email
  IF v_requester_email IS NULL OR v_requester_email = '' THEN
    RAISE NOTICE 'No requester email found for workflow %', v_workflow_id;
    RETURN NEW;
  END IF;

  -- Get auth token for API calls
  SELECT token INTO v_auth_token 
  FROM api_tokens 
  WHERE environment = 'production' 
  ORDER BY created_at DESC 
  LIMIT 1;
  
  -- Use anon key as fallback
  IF v_auth_token IS NULL THEN
    v_auth_token := 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImRqdGppY2Fqbnh5c2xwbXltb3p4Iiwicm9sZSI6ImFub24iLCJpYXQiOjE3NTgyNzMyNTEsImV4cCI6MjA3Mzg0OTI1MX0.V98U9eJ6YT_UHH4Bxn4bu6t2NSw1OZeSLtYDmBk5S_s';
  END IF;

  v_function_url := 'https://djtjicajnxyslpmymozx.supabase.co/functions/v1/send-approval-notification';

  -- Call edge function
  PERFORM net.http_post(
    url := v_function_url,
    headers := jsonb_build_object(
      'Content-Type', 'application/json',
      'Authorization', 'Bearer ' || v_auth_token
    ),
    body := jsonb_build_object(
      'type', 'action_taken',
      'recipient_email', v_requester_email,
      'recipient_name', v_requester_name,
      'document_title', COALESCE(v_document_title, 'Untitled Document'),
      'document_id', v_document_id,
      'workflow_id', v_workflow_id,
      'workflow_name', v_workflow_name,
      'requester_name', v_requester_name,
      'requester_email', v_requester_email,
      'action', NEW.status::text,
      'actioner_name', v_actioner_name,
      'comments', NEW.comments
    )
  );

  RAISE NOTICE 'Approval action notification sent to %', v_requester_email;
  
  RETURN NEW;
EXCEPTION WHEN OTHERS THEN
  RAISE WARNING 'Error sending approval action notification: %', SQLERRM;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."notify_approval_action"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."notify_approval_action"() IS 'Sends email notification when an approval step is actioned (approved/rejected/forwarded)';



CREATE OR REPLACE FUNCTION "public"."notify_approval_request"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_approver_email TEXT;
  v_approver_name TEXT;
  v_requester_email TEXT;
  v_requester_name TEXT;
  v_document_title TEXT;
  v_step_id INTEGER;
  v_auth_token TEXT;
  v_function_url TEXT;
BEGIN
  -- Get approver details from first step
  SELECT 
    COALESCE(au.email, ''),
    COALESCE(u.username, 'User')
  INTO v_approver_email, v_approver_name
  FROM document_approval_steps das
  LEFT JOIN users u ON u.auth_user_id = das.approver_user_id
  LEFT JOIN auth.users au ON au.id = das.approver_user_id
  WHERE das.workflow_id = NEW.id
  AND das.step_number = 1
  LIMIT 1;

  -- Get step ID
  SELECT id INTO v_step_id
  FROM document_approval_steps
  WHERE workflow_id = NEW.id
  AND step_number = 1
  LIMIT 1;

  -- Get requester details
  SELECT 
    COALESCE(au.email, ''),
    COALESCE(u.username, 'Requester')
  INTO v_requester_email, v_requester_name
  FROM users u
  LEFT JOIN auth.users au ON au.id = u.auth_user_id
  WHERE u.auth_user_id = NEW.initiated_by
  LIMIT 1;

  -- Get document title
  SELECT dm.title INTO v_document_title
  FROM document_versions dv
  JOIN document_metadata dm ON dm.id = dv.document_id
  WHERE dv.id = NEW.document_version_id
  LIMIT 1;

  -- Skip if no approver email
  IF v_approver_email IS NULL OR v_approver_email = '' THEN
    RAISE NOTICE 'No approver email found for workflow %', NEW.id;
    RETURN NEW;
  END IF;

  -- Get auth token for API calls
  SELECT token INTO v_auth_token 
  FROM api_tokens 
  WHERE environment = 'production' 
  ORDER BY created_at DESC 
  LIMIT 1;
  
  -- Use anon key as fallback
  IF v_auth_token IS NULL THEN
    v_auth_token := 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImRqdGppY2Fqbnh5c2xwbXltb3p4Iiwicm9sZSI6ImFub24iLCJpYXQiOjE3NTgyNzMyNTEsImV4cCI6MjA3Mzg0OTI1MX0.V98U9eJ6YT_UHH4Bxn4bu6t2NSw1OZeSLtYDmBk5S_s';
  END IF;

  v_function_url := 'https://djtjicajnxyslpmymozx.supabase.co/functions/v1/send-approval-notification';

  -- Call edge function
  PERFORM net.http_post(
    url := v_function_url,
    headers := jsonb_build_object(
      'Content-Type', 'application/json',
      'Authorization', 'Bearer ' || v_auth_token
    ),
    body := jsonb_build_object(
      'type', 'approval_request',
      'recipient_email', v_approver_email,
      'recipient_name', v_approver_name,
      'document_title', COALESCE(v_document_title, 'Untitled Document'),
      'document_id', NEW.document_version_id,
      'workflow_id', NEW.id,
      'workflow_name', NEW.workflow_name,
      'requester_name', v_requester_name,
      'requester_email', v_requester_email,
      'step_id', v_step_id
    )
  );

  RAISE NOTICE 'Approval request notification sent to %', v_approver_email;
  
  RETURN NEW;
EXCEPTION WHEN OTHERS THEN
  RAISE WARNING 'Error sending approval request notification: %', SQLERRM;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."notify_approval_request"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."notify_approval_request"() IS 'Sends email notification when a new approval workflow is created';



CREATE OR REPLACE FUNCTION "public"."notify_handler_assignment"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_handler RECORD;
  v_company RECORD;
  v_handler_type RECORD;
  v_product RECORD;
  v_template RECORD;
  v_variables JSONB;
  v_handler_email TEXT;
  v_assigned_by_name TEXT;
  v_assigned_by_email TEXT;
BEGIN
  -- Only process new assignments
  IF TG_OP = 'INSERT' OR (TG_OP = 'UPDATE' AND OLD.handler_id IS DISTINCT FROM NEW.handler_id) THEN
    
    -- Get handler details with contact info
    SELECT 
      u.auth_user_id, 
      u.username, 
      u.contact_id,
      c.first_name,
      c.last_name,
      COALESCE(c.email1, c.email2, c.email3) as contact_email
    INTO v_handler
    FROM users u
    LEFT JOIN contacts c ON c.id = u.contact_id
    WHERE u.auth_user_id = NEW.handler_id;
    
    IF NOT FOUND THEN
      RETURN NEW;
    END IF;
    
    -- Get handler email (prefer contact email, fallback to auth.users)
    v_handler_email := v_handler.contact_email;
    
    IF v_handler_email IS NULL THEN
      SELECT email INTO v_handler_email
      FROM auth.users
      WHERE id = NEW.handler_id;
    END IF;
    
    -- Skip if no email found
    IF v_handler_email IS NULL THEN
      RETURN NEW;
    END IF;
    
    -- Get company details with location
    SELECT 
      co.id, 
      co.name,
      COALESCE(co.website1, co.website2, co.website3) as website,
      COALESCE(co.phone1, co.phone2, co.phone3) as phone,
      ci.city as city_name,
      cn.country as country_name,
      CONCAT_WS(', ', ci.city, cn.country) as location
    INTO v_company
    FROM companies co
    LEFT JOIN cities ci ON ci.id = co.city_id
    LEFT JOIN countries cn ON cn.id = co.country_id
    WHERE co.id = NEW.companyid;
    
    IF NOT FOUND THEN 
      RETURN NEW; 
    END IF;
    
    -- Get handler type
    SELECT id, handlertype INTO v_handler_type 
    FROM company_handler_types 
    WHERE id = NEW.handler_type_id;
    
    IF NOT FOUND THEN 
      RETURN NEW; 
    END IF;
    
    -- Get product
    SELECT id, name INTO v_product 
    FROM products 
    WHERE id = NEW.product_id;
    
    IF NOT FOUND THEN 
      RETURN NEW; 
    END IF;
    
    -- Get current user info for assigned_by
    SELECT u.username, au.email
    INTO v_assigned_by_name, v_assigned_by_email
    FROM users u
    LEFT JOIN auth.users au ON au.id = u.auth_user_id
    WHERE u.auth_user_id = auth.uid();
    
    -- Query system_email_templates with correct column names
    SELECT id, subject, html_body, text_body INTO v_template
    FROM system_email_templates
    WHERE template_code = 'HANDLER_ASSIGNMENT' AND is_active = true
    LIMIT 1;
    
    IF NOT FOUND THEN
      -- No active template, skip notification
      RETURN NEW;
    END IF;
    
    -- Build correct template variables matching the template
    v_variables := jsonb_build_object(
      'handler_first_name', COALESCE(v_handler.first_name, v_handler.username),
      'handler_last_name', COALESCE(v_handler.last_name, ''),
      'handler_email', v_handler_email,
      'company_name', v_company.name,
      'company_url', 'https://core.bncnetwork.net/databases/companies/' || v_company.id,
      'company_website', COALESCE(v_company.website, 'N/A'),
      'company_phone', COALESCE(v_company.phone, 'N/A'),
      'company_location', COALESCE(v_company.location, 'N/A'),
      'city_name', COALESCE(v_company.city_name, 'N/A'),
      'country_name', COALESCE(v_company.country_name, 'N/A'),
      'handler_type', v_handler_type.handlertype,
      'product_name', v_product.name,
      'assigned_by', COALESCE(v_assigned_by_name, 'System'),
      'assigned_by_email', COALESCE(v_assigned_by_email, ''),
      'assignment_date', to_char(now(), 'YYYY-MM-DD HH24:MI'),
      'current_year', to_char(now(), 'YYYY')
    );
    
    -- Queue email with rendered template
    INSERT INTO email_notification_queue (
      recipient_email,
      subject,
      html_body,
      text_body,
      template_id,
      template_code,
      variables,
      priority,
      scheduled_at,
      status
    ) VALUES (
      v_handler_email,
      replace_template_variables(v_template.subject, v_variables),
      replace_template_variables(v_template.html_body, v_variables),
      replace_template_variables(v_template.text_body, v_variables),
      v_template.id,
      'HANDLER_ASSIGNMENT',
      v_variables,
      'normal',
      now(),
      'pending'
    );
    
  END IF;
  
  RETURN NEW;
END;
$$;


