CREATE OR REPLACE FUNCTION "public"."populate_dataset_contacts"("p_dataset_id" integer) RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  dataset_criteria jsonb;
  v_where_clause text;
  v_has_ibis_filters boolean;
  v_has_sfs_filters boolean;
  v_join_clause text;
  v_query text;
  v_count integer;
BEGIN
  SELECT cd.criteria INTO dataset_criteria
  FROM public.campaign_datasets cd
  WHERE cd.id = p_dataset_id;

  IF dataset_criteria IS NULL THEN
    dataset_criteria := '{}'::jsonb;
  END IF;

  v_where_clause := public.build_criteria_where_clause(dataset_criteria);
  v_has_ibis_filters := public.has_ibis_filters(dataset_criteria);
  v_has_sfs_filters := public.has_sfs_filters(dataset_criteria);
  
  v_join_clause := 'LEFT JOIN public.companies comp ON c.company_id = comp.id';
  IF v_has_ibis_filters THEN
    v_join_clause := v_join_clause || ' LEFT JOIN public.ibisusers iu ON c.id = iu.prime_contact_id';
  END IF;
  IF v_has_sfs_filters THEN
    v_join_clause := v_join_clause || ' LEFT JOIN public.company_sfs csfs ON comp.id = csfs.company_id';
  END IF;

  DELETE FROM public.campaign_dataset_contacts WHERE campaign_dataset_id = p_dataset_id;

  v_query := format(
    'INSERT INTO public.campaign_dataset_contacts (campaign_dataset_id, contact_id, created_at, updated_at)
    SELECT DISTINCT %s, c.id, NOW(), NOW()
    FROM public.contacts c
    %s
    WHERE c.email1 IS NOT NULL 
      AND c.email1 <> ''''
      AND COALESCE(c.status, ''Active'') = ''Active''
      AND (%s)
    ON CONFLICT (campaign_dataset_id, contact_id) DO NOTHING',
    p_dataset_id,
    v_join_clause,
    v_where_clause
  );

  EXECUTE v_query;
  GET DIAGNOSTICS v_count = ROW_COUNT;

  RETURN v_count;
END;
$$;


ALTER FUNCTION "public"."populate_dataset_contacts"("p_dataset_id" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."populate_dataset_contacts"("p_dataset_id" integer, "p_criteria" "jsonb", "p_search_type" "text" DEFAULT 'contacts'::"text") RETURNS integer
    LANGUAGE "plpgsql"
    AS $$
DECLARE
  v_where_clause text;
  v_query text;
  v_count integer;
  v_has_ibis_filters boolean;
BEGIN
  -- Build the WHERE clause from criteria
  v_where_clause := public.build_criteria_where_clause(p_criteria);
  
  -- Check if we need to join ibisusers
  v_has_ibis_filters := public.has_ibis_filters(p_criteria);
  
  -- Delete existing contacts for this dataset
  DELETE FROM public.campaign_dataset_contacts WHERE campaign_dataset_id = p_dataset_id;
  
  -- Build and execute dynamic query
  v_query := format(
    'INSERT INTO public.campaign_dataset_contacts (campaign_dataset_id, contact_id)
     SELECT DISTINCT %L::integer, c.id
     FROM public.contacts c
     LEFT JOIN public.companies comp ON c.company_id = comp.id
     %s
     WHERE c.email1 IS NOT NULL 
       AND c.email1 != ''''
       AND COALESCE(c.status, ''Active'') = ''Active''
       AND (%s)',
    p_dataset_id,
    CASE WHEN v_has_ibis_filters THEN 'LEFT JOIN public.ibisusers iu ON c.id = iu.prime_contact_id' ELSE '' END,
    v_where_clause
  );
  
  EXECUTE v_query;
  
  GET DIAGNOSTICS v_count = ROW_COUNT;
  
  RETURN v_count;
END;
$$;


ALTER FUNCTION "public"."populate_dataset_contacts"("p_dataset_id" integer, "p_criteria" "jsonb", "p_search_type" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."process_approval_action"("p_workflow_id" integer, "p_step_id" integer, "p_action_type" character varying, "p_comments" "text" DEFAULT NULL::"text") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_current_step integer;
  v_total_steps integer;
  v_from_status text;
BEGIN
  SELECT current_step, total_steps, status
  INTO v_current_step, v_total_steps, v_from_status
  FROM document_approval_workflows
  WHERE id = p_workflow_id;
  
  UPDATE document_approval_steps
  SET 
    status = CASE 
      WHEN p_action_type = 'approve' THEN 'approved'
      WHEN p_action_type = 'reject' THEN 'rejected'
      ELSE 'pending'
    END,
    action_at = now(),
    action_by = auth.uid(),
    comments = p_comments
  WHERE id = p_step_id;
  
  INSERT INTO document_approval_history (
    workflow_id,
    step_id,
    action_type,
    action_by,
    action_at,
    from_status,
    to_status,
    comments
  ) VALUES (
    p_workflow_id,
    p_step_id,
    p_action_type,
    auth.uid(),
    now(),
    v_from_status::approval_status,
    CASE 
      WHEN p_action_type = 'approve' AND v_current_step = v_total_steps THEN 'approved'
      WHEN p_action_type = 'reject' THEN 'rejected'
      ELSE 'pending'
    END::approval_status,
    p_comments
  );
  
  IF p_action_type = 'reject' THEN
    UPDATE document_approval_workflows
    SET status = 'rejected', completed_at = now()
    WHERE id = p_workflow_id;
  ELSIF p_action_type = 'approve' AND v_current_step = v_total_steps THEN
    UPDATE document_approval_workflows
    SET status = 'approved', completed_at = now()
    WHERE id = p_workflow_id;
  ELSIF p_action_type = 'approve' THEN
    UPDATE document_approval_workflows
    SET current_step = v_current_step + 1
    WHERE id = p_workflow_id;
    
    UPDATE document_approval_steps
    SET status = 'pending'
    WHERE workflow_id = p_workflow_id AND step_number = v_current_step + 1;
  END IF;
  
  RETURN true;
END;
$$;


ALTER FUNCTION "public"."process_approval_action"("p_workflow_id" integer, "p_step_id" integer, "p_action_type" character varying, "p_comments" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."process_approval_action"("p_step_id" integer, "p_action" "public"."approval_step_status", "p_comments" "text" DEFAULT NULL::"text", "p_forward_to_user_id" "uuid" DEFAULT NULL::"uuid", "p_forward_reason" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_workflow_id INTEGER;
  v_strategy approval_strategy;
  v_current_status approval_step_status;
  v_workflow_status approval_workflow_status;
  v_result JSONB := '{}'::JSONB;
BEGIN
  -- Get workflow details
  SELECT 
    das.workflow_id,
    das.status,
    daw.approval_strategy,
    daw.status
  INTO 
    v_workflow_id,
    v_current_status,
    v_strategy,
    v_workflow_status
  FROM document_approval_steps das
  JOIN document_approval_workflows daw ON daw.id = das.workflow_id
  WHERE das.id = p_step_id;
  
  -- Validate workflow is still pending
  IF v_workflow_status != 'pending' THEN
    RAISE EXCEPTION 'Workflow is already completed with status: %', v_workflow_status;
  END IF;
  
  -- Validate current step is pending
  IF v_current_status NOT IN ('pending', 'reviewing') THEN
    RAISE EXCEPTION 'Step already processed with status: %', v_current_status;
  END IF;
  
  -- Handle FORWARD action
  IF p_action = 'reviewing' AND p_forward_to_user_id IS NOT NULL THEN
    UPDATE document_approval_steps
    SET 
      status = 'forwarded',
      forwarded_to_user_id = p_forward_to_user_id,
      forwarded_at = now(),
      forwarded_reason = p_forward_reason,
      actioned_by = auth.uid(),
      actioned_at = now()
    WHERE id = p_step_id;
    
    -- Create new step for forwarded approver
    INSERT INTO document_approval_steps (
      workflow_id,
      step_number,
      approver_user_id,
      status,
      comments
    )
    SELECT 
      workflow_id,
      (SELECT MAX(step_number) + 1 FROM document_approval_steps WHERE workflow_id = v_workflow_id),
      p_forward_to_user_id,
      'pending',
      'Forwarded from previous approver'
    FROM document_approval_steps
    WHERE id = p_step_id;
    
    -- Update total steps
    UPDATE document_approval_workflows
    SET total_steps = total_steps + 1
    WHERE id = v_workflow_id;
    
    v_result := jsonb_build_object('action', 'forwarded', 'workflow_status', 'pending');
    
  -- Handle APPROVE/REJECT actions
  ELSE
    UPDATE document_approval_steps
    SET 
      status = p_action,
      comments = p_comments,
      actioned_by = auth.uid(),
      actioned_at = now()
    WHERE id = p_step_id;
    
    -- Apply strategy logic
    IF v_strategy = 'any_can_decide' THEN
      -- Close all other pending steps
      UPDATE document_approval_steps
      SET 
        status = 'skipped',
        comments = 'Auto-closed: Another approver made decision',
        actioned_at = now()
      WHERE workflow_id = v_workflow_id
        AND id != p_step_id
        AND status = 'pending';
      
      -- Update workflow
      UPDATE document_approval_workflows
      SET 
        status = p_action::TEXT::approval_workflow_status,
        completed_at = now(),
        final_decision_by = auth.uid(),
        final_decision_at = now()
      WHERE id = v_workflow_id;
      
      v_result := jsonb_build_object(
        'action', p_action,
        'workflow_status', p_action,
        'auto_closed_others', true
      );
      
    ELSIF v_strategy IN ('all_must_approve', 'single_approver') THEN
      -- Check if all required steps are complete
      IF NOT EXISTS (
        SELECT 1 FROM document_approval_steps
        WHERE workflow_id = v_workflow_id
          AND status = 'pending'
          AND is_required = true
      ) THEN
        -- Determine final status
        IF EXISTS (
          SELECT 1 FROM document_approval_steps
          WHERE workflow_id = v_workflow_id
            AND status = 'rejected'
        ) THEN
          v_workflow_status := 'rejected';
        ELSE
          v_workflow_status := 'approved';
        END IF;
        
        UPDATE document_approval_workflows
        SET 
          status = v_workflow_status,
          completed_at = now(),
          final_decision_by = auth.uid(),
          final_decision_at = now()
        WHERE id = v_workflow_id;
        
        v_result := jsonb_build_object(
          'action', p_action,
          'workflow_status', v_workflow_status,
          'workflow_complete', true
        );
      ELSE
        v_result := jsonb_build_object(
          'action', p_action,
          'workflow_status', 'pending',
          'workflow_complete', false
        );
      END IF;
    END IF;
  END IF;
  
  -- Log to history
  INSERT INTO document_approval_history (
    workflow_id,
    step_id,
    action_type,
    action_by,
    to_status,
    comments
  ) VALUES (
    v_workflow_id,
    p_step_id,
    p_action::TEXT,
    auth.uid(),
    p_action,
    p_comments
  );
  
  RETURN v_result;
END;
$$;


ALTER FUNCTION "public"."process_approval_action"("p_step_id" integer, "p_action" "public"."approval_step_status", "p_comments" "text", "p_forward_to_user_id" "uuid", "p_forward_reason" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."process_scheduled_email_jobs"() RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
    job_record RECORD;
    current_time_only TIME;
    job_result JSONB;
    auth_token TEXT;
BEGIN
    current_time_only := CURRENT_TIME;
    
    -- Get auth token, fallback to anon key
    SELECT token INTO auth_token 
    FROM api_tokens 
    WHERE environment = 'production' 
    ORDER BY created_at DESC 
    LIMIT 1;
    
    IF auth_token IS NULL THEN
        auth_token := 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImRqdGppY2Fqbnh5c2xwbXltb3p4Iiwicm9sZSI6ImFub24iLCJpYXQiOjE3NTgyNzMyNTEsImV4cCI6MjA3Mzg0OTI1MX0.V98U9eJ6YT_UHH4Bxn4bu6t2NSw1OZeSLtYDmBk5S_s';
    END IF;
    
    -- Find jobs that are due with recipient_list_id check
    FOR job_record IN 
        SELECT id, window_start, window_end
        FROM email_jobs 
        WHERE status = 'scheduled' 
          AND scheduled_at <= NOW()
          AND recipient_list_id IS NOT NULL
          AND (
            (window_start IS NULL AND window_end IS NULL)
            OR (window_start IS NOT NULL AND window_end IS NOT NULL 
                AND current_time_only >= window_start 
                AND current_time_only <= window_end)
            OR (window_start IS NOT NULL AND window_end IS NULL 
                AND current_time_only >= window_start)
            OR (window_start IS NULL AND window_end IS NOT NULL 
                AND current_time_only <= window_end)
          )
        ORDER BY scheduled_at ASC
        LIMIT 10
        FOR UPDATE SKIP LOCKED
    LOOP
        -- Update status to processing
        UPDATE email_jobs 
        SET status = 'processing', updated_at = NOW()
        WHERE id = job_record.id AND status = 'scheduled';
        
        IF FOUND THEN
            -- Call the edge function to process the job
            BEGIN
                SELECT INTO job_result
                    net.http_post(
                        url := 'https://djtjicajnxyslpmymozx.supabase.co/functions/v1/process-email-jobs',
                        headers := jsonb_build_object(
                            'Content-Type', 'application/json',
                            'Authorization', 'Bearer ' || auth_token
                        ),
                        body := jsonb_build_object('jobId', job_record.id)
                    );
                    
                RAISE NOTICE 'Triggered process-email-jobs for job %', job_record.id;
            EXCEPTION WHEN OTHERS THEN
                -- If edge function call fails, reset job to scheduled
                UPDATE email_jobs 
                SET status = 'scheduled', updated_at = NOW()
                WHERE id = job_record.id;
                
                RAISE WARNING 'Failed to trigger edge function for job %: %', job_record.id, SQLERRM;
            END;
        END IF;
    END LOOP;
END;
$$;


ALTER FUNCTION "public"."process_scheduled_email_jobs"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."recalculate_renewal_status"("p_subscription_id" integer) RETURNS "text"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_company_id INTEGER;
  v_status TEXT;
  v_inv_no INTEGER;
  v_end_date DATE;
  v_extended_date DATE;
  v_new_status TEXT := 'not_yet_due';
BEGIN
  -- Fetch the subscription record
  SELECT company_id, status, inv_no,
         end_date::date, extended_date::date
    INTO v_company_id, v_status, v_inv_no, v_end_date, v_extended_date
    FROM subscriptions
   WHERE id = p_subscription_id;

  IF NOT FOUND THEN
    RETURN NULL;
  END IF;

  -- Priority 1: renewed (Inactive/Expired with successor subscription OR 'won' renewal quotation)
  IF v_status IN ('Inactive', 'Expired') THEN
    IF EXISTS (
      SELECT 1 FROM subscriptions s2
       WHERE s2.company_id = v_company_id
         AND s2.id != p_subscription_id
         AND s2.start_date > (SELECT start_date FROM subscriptions WHERE id = p_subscription_id)
    ) THEN
      v_new_status := 'renewed';
    ELSIF EXISTS (
      SELECT 1 FROM quotations q
       WHERE q.company_id = v_company_id
         AND q.quotation_type = 'renewal'
         AND q.status = 'won'
    ) THEN
      v_new_status := 'renewed';
    END IF;
  END IF;

  -- Priority 2: auto_renewal_in_progress
  IF v_new_status = 'not_yet_due' THEN
    IF EXISTS (
      SELECT 1 FROM pending_renewals pr
       WHERE pr.previous_subscription_id = p_subscription_id
         AND pr.status = 'Pending'
    ) THEN
      v_new_status := 'auto_renewal_in_progress';
    END IF;
  END IF;

  -- Priority 3: pending_activation (renewal invoice collected, sub not yet activated)
  IF v_new_status = 'not_yet_due' THEN
    IF EXISTS (
      SELECT 1 FROM invoices i
        JOIN quotations q ON q.id = i.quotation_id
       WHERE q.company_id = v_company_id
         AND q.quotation_type = 'renewal'
         AND i.status = 'Generated'
         AND i.collection_status = 'Collected'
         AND i.subscription_status = false
         AND (v_inv_no IS NULL OR i.id != v_inv_no)
    ) THEN
      v_new_status := 'pending_activation';
    END IF;
  END IF;

  -- Priority 4: pending_payment (renewal invoice exists, not collected)
  IF v_new_status = 'not_yet_due' THEN
    IF EXISTS (
      SELECT 1 FROM invoices i
        JOIN quotations q ON q.id = i.quotation_id
       WHERE q.company_id = v_company_id
         AND q.quotation_type = 'renewal'
         AND i.status = 'Generated'
         AND (i.collection_status IS NULL OR i.collection_status != 'Collected')
         AND (v_inv_no IS NULL OR i.id != v_inv_no)
    ) THEN
      v_new_status := 'pending_payment';
    END IF;
  END IF;

  -- Priority 5: invoiced
  IF v_new_status = 'not_yet_due' THEN
    IF EXISTS (
      SELECT 1 FROM quotations q
       WHERE q.company_id = v_company_id
         AND q.quotation_type = 'renewal'
         AND q.status = 'invoiced'
    ) THEN
      v_new_status := 'invoiced';
    END IF;
  END IF;

  -- Priority 6: proforma_generated
  IF v_new_status = 'not_yet_due' THEN
    IF EXISTS (
      SELECT 1 FROM quotations q
       WHERE q.company_id = v_company_id
         AND q.quotation_type = 'renewal'
         AND q.status = 'proforma_invoiced'
    ) THEN
      v_new_status := 'proforma_generated';
    END IF;
  END IF;

  -- Priority 7: quoted
  IF v_new_status = 'not_yet_due' THEN
    IF EXISTS (
      SELECT 1 FROM quotations q
       WHERE q.company_id = v_company_id
         AND q.quotation_type = 'renewal'
         AND q.status = 'under_follow_up'
    ) THEN
      v_new_status := 'quoted';
    END IF;
  END IF;

  -- Priority 8: due_for_renewal (Active, within 90 days, no renewal quotation)
  IF v_new_status = 'not_yet_due' AND v_status = 'Active' THEN
    IF COALESCE(v_extended_date, v_end_date) <= (CURRENT_DATE + INTERVAL '90 days') THEN
      IF NOT EXISTS (
        SELECT 1 FROM quotations q
         WHERE q.company_id = v_company_id
           AND q.quotation_type = 'renewal'
           AND q.status NOT IN ('void', 'lost')
      ) THEN
        v_new_status := 'due_for_renewal';
      END IF;
    END IF;
  END IF;

  -- Priority 9: churned (Inactive/Expired, no successor, no open commercial activity)
  IF v_new_status = 'not_yet_due' AND v_status IN ('Inactive', 'Expired') THEN
    v_new_status := 'churned';
  END IF;

  -- Update the subscription
  UPDATE subscriptions
     SET renewal_status = v_new_status
   WHERE id = p_subscription_id;

  RETURN v_new_status;
END;
$$;


ALTER FUNCTION "public"."recalculate_renewal_status"("p_subscription_id" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."refresh_company_handler_sender_cache"("p_product_id" integer) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  deleted_count integer;
  inserted_count integer;
BEGIN
  -- Delete existing cache entries for this product
  DELETE FROM company_handler_sender_cache WHERE product_id = p_product_id;
  GET DIAGNOSTICS deleted_count = ROW_COUNT;
  
  -- Insert fresh cache entries from company_handlers joined with users and contacts
  INSERT INTO company_handler_sender_cache 
    (company_id, handler_type_id, handler_id, from_name, from_email, product_id)
  SELECT 
    ch.companyid,
    ch.handler_type_id,
    ch.handler_id,
    TRIM(CONCAT(c.first_name, ' ', COALESCE(c.last_name, ''))) as from_name,
    COALESCE(c.email1, c.email2) as from_email,
    ch.product_id
  FROM company_handlers ch
  JOIN users u ON u.auth_user_id = ch.handler_id
  JOIN contacts c ON c.id = u.contact_id
  WHERE ch.product_id = p_product_id
    AND ch.handler_id IS NOT NULL
    AND COALESCE(c.email1, c.email2) IS NOT NULL
    AND COALESCE(c.email1, c.email2) != '';
  
  GET DIAGNOSTICS inserted_count = ROW_COUNT;
  
  RETURN jsonb_build_object(
    'success', true,
    'deleted_count', deleted_count,
    'inserted_count', inserted_count,
    'product_id', p_product_id
  );
END;
$$;


ALTER FUNCTION "public"."refresh_company_handler_sender_cache"("p_product_id" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."replace_template_variables"("p_template" "text", "p_variables" "jsonb") RETURNS "text"
    LANGUAGE "plpgsql"
    AS $$
DECLARE
  v_result TEXT := p_template;
  v_key TEXT;
  v_value TEXT;
BEGIN
  IF p_template IS NULL THEN
    RETURN NULL;
  END IF;
  
  IF p_variables IS NULL THEN
    RETURN p_template;
  END IF;
  
  -- Replace each variable in the template
  FOR v_key, v_value IN SELECT * FROM jsonb_each_text(p_variables)
  LOOP
    v_result := REPLACE(v_result, '{{' || v_key || '}}', COALESCE(v_value, ''));
  END LOOP;
  
  RETURN v_result;
END;
$$;


ALTER FUNCTION "public"."replace_template_variables"("p_template" "text", "p_variables" "jsonb") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."reserve_quotation_reference"("p_company_id" bigint, "p_created_by" "uuid", "p_currency" "text" DEFAULT 'AED'::"text", "p_revision_number" integer DEFAULT 0, "p_revised_from_id" bigint DEFAULT NULL::bigint) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_company_status text;
  v_company_name text;
  v_quotation_id bigint;
  v_reference_number text;
  v_year text;
BEGIN
  -- Check company status first
  SELECT status, name INTO v_company_status, v_company_name 
  FROM companies 
  WHERE id = p_company_id;

  IF v_company_status IS NULL THEN
    RAISE EXCEPTION 'Company with ID % not found', p_company_id;
  END IF;

  IF v_company_status IS DISTINCT FROM 'Active' THEN
    RAISE EXCEPTION 'Cannot create quotation for inactive company: %', v_company_name;
  END IF;

  -- Get current year (last 2 digits)
  v_year := RIGHT(EXTRACT(YEAR FROM NOW())::TEXT, 2);
  
  -- Insert quotation record with 'under_follow_up' status (changed from 'draft')
  INSERT INTO quotations (
    company_id,
    quotation_date,
    currency,
    status,
    created_by,
    revised_from_id,
    revision_number,
    reference_number
  ) VALUES (
    p_company_id,
    CURRENT_DATE,
    p_currency,
    'under_follow_up',  -- Changed from 'draft'
    p_created_by,
    p_revised_from_id,
    p_revision_number,
    'PENDING'
  )
  RETURNING id INTO v_quotation_id;
  
  -- Generate the reference number using the reserved ID
  IF p_revision_number = 0 THEN
    v_reference_number := 'SLS-PRP-001-' || v_quotation_id::TEXT || '-' || v_year;
  ELSE
    v_reference_number := 'SLS-PRP-001-' || v_quotation_id::TEXT || '-' || v_year || '-REV-' || p_revision_number::TEXT;
  END IF;
  
  -- Update the record with the generated reference number
  UPDATE quotations 
  SET reference_number = v_reference_number
  WHERE id = v_quotation_id;
  
  RETURN jsonb_build_object(
    'quotation_id', v_quotation_id,
    'reference_number', v_reference_number,
    'reserved_at', NOW()
  );
END;
$$;


ALTER FUNCTION "public"."reserve_quotation_reference"("p_company_id" bigint, "p_created_by" "uuid", "p_currency" "text", "p_revision_number" integer, "p_revised_from_id" bigint) OWNER TO "postgres";


