CREATE OR REPLACE FUNCTION "public"."search_companies_by_ids"("p_company_ids" integer[], "p_status" "text" DEFAULT NULL::"text", "p_search" "text" DEFAULT NULL::"text", "p_page" integer DEFAULT 1, "p_page_size" integer DEFAULT 20) RETURNS TABLE("company_id" integer, "total_count" bigint)
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  WITH filtered AS (
    SELECT c.id
    FROM companies c
    WHERE c.id = ANY(p_company_ids)
      AND (p_status IS NULL OR c.status = p_status)
      AND (p_search IS NULL OR c.name ILIKE '%' || p_search || '%')
  ),
  cnt AS (
    SELECT count(*) AS total FROM filtered
  )
  SELECT f.id AS company_id, cnt.total AS total_count
  FROM filtered f, cnt
  ORDER BY f.id
  LIMIT p_page_size
  OFFSET (p_page - 1) * p_page_size;
$$;


ALTER FUNCTION "public"."search_companies_by_ids"("p_company_ids" integer[], "p_status" "text", "p_search" "text", "p_page" integer, "p_page_size" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."search_companies_by_lead_domain"("p_email" "text", "p_limit" integer DEFAULT 10) RETURNS TABLE("id" integer, "name" character varying, "status" character varying, "email1" character varying, "email2" character varying, "email3" character varying, "website1" "text", "website2" "text", "website3" "text", "address" character varying, "city" character varying, "country" character varying, "company_type" character varying, "match_type" "text", "match_score" double precision)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_domain text;
  v_domain_pattern text;
BEGIN
  -- Extract domain from email (everything after @)
  v_domain := lower(split_part(p_email, '@', 2));
  
  -- Skip if no valid domain
  IF v_domain IS NULL OR v_domain = '' THEN
    RETURN;
  END IF;
  
  -- Create pattern for matching (e.g., '%technomak.com%')
  v_domain_pattern := '%' || v_domain || '%';
  
  RETURN QUERY
  WITH email_matches AS (
    SELECT 
      c.id,
      c.name,
      c.status,
      c.email1,
      c.email2,
      c.email3,
      c.website1,
      c.website2,
      c.website3,
      c.address,
      ci.city,
      co.country,
      ct.type as company_type,
      'email_domain'::text as match_type,
      CASE 
        WHEN lower(c.email1) LIKE v_domain_pattern THEN 1.0
        WHEN lower(c.email2) LIKE v_domain_pattern THEN 0.9
        WHEN lower(c.email3) LIKE v_domain_pattern THEN 0.8
        ELSE 0.0
      END::double precision as match_score
    FROM companies c
    LEFT JOIN cities ci ON c.city_id = ci.id
    LEFT JOIN countries co ON co.id = COALESCE(c.country_id, ci.country_id)
    LEFT JOIN companytypes ct ON c.companytype_id = ct.id
    WHERE 
      lower(c.email1) LIKE v_domain_pattern
      OR lower(c.email2) LIKE v_domain_pattern
      OR lower(c.email3) LIKE v_domain_pattern
  ),
  website_matches AS (
    SELECT 
      c.id,
      c.name,
      c.status,
      c.email1,
      c.email2,
      c.email3,
      c.website1,
      c.website2,
      c.website3,
      c.address,
      ci.city,
      co.country,
      ct.type as company_type,
      'website_domain'::text as match_type,
      CASE 
        WHEN lower(c.website1) LIKE v_domain_pattern THEN 0.7
        WHEN lower(c.website2) LIKE v_domain_pattern THEN 0.6
        WHEN lower(c.website3) LIKE v_domain_pattern THEN 0.5
        ELSE 0.0
      END::double precision as match_score
    FROM companies c
    LEFT JOIN cities ci ON c.city_id = ci.id
    LEFT JOIN countries co ON co.id = COALESCE(c.country_id, ci.country_id)
    LEFT JOIN companytypes ct ON c.companytype_id = ct.id
    WHERE 
      (lower(c.website1) LIKE v_domain_pattern
       OR lower(c.website2) LIKE v_domain_pattern
       OR lower(c.website3) LIKE v_domain_pattern)
      AND c.id NOT IN (SELECT em.id FROM email_matches em)
  ),
  all_matches AS (
    SELECT * FROM email_matches
    UNION ALL
    SELECT * FROM website_matches
  )
  SELECT * FROM all_matches
  ORDER BY match_score DESC, all_matches.id
  LIMIT p_limit;
END;
$$;


ALTER FUNCTION "public"."search_companies_by_lead_domain"("p_email" "text", "p_limit" integer) OWNER TO "postgres";


