CREATE OR REPLACE FUNCTION "public"."toggle_cron_job"("p_job_id" bigint, "p_active" boolean) RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'cron'
    AS $$
BEGIN
  -- Use cron.alter_job which is the proper pg_cron API
  PERFORM cron.alter_job(p_job_id, active := p_active);
  RETURN true;
EXCEPTION WHEN OTHERS THEN
  -- Fallback: direct update
  UPDATE cron.job
  SET active = p_active
  WHERE jobid = p_job_id;
  RETURN FOUND;
END;
$$;


