CREATE OR REPLACE FUNCTION "public"."trigger_account_review_queue_processor"() RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  supabase_url text;
  service_role_key text;
BEGIN
  -- Get the Supabase URL and service role key from config
  SELECT decrypted_secret INTO supabase_url 
  FROM vault.decrypted_secrets 
  WHERE name = 'supabase_url' 
  LIMIT 1;
  
  SELECT decrypted_secret INTO service_role_key 
  FROM vault.decrypted_secrets 
  WHERE name = 'supabase_service_role_key' 
  LIMIT 1;
  
  -- Fallback to hardcoded URL if vault secrets not available
  IF supabase_url IS NULL THEN
    supabase_url := 'https://djtjicajnxyslpmymozx.supabase.co';
  END IF;
  
  -- Make HTTP POST request to the edge function
  PERFORM net.http_post(
    url := supabase_url || '/functions/v1/account-review-queue-processor',
    headers := jsonb_build_object(
      'Content-Type', 'application/json',
      'Authorization', 'Bearer ' || COALESCE(service_role_key, current_setting('app.settings.service_role_key', true))
    ),
    body := '{}'::jsonb
  );
  
  RAISE NOTICE 'Triggered account-review-queue-processor';
END;
$$;


ALTER FUNCTION "public"."trigger_account_review_queue_processor"() OWNER TO "postgres";


