CREATE OR REPLACE FUNCTION "public"."update_batch_progress"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  -- Only process if batch_id is set and status changed to completed or failed
  IF NEW.batch_id IS NOT NULL AND OLD.status != NEW.status THEN
    IF NEW.status = 'completed' THEN
      UPDATE account_review_batches 
      SET 
        completed_count = completed_count + 1,
        status = CASE 
          WHEN completed_count + failed_count + 1 >= total_companies THEN 
            CASE WHEN failed_count > 0 THEN 'partial' ELSE 'completed' END
          ELSE 'processing' 
        END,
        started_at = COALESCE(started_at, now()),
        completed_at = CASE 
          WHEN completed_count + failed_count + 1 >= total_companies THEN now()
          ELSE completed_at 
        END
      WHERE id = NEW.batch_id;
    ELSIF NEW.status = 'failed' THEN
      UPDATE account_review_batches 
      SET 
        failed_count = failed_count + 1,
        status = CASE 
          WHEN completed_count + failed_count + 1 >= total_companies THEN 
            CASE WHEN completed_count > 0 THEN 'partial' ELSE 'failed' END
          ELSE 'processing' 
        END,
        started_at = COALESCE(started_at, now()),
        completed_at = CASE 
          WHEN completed_count + failed_count + 1 >= total_companies THEN now()
          ELSE completed_at 
        END
      WHERE id = NEW.batch_id;
    ELSIF NEW.status = 'processing' AND OLD.status = 'pending' THEN
      -- Mark batch as processing when first item starts
      UPDATE account_review_batches 
      SET status = 'processing', started_at = COALESCE(started_at, now())
      WHERE id = NEW.batch_id AND status = 'pending';
    END IF;
  END IF;
  
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."update_batch_progress"() OWNER TO "postgres";


