CREATE OR REPLACE FUNCTION "public"."update_invoice_collection_status"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_invoice_id BIGINT;
  v_total_collected NUMERIC;
  v_invoice_amount NUMERIC;
  v_new_status TEXT;
BEGIN
  -- Get the invoice_id depending on operation
  IF TG_OP = 'DELETE' THEN
    v_invoice_id := OLD.invoice_id;
  ELSE
    v_invoice_id := NEW.invoice_id;
  END IF;
  
  -- Skip if invoice_id is null
  IF v_invoice_id IS NULL THEN
    RETURN COALESCE(NEW, OLD);
  END IF;
  
  -- Calculate total collected from Completed collections
  SELECT COALESCE(SUM(amount), 0)
  INTO v_total_collected
  FROM public.invoice_collections
  WHERE invoice_id = v_invoice_id
    AND status = 'Completed';
  
  -- Get invoice amount
  SELECT amount INTO v_invoice_amount
  FROM public.invoices WHERE id = v_invoice_id;
  
  -- Skip if invoice not found
  IF v_invoice_amount IS NULL THEN
    RETURN COALESCE(NEW, OLD);
  END IF;
  
  -- Determine collection status
  IF v_total_collected >= v_invoice_amount THEN
    v_new_status := 'Completed';
  ELSE
    v_new_status := 'Pending';
  END IF;
  
  -- Update the invoice collection_status
  UPDATE public.invoices
  SET collection_status = v_new_status,
      updated_at = NOW()
  WHERE id = v_invoice_id;
  
  RETURN COALESCE(NEW, OLD);
END;
$$;


ALTER FUNCTION "public"."update_invoice_collection_status"() OWNER TO "postgres";


