CREATE OR REPLACE FUNCTION "public"."update_sales_manager_on_mp_task_insert"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  -- Check if this is an MP task (taskid = 8) with required fields
  IF NEW.taskid = 8 
     AND NEW.companyid IS NOT NULL 
     AND NEW.product_id IS NOT NULL 
     AND NEW.taskowner IS NOT NULL THEN
    
    -- Check if Sales Manager (handler_type_id = 3) already exists for this company-product
    IF NOT EXISTS (
      SELECT 1 
      FROM public.company_handlers 
      WHERE companyid = NEW.companyid 
        AND product_id = NEW.product_id 
        AND handler_type_id = 3
    ) THEN
      -- Insert Sales Manager into company_handlers
      INSERT INTO public.company_handlers (
        companyid,
        product_id,
        handler_type_id,
        handler_id,
        entered_by,
        updated_by,
        entered_on,
        updated_on
      ) VALUES (
        NEW.companyid,
        NEW.product_id,
        3, -- Sales Manager handler type
        NEW.taskowner,
        NEW.taskowner,
        NEW.taskowner,
        now(),
        now()
      );
      
      RAISE NOTICE 'Sales Manager assigned: company_id=%, product_id=%, handler_id=%', 
        NEW.companyid, NEW.product_id, NEW.taskowner;
    ELSE
      RAISE NOTICE 'Sales Manager already exists for company_id=%, product_id=%', 
        NEW.companyid, NEW.product_id;
    END IF;
  END IF;
  
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."update_sales_manager_on_mp_task_insert"() OWNER TO "postgres";


