CREATE OR REPLACE FUNCTION "public"."update_sfs_on_handler_insert"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  sales_manager_handler_type_id INTEGER := 3; -- Sales Manager handler type
  prospect_sfs_id INTEGER := 3; -- Prospect SFS
  current_sfs_id INTEGER;
BEGIN
  -- Only proceed if the handler being added is a Sales Manager (handler_type_id = 3)
  IF NEW.handler_type_id = sales_manager_handler_type_id THEN
    
    -- Get current SFS for this company-product combination
    SELECT sfsid INTO current_sfs_id
    FROM public.company_sfs
    WHERE companyid = NEW.companyid
      AND productid = NEW.product_id;
    
    -- Check if SFS needs to be updated to Prospect
    -- Update if current SFS is NOT: Prospect(3), Proposal(4), Customer(5), Sub-Customer(9)
    IF current_sfs_id IS NULL THEN
      -- No SFS record exists, create one as Prospect
      INSERT INTO public.company_sfs (
        companyid,
        productid,
        sfsid,
        enteredby,
        enteredon,
        updatedby,
        updatedon
      ) VALUES (
        NEW.companyid,
        NEW.product_id,
        prospect_sfs_id,
        NEW.entered_by,
        now(),
        NEW.entered_by,
        now()
      );
      
      RAISE NOTICE 'Created new Prospect SFS for company % product %', NEW.companyid, NEW.product_id;
      
    ELSIF current_sfs_id NOT IN (3, 4, 5, 9) THEN
      -- SFS exists but is Stranger(1), Target(2), Out Of Funnel(6), Alien(7), or OOF Pending(8)
      -- Update to Prospect
      UPDATE public.company_sfs
      SET sfsid = prospect_sfs_id,
          updatedby = NEW.entered_by,
          updatedon = now()
      WHERE companyid = NEW.companyid
        AND productid = NEW.product_id;
      
      RAISE NOTICE 'Updated SFS to Prospect for company % product % (previous SFS: %)', NEW.companyid, NEW.product_id, current_sfs_id;
    ELSE
      RAISE NOTICE 'SFS already at advanced stage (%) for company % product %, no update needed', current_sfs_id, NEW.companyid, NEW.product_id;
    END IF;
  END IF;
  
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."update_sfs_on_handler_insert"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."update_sfs_on_handler_insert"() IS 'Automatically updates company SFS to Prospect when a Sales Manager handler is added, if SFS is not already at Prospect, Proposal, Customer, or Sub-Customer stage';



