CREATE OR REPLACE FUNCTION "public"."update_workflow_status_on_step_change"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_total_steps INTEGER;
  v_approved_steps INTEGER;
  v_rejected_steps INTEGER;
  v_pending_steps INTEGER;
  v_new_status approval_workflow_status;
  v_workflow_id INTEGER;
BEGIN
  -- Get the workflow_id from the step
  v_workflow_id := NEW.workflow_id;
  
  -- Count step statuses for this workflow
  SELECT 
    COUNT(*),
    COUNT(*) FILTER (WHERE status = 'approved'),
    COUNT(*) FILTER (WHERE status = 'rejected'),
    COUNT(*) FILTER (WHERE status IN ('pending', 'reviewing'))
  INTO 
    v_total_steps,
    v_approved_steps,
    v_rejected_steps,
    v_pending_steps
  FROM document_approval_steps
  WHERE workflow_id = v_workflow_id;
  
  -- Determine new workflow status
  IF v_rejected_steps > 0 THEN
    -- Any rejection fails the workflow
    v_new_status := 'rejected'::approval_workflow_status;
  ELSIF v_approved_steps = v_total_steps THEN
    -- All steps approved
    v_new_status := 'approved'::approval_workflow_status;
  ELSIF v_pending_steps = 0 AND v_approved_steps > 0 THEN
    -- No pending steps, some approved (rest might be skipped/forwarded)
    v_new_status := 'reviewed'::approval_workflow_status;
  ELSE
    -- Still has pending steps
    v_new_status := 'pending'::approval_workflow_status;
  END IF;
  
  -- Update the workflow
  UPDATE document_approval_workflows
  SET 
    status = v_new_status,
    completed_at = CASE 
      WHEN v_new_status IN ('approved', 'rejected') THEN NOW()
      ELSE completed_at
    END,
    final_decision_by = CASE 
      WHEN v_new_status IN ('approved', 'rejected') THEN NEW.actioned_by
      ELSE final_decision_by
    END,
    final_decision_at = CASE 
      WHEN v_new_status IN ('approved', 'rejected') THEN NOW()
      ELSE final_decision_at
    END
  WHERE id = v_workflow_id;
  
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."update_workflow_status_on_step_change"() OWNER TO "postgres";


