CREATE OR REPLACE FUNCTION "public"."validate_document_contact"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_contact_company_id INTEGER;
BEGIN
  -- Case 1: Both contact and company are provided
  IF NEW.contact_id IS NOT NULL AND NEW.company_id IS NOT NULL THEN
    -- Validate contact belongs to company
    SELECT company_id INTO v_contact_company_id
    FROM contacts
    WHERE id = NEW.contact_id;
    
    IF v_contact_company_id IS NULL THEN
      RAISE EXCEPTION 'Contact ID % not found', NEW.contact_id;
    END IF;
    
    IF v_contact_company_id != NEW.company_id THEN
      RAISE EXCEPTION 'Contact (ID: %) does not belong to Company (ID: %). Contact belongs to Company ID: %',
        NEW.contact_id, NEW.company_id, v_contact_company_id;
    END IF;
  END IF;
  
  -- Case 2: Contact provided but company is NULL - Auto-populate company
  IF NEW.contact_id IS NOT NULL AND NEW.company_id IS NULL THEN
    SELECT company_id INTO NEW.company_id
    FROM contacts
    WHERE id = NEW.contact_id;
    
    IF NEW.company_id IS NULL THEN
      RAISE WARNING 'Contact ID % has no associated company', NEW.contact_id;
    END IF;
  END IF;
  
  -- Case 3: Inbound documents MUST have company (already enforced by CHECK constraint, but double-check)
  IF NEW.flow_direction = 'inbound' AND NEW.company_id IS NULL THEN
    RAISE EXCEPTION 'Inbound documents must have a company assigned';
  END IF;
  
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."validate_document_contact"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."validate_document_contact"() IS 'Validates contact-company relationship and auto-populates company from contact';



CREATE OR REPLACE FUNCTION "public"."validate_engagement_segments"("segments" "text") RETURNS boolean
    LANGUAGE "plpgsql" IMMUTABLE
    SET "search_path" TO 'public'
    AS $$
DECLARE
  segment text;
  valid_segments text[] := ARRAY['not_clicked', 'opened_not_clicked', 'opened_clicked', 'delivered_not_opened'];
BEGIN
  -- Handle null or empty string
  IF segments IS NULL OR segments = '' THEN
    RETURN false;
  END IF;
  
  -- Split by comma and validate each segment
  FOREACH segment IN ARRAY string_to_array(segments, ',')
  LOOP
    IF NOT (trim(segment) = ANY(valid_segments)) THEN
      RETURN false;
    END IF;
  END LOOP;
  
  RETURN true;
END;
$$;


ALTER FUNCTION "public"."validate_engagement_segments"("segments" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."validate_invitation_status"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
BEGIN
  IF NEW.invitation_status NOT IN ('shortlisted', 'invited', 'pending', 'accepted', 'declined', 'tentative', 'attended', 'no_show') THEN
    RAISE EXCEPTION 'Invalid invitation_status. Must be one of: shortlisted, invited, pending, accepted, declined, tentative, attended, no_show';
  END IF;
  RETURN NEW;
END;
$$;


