CREATE OR REPLACE VIEW "public"."campaigns_enriched" AS
 SELECT "c"."id",
    "c"."product_id",
    "c"."name",
    "c"."description",
    "c"."owner_id",
    "c"."start_date",
    "c"."end_date",
    "c"."status",
    "c"."created_at",
    "c"."updated_at",
    "c"."created_by",
    "c"."updated_by",
    "c"."code",
    "p"."name" AS "product_name",
    COALESCE(TRIM(BOTH FROM "concat"("cont"."first_name", ' ', "cont"."last_name")), "u"."username") AS "owner_name",
    ( SELECT ("count"(*))::integer AS "count"
           FROM "public"."subcampaigns" "s"
          WHERE ("s"."campaign_id" = "c"."id")) AS "subcampaigns_count"
   FROM ((("public"."campaigns" "c"
     LEFT JOIN "public"."products" "p" ON (("c"."product_id" = "p"."id")))
     LEFT JOIN "public"."users" "u" ON (("c"."owner_id" = "u"."auth_user_id")))
     LEFT JOIN "public"."contacts" "cont" ON (("u"."contact_id" = "cont"."id")));


