CREATE TABLE IF NOT EXISTS "public"."company_credit_ledger" (
    "id" bigint NOT NULL,
    "company_id" integer NOT NULL,
    "transaction_type" "text" NOT NULL,
    "amount" numeric NOT NULL,
    "currency" "text" DEFAULT 'AED'::"text" NOT NULL,
    "balance_after" numeric NOT NULL,
    "source_type" "text",
    "subscription_id" integer,
    "quotation_id" bigint,
    "proforma_id" bigint,
    "invoice_id" bigint,
    "original_subscription_value" numeric,
    "days_total" integer,
    "days_remaining" integer,
    "calculation_date" "date",
    "notes" "text",
    "created_by" "uuid" NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "company_credit_ledger_amount_check" CHECK (("amount" >= (0)::numeric)),
    CONSTRAINT "company_credit_ledger_transaction_type_check" CHECK (("transaction_type" = ANY (ARRAY['credit'::"text", 'debit'::"text"])))
);


ALTER TABLE "public"."company_credit_ledger" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."company_credit_balance" AS
 SELECT "company_id",
    "currency",
    COALESCE(( SELECT "cl2"."balance_after"
           FROM "public"."company_credit_ledger" "cl2"
          WHERE (("cl2"."company_id" = "cl"."company_id") AND ("cl2"."currency" = "cl"."currency"))
          ORDER BY "cl2"."created_at" DESC, "cl2"."id" DESC
         LIMIT 1), (0)::numeric) AS "current_balance",
    "max"("created_at") AS "last_transaction_date"
   FROM "public"."company_credit_ledger" "cl"
  GROUP BY "company_id", "currency";


ALTER VIEW "public"."company_credit_balance" OWNER TO "postgres";


