COMMENT ON COLUMN "public"."leads2"."linkedby" IS 'User who verified/linked this lead';



COMMENT ON COLUMN "public"."leads2"."linkedon" IS 'When this lead was verified/linked';



COMMENT ON COLUMN "public"."leads2"."ibis_lead_id" IS 'Legacy IBIS system lead ID';



COMMENT ON COLUMN "public"."leads2"."notes" IS 'Verification notes, match information, etc.';



COMMENT ON COLUMN "public"."leads2"."linked_contact_id" IS 'Contact ID when lead is linked to a specific contact';



COMMENT ON COLUMN "public"."leads2"."linked_contact_by" IS 'User who linked the contact to this lead';



COMMENT ON COLUMN "public"."leads2"."linked_contact_on" IS 'Timestamp when contact was linked to this lead';



