CREATE TABLE IF NOT EXISTS "public"."quotations" (
    "id" bigint NOT NULL,
    "company_id" integer NOT NULL,
    "contact_id" integer,
    "reference_number" "text",
    "quotation_date" "date" NOT NULL,
    "currency" "text" DEFAULT 'USD'::"text" NOT NULL,
    "exchange_rate" numeric(12,6),
    "terms_conditions" "text",
    "proposal_validity" "text",
    "early_termination_fee" numeric(5,2),
    "pdf_url" "text",
    "payment_plan" "text" DEFAULT 'Upfront'::"text" NOT NULL,
    "created_by" "uuid" NOT NULL,
    "updated_by" "uuid",
    "approved_by" "uuid",
    "approved_at" timestamp with time zone,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "status" "public"."quotation_status" DEFAULT 'under_follow_up'::"public"."quotation_status" NOT NULL,
    "syg_quotationid" integer,
    "lost_reasons" "text"[],
    "lost_sub_reasons" "text"[],
    "lost_notes" "text",
    "status_updated_by" "uuid",
    "status_updated_at" timestamp with time zone,
    "quotation_type" "public"."quotation_type" DEFAULT 'new'::"public"."quotation_type" NOT NULL,
    "is_locked" boolean DEFAULT false,
    "percentage" integer,
    "number_of_payments" integer DEFAULT 1,
    "payment1_percentage" numeric DEFAULT 100,
    "payment2_percentage" numeric DEFAULT 0,
    "payment3_percentage" numeric DEFAULT 0,
    "payment2_date" "date",
    "payment3_date" "date",
    "approval_status" character varying(20) DEFAULT NULL::character varying,
    "approval_notes" "text",
    "submitted_for_approval_at" timestamp with time zone,
    "submitted_by" "uuid",
    "revised_from_id" bigint,
    "revision_number" integer DEFAULT 1,
    "requires_approval" boolean DEFAULT false,
    "sent_status" "text" DEFAULT 'unsent'::"text",
    "sent_at" timestamp with time zone,
    "sent_by" "text",
    "is_auto_generated" boolean DEFAULT false,
    "auto_generated_source" "text",
    "void_notes" "text",
    "void_reason" "text",
    "voided_at" timestamp with time zone,
    "voided_by" "uuid",
    CONSTRAINT "chk_quotations_currency" CHECK (("currency" = ANY (ARRAY['AED'::"text", 'USD'::"text"]))),
    CONSTRAINT "quotations_approval_status_check" CHECK ((("approval_status" IS NULL) OR (("approval_status")::"text" = ANY (ARRAY[('pending'::character varying)::"text", ('approved'::character varying)::"text", ('rejected'::character varying)::"text"]))))
);


ALTER TABLE "public"."quotations" OWNER TO "postgres";


COMMENT ON COLUMN "public"."quotations"."quotation_type" IS 'Type of quotation: new (first time), renewal (subscription renewal), or upgrade (existing service upgrade)';



COMMENT ON COLUMN "public"."quotations"."is_locked" IS 'Locks the quotation after proforma invoice generation to prevent further modifications';



COMMENT ON COLUMN "public"."quotations"."percentage" IS 'Win probability or completion percentage (set to 95 when proforma is generated as per SP logic)';



COMMENT ON COLUMN "public"."quotations"."revised_from_id" IS 'Reference to the original quotation that was revised';



COMMENT ON COLUMN "public"."quotations"."revision_number" IS 'Revision number, starts at 1 for original quotations';



COMMENT ON COLUMN "public"."quotations"."requires_approval" IS 'True if quotation needs admin approval due to special terms/discounts';



CREATE SEQUENCE IF NOT EXISTS "public"."quotations_id_seq"
    START WITH 1
    INCREMENT BY 1
    NO MINVALUE
    NO MAXVALUE
    CACHE 1;


ALTER SEQUENCE "public"."quotations_id_seq" OWNER TO "postgres";


ALTER SEQUENCE "public"."quotations_id_seq" OWNED BY "public"."quotations"."id";



