CREATE OR REPLACE VIEW "public"."tasklist_enriched" AS
 SELECT "tl"."tasklistid",
    "tl"."taskid",
    "tl"."taskowner",
    "tl"."taskdate",
    "tl"."closedon",
    "tl"."taskstatus",
    "tl"."remarks",
    "tl"."companyid",
    "tl"."contactid",
    "tl"."leadid",
    "tl"."meeting_id",
    "tl"."previous_task_id",
    "tl"."calendar_event_id",
    "tl"."enteredon",
    "tl"."updatedon",
    "tl"."enteredby",
    "tl"."updatedby",
    "tl"."product_id",
    "tl"."puuserid",
    "t"."task" AS "task_name",
    COALESCE(((("assignee_contact"."first_name")::"text" || ' '::"text") || (COALESCE("assignee_contact"."last_name", ''::character varying))::"text"), "u"."username", 'Unassigned'::"text") AS "assignee_username",
    "comp"."name" AS "company_name",
    COALESCE(((("cont"."first_name")::"text" || ' '::"text") || (COALESCE("cont"."last_name", ''::character varying))::"text"), ''::"text") AS "contact_name",
    COALESCE(((("ld"."first_name")::"text" || ' '::"text") || (COALESCE("ld"."last_name", ''::character varying))::"text"), ''::"text") AS "lead_name",
    "ce"."title" AS "meeting_title",
    "pu"."name" AS "puuser_name",
        CASE
            WHEN (("tl"."taskstatus" = 'Open'::"public"."task_list_status") AND ("tl"."taskid" = 6)) THEN 0
            ELSE 1
        END AS "sort_priority"
   FROM (((((((("public"."tasklist" "tl"
     LEFT JOIN "public"."tasks" "t" ON (("tl"."taskid" = "t"."id")))
     LEFT JOIN "public"."users" "u" ON (("tl"."taskowner" = "u"."auth_user_id")))
     LEFT JOIN "public"."contacts" "assignee_contact" ON (("u"."contact_id" = "assignee_contact"."id")))
     LEFT JOIN "public"."companies" "comp" ON (("tl"."companyid" = "comp"."id")))
     LEFT JOIN "public"."contacts" "cont" ON (("tl"."contactid" = "cont"."id")))
     LEFT JOIN "public"."leads2" "ld" ON (("tl"."leadid" = "ld"."id")))
     LEFT JOIN "public"."calendar_events" "ce" ON (("tl"."calendar_event_id" = "ce"."id")))
     LEFT JOIN "public"."puusers" "pu" ON (("tl"."puuserid" = "pu"."id")));


