CREATE OR REPLACE VIEW "public"."v_job_run_stats" AS
 SELECT "j"."jobid",
    "j"."jobname",
    "j"."schedule",
    "j"."active",
    "count"(
        CASE
            WHEN ("r"."status" = 'succeeded'::"text") THEN 1
            ELSE NULL::integer
        END) AS "success_count",
    "count"(
        CASE
            WHEN ("r"."status" = 'failed'::"text") THEN 1
            ELSE NULL::integer
        END) AS "failure_count",
    "count"("r"."runid") AS "total_runs",
    "max"("r"."start_time") AS "last_run_at",
    ("avg"((EXTRACT(epoch FROM ("r"."end_time" - "r"."start_time")) * (1000)::numeric)))::integer AS "avg_duration_ms"
   FROM ("cron"."job" "j"
     LEFT JOIN "cron"."job_run_details" "r" ON (("j"."jobid" = "r"."jobid")))
  GROUP BY "j"."jobid", "j"."jobname", "j"."schedule", "j"."active";


ALTER VIEW "public"."v_job_run_stats" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_user_product" WITH ("security_invoker"='true') AS
 SELECT "u"."auth_user_id" AS "user_id",
    "upa"."product_id"
   FROM ("public"."user_product_assignments" "upa"
     JOIN "public"."users" "u" ON (("u"."auth_user_id" = "upa"."user_id")))
  WHERE (("u"."status")::"text" = 'active'::"text");


