    "id" bigint NOT NULL,
    "quotation_id" bigint,
    "related_document_type" "text",
    "related_document_id" bigint,
    "recipient_email" "text" NOT NULL,
    "contact_id" integer,
    "event_type" "text" NOT NULL,
    "event_timestamp" timestamp with time zone DEFAULT "now"() NOT NULL,
    "session_id" "text",
    "token_jti" "text",
    "ip_hash" "text",
    "user_agent_hash" "text",
    "metadata" "jsonb",
    "prev_event_hash" "text",
    "event_hash" "text" NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "valid_event_type" CHECK (("event_type" = ANY (ARRAY['TOKEN_ACCESSED'::"text", 'TOKEN_ISSUED'::"text", 'TOKEN_REVOKED'::"text", 'LINK_OPENED'::"text", 'OTP_REQUESTED'::"text", 'OTP_SENT'::"text", 'OTP_VERIFIED'::"text", 'OTP_VERIFY_FAILED'::"text", 'SESSION_CREATED'::"text", 'SESSION_REFRESHED'::"text", 'SESSION_REVOKED'::"text", 'STEP_UP_COMPLETED'::"text", 'DOCUMENT_VIEWED'::"text", 'DOCUMENT_APPROVED'::"text", 'DOCUMENT_REJECTED'::"text", 'DOCUMENT_SIGNED'::"text", 'PDF_DOWNLOADED'::"text", 'SOFT_QUOTE_SENT'::"text", 'EMAIL_REQUESTED'::"text", 'EMAIL_SENT'::"text", 'EMAIL_FAILED'::"text"])))
);


ALTER TABLE "public"."viewer_audit_log" OWNER TO "postgres";


