CREATE POLICY "Admin can delete competitors" ON "public"."competitors" FOR DELETE USING (("public"."has_role"('Super Admin'::"text") OR "public"."has_role"('Admin'::"text")));



CREATE POLICY "Admin can manage blocked domains" ON "public"."blocked_domains" USING (("public"."has_role"('Super Admin'::"text") OR "public"."has_role"('Admin'::"text")));



CREATE POLICY "Admin can manage public domains" ON "public"."public_domains" USING (("public"."has_role"('Super Admin'::"text") OR "public"."has_role"('Admin'::"text")));



CREATE POLICY "Admin can read all company_handler_removal_log" ON "public"."company_handler_removal_log" FOR SELECT USING (("public"."has_role"('Super Admin'::"text") OR "public"."has_role"('Admin'::"text") OR ("created_by" = "auth"."uid"())));



CREATE POLICY "Admins can create API keys" ON "public"."nucleus_api_keys" FOR INSERT TO "authenticated" WITH CHECK ((EXISTS ( SELECT 1
   FROM ("public"."users" "u"
     JOIN "public"."roles" "r" ON (("u"."role_id" = "r"."id")))
  WHERE (("u"."auth_user_id" = "auth"."uid"()) AND ("r"."name" = 'Nucleus Admin'::"text")))));



CREATE POLICY "Admins can create approved QA" ON "public"."nucleus_approved_qa" FOR INSERT WITH CHECK ("public"."has_iris_role"('IRIS Admin'::"text"));



CREATE POLICY "Admins can create documents" ON "public"."nucleus_documents" FOR INSERT WITH CHECK (("public"."has_iris_role"('IRIS Admin'::"text") OR "public"."has_iris_role"('Super Admin'::"text")));



CREATE POLICY "Admins can create widget integrations" ON "public"."nucleus_widget_integrations" FOR INSERT WITH CHECK ("public"."has_iris_role"('IRIS Admin'::"text"));



CREATE POLICY "Admins can delete API keys" ON "public"."nucleus_api_keys" FOR DELETE TO "authenticated" USING ((EXISTS ( SELECT 1
   FROM ("public"."users" "u"
     JOIN "public"."roles" "r" ON (("u"."role_id" = "r"."id")))
  WHERE (("u"."auth_user_id" = "auth"."uid"()) AND ("r"."name" = 'Nucleus Admin'::"text")))));



CREATE POLICY "Admins can delete approved QA" ON "public"."nucleus_approved_qa" FOR DELETE USING ("public"."has_iris_role"('IRIS Admin'::"text"));



CREATE POLICY "Admins can delete documents" ON "public"."nucleus_documents" FOR DELETE USING (("public"."has_iris_role"('IRIS Admin'::"text") OR "public"."has_iris_role"('Super Admin'::"text")));



CREATE POLICY "Admins can delete widget integrations" ON "public"."nucleus_widget_integrations" FOR DELETE USING ("public"."has_iris_role"('IRIS Admin'::"text"));



CREATE POLICY "Admins can manage agent documents" ON "public"."nucleus_agent_documents" TO "authenticated" USING ((EXISTS ( SELECT 1
   FROM ("public"."users" "u"
     JOIN "public"."roles" "r" ON (("u"."role_id" = "r"."id")))
  WHERE (("u"."auth_user_id" = "auth"."uid"()) AND ("r"."name" = 'Nucleus Admin'::"text")))));



CREATE POLICY "Admins can manage agent tools" ON "public"."nucleus_agent_tools" TO "authenticated" USING ((EXISTS ( SELECT 1
   FROM ("public"."users" "u"
     JOIN "public"."roles" "r" ON (("u"."role_id" = "r"."id")))
  WHERE (("u"."auth_user_id" = "auth"."uid"()) AND ("r"."name" = 'Nucleus Admin'::"text")))));



